// Helper functions to get landArea and FAR from the correct source
// Priority: 1) Field value, 2) window.projectData, 3) Default
function getProjectLandArea() {
    const fieldValue = parseFloat(document.getElementById('landArea')?.value);
    if (!isNaN(fieldValue) && fieldValue > 0) {
        console.log(`📊 [getProjectLandArea] Reading from field: ${fieldValue}`);
        return fieldValue;
    }
    // Fallback to window.projectData
    if (window.projectData && window.projectData.landArea) {
        console.log(`📊 [getProjectLandArea] Reading from window.projectData: ${window.projectData.landArea}`);
        return parseFloat(window.projectData.landArea);
    }
    // Last resort - default
    console.warn(`⚠️ [getProjectLandArea] Using default: 10000`);
    return 10000;
}

function getProjectFAR() {
    const fieldValue = parseFloat(document.getElementById('far')?.value);
    if (!isNaN(fieldValue) && fieldValue >= 0) {
        console.log(`📊 [getProjectFAR] Reading from field: ${fieldValue}`);
        return fieldValue;
    }
    // Fallback to window.projectData
    if (window.projectData && window.projectData.far) {
        console.log(`📊 [getProjectFAR] Reading from window.projectData: ${window.projectData.far}`);
        return parseFloat(window.projectData.far);
    }
    // Last resort - default
    console.warn(`⚠️ [getProjectFAR] Using default: 3.5`);
    return 3.5;
}

// ============================================================================
// SIMPLE SOLUTION: Convert Arabic-Indic numerals to Latin (0-9)
// ============================================================================
if (typeof window !== 'undefined') {
  // Converter function
  window.toLatinNumerals = function(str) {
    if (str == null) return '';
    return String(str).replace(/[٠-٩۰-۹]/g, function(c) {
      return '٠١٢٣٤٥٦٧٨٩۰۱۲۳۴۵۶۷۸۹'.indexOf(c) % 10;
    });
  };

  // Override toLocaleString
  const originalToLocaleString = Number.prototype.toLocaleString;
  Number.prototype.toLocaleString = function() {
    return originalToLocaleString.call(this, 'en-US');
  };

  // CRITICAL: Override HTMLInputElement value property
  const inputValueDescriptor = Object.getOwnPropertyDescriptor(HTMLInputElement.prototype, 'value');
  const originalValueSetter = inputValueDescriptor.set;
  const originalValueGetter = inputValueDescriptor.get;

  Object.defineProperty(HTMLInputElement.prototype, 'value', {
    get: function() {
      const val = originalValueGetter.call(this);
      return window.toLatinNumerals(val);
    },
    set: function(newValue) {
      const converted = window.toLatinNumerals(String(newValue));
      originalValueSetter.call(this, converted);
    },
    configurable: true
  });

  // Convert all inputs immediately and continuously
  function convertAllInputs() {
    document.querySelectorAll('input, textarea').forEach(function(el) {
      if (el.value && /[٠-٩۰-۹]/.test(el.value)) {
        const start = el.selectionStart;
        const scrollPos = el.scrollTop;
        el.value = window.toLatinNumerals(el.value);
        if (start !== null && start !== undefined) {
          try { el.setSelectionRange(start, start); } catch(e) {}
        }
        if (scrollPos) el.scrollTop = scrollPos;
      }
    });
  }

  // Run immediately
  convertAllInputs();
  
  // Run periodically
  setInterval(convertAllInputs, 50);
  
  // Run on any user interaction
  document.addEventListener('input', convertAllInputs, true);
  document.addEventListener('change', convertAllInputs, true);
  document.addEventListener('keyup', convertAllInputs, true);
  document.addEventListener('click', convertAllInputs, true);
  
  // Special handling for number input spinners (arrow buttons)
  document.addEventListener('mousedown', function(e) {
    if (e.target && e.target.tagName === 'INPUT' && e.target.type === 'number') {
      setTimeout(convertAllInputs, 10);
      setTimeout(convertAllInputs, 50);
      setTimeout(convertAllInputs, 100);
    }
  }, true);

  console.log('✅ Numeral converter active');
}

if (typeof window !== 'undefined') {
  const numberFormatter = (value = 0, locale = 'en-US') => {
    const numericValue = typeof value === 'number' ? value : Number(value) || 0;
    try {
      return new Intl.NumberFormat(locale).format(numericValue);
    } catch (error) {
      console.warn('⚠️ formatNumberLocale fallback triggered:', error);
      return numericValue.toLocaleString('en-US');
    }
  };

  const digitMap = {
    '٠': '0','١': '1','٢': '2','٣': '3','٤': '4','٥': '5','٦': '6','٧': '7','٨': '8','٩': '9',
    '۰': '0','۱': '1','۲': '2','۳': '3','۴': '4','۵': '5','۶': '6','۷': '7','۸': '8','۹': '9'
  };

  window.formatNumberLocale = window.formatNumberLocale || numberFormatter;
  window.parseLocalizedNumber = window.parseLocalizedNumber || function parseLocalizedNumber(value) {
    if (typeof value === 'number') {
      return value;
    }
    if (value == null) {
      return 0;
    }

    const normalized = String(value).replace(/[٠-٩۰-۹]/g, (char) => digitMap[char] || char);
    const sanitized = normalized.replace(/[^0-9+\-.]/g, '');
    const parsed = parseFloat(sanitized);
    return Number.isNaN(parsed) ? 0 : parsed;
  };

  if (typeof window.FINANCE_API !== 'object' || window.FINANCE_API === null) {
    window.FINANCE_API = {
      snapshot: () => ({ totalInvestment: 0, construction: 0, land: 0, additional: 0 }),
      total: () => 0,
      totalFormatted: (locale = 'en-US') => numberFormatter(0, locale)
    };
  } else {
    window.FINANCE_API.snapshot = window.FINANCE_API.snapshot || (() => ({ totalInvestment: 0 }));
    window.FINANCE_API.total = window.FINANCE_API.total || (() => 0);
    window.FINANCE_API.totalFormatted = window.FINANCE_API.totalFormatted || ((locale = 'en-US') => numberFormatter(window.FINANCE_API.total(), locale));
  }

  window.kpiROI = window.kpiROI || function kpiROI({ annualNetIncome = 0, totalInvestment = 0 } = {}) {
    if (!totalInvestment) {
      return 0;
    }
    return (annualNetIncome / totalInvestment) * 100;
  };

  /**
   * حساب ROI الصحيح باستخدام البيانات الفعلية من النظام
   * ROI = (صافي الدخل السنوي ÷ إجمالي الاستثمار) × 100
   * حيث: صافي الدخل السنوي = إجمالي الإيرادات - إجمالي النفقات التشغيلية
   */
  window.calculateCorrectROI = function calculateCorrectROI() {
    try {
      console.log('💰 [calculateCorrectROI] بدء حساب Total ROI الشامل...');
      
      // 1. حساب إجمالي الإيرادات السنوية
      let totalAnnualRevenue = 0;
      if (typeof calculateIntegratedAnnualRevenue === 'function') {
        totalAnnualRevenue = calculateIntegratedAnnualRevenue() || 0;
      }
      console.log(`  📈 إجمالي الإيرادات السنوية: ${totalAnnualRevenue.toLocaleString('en-US')} ريال`);
      
      // 2. حساب إجمالي النفقات التشغيلية (OPEX)
      let totalOpex = 0;
      if (typeof calculateOpexSummary === 'function') {
        const opexSummary = calculateOpexSummary();
        totalOpex = opexSummary.totalOpex || 0;
      }
      console.log(`  📉 إجمالي النفقات التشغيلية: ${totalOpex.toLocaleString('en-US')} ريال`);
      
      // 3. حساب صافي الدخل السنوي (NOI - Net Operating Income)
      const annualNetIncome = totalAnnualRevenue - totalOpex;
      console.log(`  💵 صافي الدخل السنوي (NOI): ${annualNetIncome.toLocaleString('en-US')} ريال`);
      
      // 4. الحصول على إجمالي الاستثمار
      let totalInvestment = 0;
      if (typeof getIntegrationData === 'function') {
        const integrationData = getIntegrationData();
        totalInvestment = integrationData.totalProjectCost || 0;
      }
      console.log(`  🏗️ إجمالي الاستثمار: ${totalInvestment.toLocaleString('en-US')} ريال`);
      
      // 5. الحصول على فترة التشغيل
      const operationPeriod = parseInt(document.getElementById('operationDuration')?.value) || 20;
      console.log(`  ⏱️ فترة التشغيل: ${operationPeriod} سنة`);
      
      // 6. حساب Exit Value (قيمة الخروج)
      let exitValue = 0;
      if (typeof window.calculateExitValue === 'function') {
        exitValue = window.calculateExitValue() || 0;
      }
      
      // إذا لم تكن هناك قيمة خروج محددة، نستخدم Cap Rate Method
      if (exitValue === 0 && annualNetIncome > 0) {
        const exitCapRate = parseFloat(document.getElementById('exitCapRate')?.value) || 0.07;
        exitValue = annualNetIncome / exitCapRate;
        console.log(`  🎯 Exit Value (محسوبة بـ Cap Rate ${(exitCapRate * 100).toFixed(2)}%): ${exitValue.toLocaleString('en-US')} ريال`);
      } else {
        console.log(`  🎯 Exit Value (من calculateExitValue): ${exitValue.toLocaleString('en-US')} ريال`);
      }
      
      // 7. حساب Total Cash Inflows (إجمالي التدفقات النقدية الداخلة)
      const totalCashFlows = annualNetIncome * operationPeriod;
      const totalCashInflows = totalCashFlows + exitValue;
      console.log(`  💰 إجمالي التدفقات النقدية (${operationPeriod} سنة): ${totalCashFlows.toLocaleString('en-US')} ريال`);
      console.log(`  💎 إجمالي التدفقات مع قيمة الخروج: ${totalCashInflows.toLocaleString('en-US')} ريال`);
      
      // 8. حساب Total ROI الشامل
      if (totalInvestment === 0) {
        console.warn('⚠️ إجمالي الاستثمار = 0، لا يمكن حساب ROI');
        return 0;
      }
      
      // Total ROI = ((Total Returns - Total Investment) / Total Investment) × 100
      const totalROI = ((totalCashInflows - totalInvestment) / totalInvestment) * 100;
      
      // حساب Annualized ROI (العائد السنوي المعادل)
      const annualizedROI = totalROI / operationPeriod;
      
      console.log(`✅ [calculateCorrectROI] Total ROI (على ${operationPeriod} سنة) = ${totalROI.toFixed(2)}%`);
      console.log(`✅ [calculateCorrectROI] Annualized ROI (سنوي معادل) = ${annualizedROI.toFixed(2)}%`);
      
      // نعيد Annualized ROI لأنه أكثر فائدة للمقارنة
      return annualizedROI;
      
    } catch (error) {
      console.error('❌ خطأ في حساب ROI الشامل:', error);
      return 0;
    }
  };

  window.kpiPayback = window.kpiPayback || function kpiPayback({ totalInvestment = 0, annualCashFlow = 0 } = {}) {
    if (!annualCashFlow) {
      return Infinity;
    }
    return totalInvestment / annualCashFlow;
  };

  window.kpiNPV = window.kpiNPV || function kpiNPV({ discountRate = 0, cashFlows = [] } = {}) {
    const rate = (discountRate || 0) / 100;
    return (Array.isArray(cashFlows) ? cashFlows : []).reduce((total, cashFlow = 0, index) => {
      const denominator = Math.pow(1 + rate, index + 1);
      return total + (cashFlow || 0) / (denominator || 1);
    }, 0);
  };

  if (typeof window.calculateFinancialKPIs !== 'function') {
    window.calculateFinancialKPIs = function calculateFinancialKPIs() {
      console.info('ℹ️ calculateFinancialKPIs is disabled during the current maintenance window.');
      return {
        roi: 0,
        irr: 0,
        paybackPeriod: null,
        noi: 0
      };
    };
  }
}

/* === I18N GUARDS: Safe updateMapTranslations hook (v2) === */

/* 0) util: تقسيم العمل لتقليل long tasks */
if (typeof window.timeSlice !== 'function') {
  window.timeSlice = function timeSlice(list, doItem, budgetMs = 12) {
    const arr = Array.from(list || []);
    let i = 0;
    function step() {
      const t0 = performance.now();
      while (i < arr.length && performance.now() - t0 < budgetMs) {
        try { doItem(arr[i], i); } catch {}
        i++;
      }
      if (i < arr.length) requestAnimationFrame(step);
    }
    requestAnimationFrame(step);
  };
}

/* 1) util: حزمة ترجمة آمنة دائمًا */
if (typeof window.getTranslationBundle !== 'function') {
  window.getTranslationBundle = function getTranslationBundle(locale) {
    const loc = (locale || '').toString();
    const direct = (window.TRANSLATIONS && window.TRANSLATIONS[loc]) || null;
    if (direct && typeof direct === 'object') return direct;
    // fallback يمنع الكسر
    return { locationMap: {}, labels: {} };
  };
}

/* 2) hook: اعتراض القراءة/الكتابة على window.updateMapTranslations */
(function hookUpdateMapTranslations() {
  let __orig = undefined; // نخزّن أي دالة أصلية تُعيَّن لاحقًا

  function updateMapTranslationsSafe(locale) {
    try {
      const bundle = window.getTranslationBundle(locale);
      const locMap = bundle && bundle.locationMap ? bundle.locationMap : {};

      // نفّذ الدالة الأصلية (إن وُجدت) داخل حارس
      if (typeof __orig === 'function') {
        try { __orig.call(window, locale, bundle); }
        catch (e) { console.warn('🌐 [i18n] original updateMapTranslations failed, continuing safely:', e); }
      }

      // Fallback آمن: عناصر تحمل data-loc-key
      const nodes = document.querySelectorAll('[data-loc-key]');
      window.timeSlice(nodes, (el) => {
        const key = el.getAttribute('data-loc-key');
        if (typeof locMap[key] === 'string') el.textContent = locMap[key];
      });
    } catch (e) {
      console.warn('🌐 [i18n] updateMapTranslationsSafe error:', e);
    }
  }

  // حقل قابل لإعادة التعريف مع getter/setter (اعتراض دائم)
  Object.defineProperty(window, 'updateMapTranslations', {
    configurable: true,
    enumerable: true,
    get() { return updateMapTranslationsSafe; },
    set(fn) { __orig = fn; } // أي تعريف لاحق يُلتقط هنا
  });
})();

