window.DEBUG_MISSING_FIELDS = window.DEBUG_MISSING_FIELDS ?? /localhost|127\.0\.0\.1/.test(location.host);

/** تحذير مرة واحدة لكل حقل */
const __WARN_ONCE__ = new Set();
function warnOnce(msg) {
  if (!window.DEBUG_MISSING_FIELDS) return;
  if (__WARN_ONCE__.has(msg)) return;
  __WARN_ONCE__.add(msg);
  console.warn(msg);
}

/** يعيد أول عنصر مطابق سواء بالـID أو أي Selector بديل */
function resolveField(id) {
  // صرّف مباشرةً لو العنصر بالـID موجود
  const el0 = document.getElementById(id);
  if (el0) return el0;

  // جرّب المرادفات
  const list = FIELD_SYNONYMS[id] || [];
  for (const sel of list) {
    const el = document.querySelector(sel);
    if (el) return el;
  }

  // لا يوجد؟ حذّر مرة واحدة فقط
  warnOnce(`⚠️ لم يتم العثور على الحقل ${id}`);
  return null;
}

