/** تغليف ضغطة كثيفة (اختياري) — مثال عام */
function wrapHeavyClick(id, selectorOfItems, toggleFn) {
  const btn = document.getElementById(id);
  if (!btn) return;
  if (btn.dataset.heavyWrapped === '1') return;
  btn.dataset.heavyWrapped = '1';

  btn.addEventListener('click', (ev) => {
    const nodes = document.querySelectorAll(selectorOfItems);
    timeSlice(nodes, (node) => {
      try { toggleFn(node); } catch {}
    });
  }, { passive: true });
}



/* === SAFE FIELD WRITES (number/date/month friendly) === */

// 1) تحويل الأرقام العربية/الفارسية إلى ASCII (عند الحاجة)
function normalizeDigits(str) {
  const s = String(str ?? '');
  const map = {
    '٠':'0','١':'1','٢':'2','٣':'3','٤':'4','٥':'5','٦':'6','٧':'7','٨':'8','٩':'9',
    '۰':'0','۱':'1','۲':'2','۳':'3','۴':'4','۵':'5','۶':'6','۷':'7','۸':'8','۹':'9'
  };
  return s.replace(/[٠-٩۰-۹]/g, d => map[d] || d);
}


// --- Numerical + cloning helpers ---
function safeDeepClone(value) {
  if (value === null || typeof value !== 'object') {
    return value;
  }
  if (typeof structuredClone === 'function') {
    try {
      return structuredClone(value);
    } catch {}
  }
  try {
    return JSON.parse(JSON.stringify(value));
  } catch {}
  if (Array.isArray(value)) {
    return value.map((item) => safeDeepClone(item));
  }
  const clone = {};
  for (const key in value) {
    if (Object.prototype.hasOwnProperty.call(value, key)) {
      clone[key] = safeDeepClone(value[key]);
    }
  }
  return clone;
}

function toNumeric(value, fallback = 0) {
  if (value === null || value === undefined || value === '') {
    return fallback;
  }
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : fallback;
}

function toNumericOrNull(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }
  const numeric = Number(value);
  return Number.isFinite(numeric) ? numeric : null;
}

// 2) كتابة آمنة لحقول مشتقة بحسب نوع input

function setDerivedFieldSafely(id, value, { locale = 'en-US', maxFrac = 0 } = {}) {
  const el = document.getElementById(id);
  if (!el) return false;

  const numeric = Number(value ?? 0);
  const type = (el.getAttribute('type') || el.type || '').toLowerCase();

  // علِّم أن هذه كتابة برمجية لتجنب حلقات الأحداث
  (window.__PROGRAMMATIC_WRITES__ ||= new Set()).add(id);
  el.dataset.numeric = String(isFinite(numeric) ? numeric : 0);

  try {
    if (type === 'number') {
      // number: ممنوع النص المنسّق، استخدم valueAsNumber فقط
      el.valueAsNumber = isFinite(numeric) ? numeric : 0;
    } else if (type === 'date' || type === 'month') {
      // date/month: استخدم ISO-8601
      const d = (value instanceof Date) ? value : new Date(value || Date.now());
      if (!isNaN(+d)) {
        if (type === 'date')   el.value = d.toISOString().slice(0, 10); // YYYY-MM-DD
        if (type === 'month')  el.value = d.toISOString().slice(0, 7);  // YYYY-MM
      } else {
        // تفريغ عند عدم القدرة على التحويل
        el.value = '';
      }
    } else {
      // text/others: هنا فقط نعرض الصيغة المنسّقة
      const pretty = Number.isFinite(numeric)
        ? Number(numeric).toLocaleString(locale, { maximumFractionDigits: maxFrac })
        : '0';
      if (el.value !== pretty) el.value = pretty;
    }
  } finally {
    window.__PROGRAMMATIC_WRITES__.delete(id);
  }
  return true;
}

// 3) تحديث إجمالي الاستثمار باستخدام الكتابة الآمنة (يحافظ على المعمارية الحالية)
// ✅ ENABLED: Update totalInvestment field with unified calculation
function updateTotalInvestmentField() {
  try {
    const integrationData = getIntegrationData();
    
    // Get totalProjectCost from integration data
    const totalInvestment = integrationData.totalProjectCost || 0;
    
    // Update the input field using the proper setter (RULE COMPLIANT)
    const totalInvestmentElement = document.getElementById('totalInvestment');
    if (totalInvestmentElement) {
      // ✅ USE setDerivedFieldFormatted instead of direct .value assignment
      setDerivedFieldFormatted('totalInvestment', totalInvestment);
      console.log('💰 [updateTotalInvestmentField] Updated:', totalInvestment.toLocaleString('en-US'), 'ريال');
    }
    
    // Update the breakdown text
    const breakdownElement = document.getElementById('totalInvestmentBreakdown');
    if (breakdownElement) {
      const landPercentage = integrationData.totalProjectCost > 0 
        ? ((integrationData.landCost / integrationData.totalProjectCost) * 100).toFixed(1)
        : 0;
      const devPercentage = integrationData.totalProjectCost > 0
        ? ((integrationData.constructionCost / integrationData.totalProjectCost) * 100).toFixed(1)
        : 0;
      
      breakdownElement.textContent = `أرض (${landPercentage}%) + تطوير (${devPercentage}%)`;
    }
    
  } catch (error) {
    console.error('❌ [updateTotalInvestmentField] Error:', error);
  }
}

// 4) كتابة آمنة لتواريخ/أشهر معيّنة (عند الحاجة)
function setISODateInput(id, dateLike) {
  const el = document.getElementById(id);
  if (!el) return false;
  const t = (el.getAttribute('type') || el.type || '').toLowerCase();
  const d = (dateLike instanceof Date) ? dateLike : new Date(dateLike);
  if (isNaN(+d)) return false;
  (window.__PROGRAMMATIC_WRITES__ ||= new Set()).add(id);
  if (t === 'date')  el.value = d.toISOString().slice(0,10);
  if (t === 'month') el.value = d.toISOString().slice(0,7);
  window.__PROGRAMMATIC_WRITES__.delete(id);
  return true;
}

// 5) قارئ رقمي موحّد حتى لو الحقل معروض بصيغة محلية أو به أرقام عربية
function getDerivedFieldNumeric(id) {
  const el = document.getElementById(id);
  if (!el) return 0;
  if (el.dataset?.numeric) return Number(el.dataset.numeric || 0);
  const type = (el.getAttribute('type') || el.type || '').toLowerCase();
  if (type === 'number') return el.valueAsNumber || 0;
  // إزالة فواصل/أرقام عربية عند القراءة
  const raw = normalizeDigits(el.value).replace(/[^\d.\-]/g, '');
  const n = parseFloat(raw);
  return Number.isFinite(n) ? n : 0;
}

