// ===== Core Utils (Safe; no UI changes) =====
const $ = (id) => document.getElementById(id);
const num = (id, fallback = 0) => {
  const el = $(id);
  if (!el) return fallback;
  const v = parseFloat(String(el.value).replace(/,/g, ''));
  return Number.isFinite(v) ? v : fallback;
};
const assign = (id, value) => {
  const el = $(id);
  if (el) el.value = String(value);
};

// ===== Logging (Non-invasive) =====
const LOG = (() => {
  const LEVELS = { debug: 0, info: 1, warn: 2, error: 3 };
  const current =
    (typeof window !== 'undefined' && window.APP_LOG_LEVEL) || 'info';
  const lvl = LEVELS[current] ?? 1;
  const emit = (type, ns, ...args) => {
    const map = { debug: 'log', info: 'log', warn: 'warn', error: 'error' };
    const c = map[type] || 'log';
    if (LEVELS[type] >= lvl) console[c](`[${ns}]`, ...args);
  };
  const ns = (name) => ({
    debug: (...a) => emit('debug', name, ...a),
    info:  (...a) => emit('info',  name, ...a),
    warn:  (...a) => emit('warn',  name, ...a),
    error: (...a) => emit('error', name, ...a),
  });
  return { ns };
})();

// ===== Async Guards =====
const AsyncGuards = (() => {
  const timeouts = new Set();
  const namedTimeouts = new Map();
  
  return {
    set(fn, ms, name = null){
      const t = setTimeout(fn, ms);
      timeouts.add(t);
      if (name) {
        // إذا كان هناك timeout بنفس الاسم، امسح القديم
        if (namedTimeouts.has(name)) {
          clearTimeout(namedTimeouts.get(name));
        }
        namedTimeouts.set(name, t);
      }
      return t;
    },
    clearAll(){
      timeouts.forEach(clearTimeout);
      timeouts.clear();
      namedTimeouts.clear();
    },
    clearNamed(name) {
      if (namedTimeouts.has(name)) {
        const t = namedTimeouts.get(name);
        clearTimeout(t);
        timeouts.delete(t);
        namedTimeouts.delete(name);
      }
    }
  };
})();

// Centralized delay management functions
function delayedUpdate(fn, ms = 300, description = 'تحديث مؤخر') {
  console.log(`⏱️ ${description} - تأخير ${ms}ms`)
  return AsyncGuards.set(fn, ms);
}

function safeguardedTimeout(fn, ms = 1000, description = 'عملية آمنة') {
  console.log(`🛡️ ${description} - timeout محمي ${ms}ms`)
  return AsyncGuards.set(fn, ms);
}

// Smart replacement for individual timeout patterns
function replaceableTimeout(fn, ms = 300, name, description = 'مهمة قابلة للاستبدال') {
  console.log(`🔄 ${description} - استبدال timeout "${name}" - ${ms}ms`)
  return AsyncGuards.set(fn, ms, name);
}

