// دمج سطحي آمن (لا يستبدل callbacks/axes إن كانت موجودة)
function shallowMerge(base, extra) {
  const out = { ...base };
  for (const k in extra) {
    if (out[k] === undefined) out[k] = extra[k];
    else if (typeof out[k] === 'object' && typeof extra[k] === 'object' && !Array.isArray(out[k])) {
      out[k] = shallowMerge(out[k], extra[k]); // اندماج من مستوى واحد
    }
  }
  return out;
}

