// 3) فاحص سلامة للرسوم المعقّدة (بدون تعديلها)
function assertChartInvariants(chartConfig) {
  const c = chartConfig || {};
  const hasCustomTooltip = !!c?.options?.plugins?.tooltip?.callbacks;
  const hasDualAxes     = !!c?.options?.scales?.y1;
  const hasMixedTypes   = Array.isArray(c?.data?.datasets) && c.data.datasets.some(ds => ds.type === 'line');
  return { hasCustomTooltip, hasDualAxes, hasMixedTypes };
}

