// 🎯 حل نهائي للازدواجية - نظام مرجعي موحد للدوال المالية
(function initializeGlobalFunctionRegistry() {
    // منع التهيئة المضاعفة
    if (window.__FUNCTION_REGISTRY_INITIALIZED__) {
        console.log('✅ Global Function Registry already initialized');
        return;
    }

    console.log('🚀 تهيئة النظام المرجعي الموحد للدوال المالية...');

    // إنشاء مساحة اسماء آمنة للدوال المالية
    window.FinancialFunctions = window.FinancialFunctions || {};
    
    // نظام fallback آمن
    const createSafeFallback = (functionName, defaultValue = 0) => {
        return function(...args) {
            console.warn(`⚠️ [${functionName}] Fallback function called - main function not available`);
            return defaultValue;
        };
    };

    // تسجيل دالة في النظام المرجعي
    const registerFunction = (name, func, description) => {
        if (typeof func !== 'function') {
            console.error(`❌ Cannot register ${name}: not a function`);
            return false;
        }
        
        window.FinancialFunctions[name] = func;
        console.log(`✅ Registered: ${name} - ${description}`);
        return true;
    };

    // الحصول على دالة من النظام المرجعي مع fallback آمن
    const getFunction = (name, fallback = null) => {
        const func = window.FinancialFunctions[name] || fallback || createSafeFallback(name);
        if (func === createSafeFallback(name)) {
            console.warn(`⚠️ Function ${name} not found, using fallback`);
        }
        return func;
    };

    // تصدير الدوال للاستخدام العام
    window.registerFinancialFunction = registerFunction;
    window.getFinancialFunction = getFunction;
    
    // تعيين العلامة
    window.__FUNCTION_REGISTRY_INITIALIZED__ = true;
    
    console.log('✅ نظام الدوال المرجعي جاهز!');
})();

