/**
 * دالة عرض الإشعارات المحسنة
 */
function showNotification(message, type = 'info', duration = 3000, title = '') {
    // إزالة الإشعارات السابقة
    const existing = document.getElementById('notification-container')
    if (existing) {
        existing.remove()
    }
    
    const colors = {
        success: 'bg-emerald-500/200 border-emerald-400/50',
        error: 'bg-red-500/200 border-red-600',
        warning: 'bg-amber-500/200 border-yellow-600',
        info: 'bg-blue-500/200 border-blue-600'
    }
    
    const icons = {
        success: 'fa-check-circle',
        error: 'fa-exclamation-circle',
        warning: 'fa-exclamation-triangle',
        info: 'fa-info-circle'
    }
    
    const notification = document.createElement('div')
    notification.id = 'notification-container'
    notification.className = `fixed top-4 right-4 ${colors[type]} text-white px-6 py-4 rounded-lg shadow-lg border-l-4 max-w-sm`
    notification.style.zIndex = '9999'
    
    notification.innerHTML = `
        <div class="flex items-center">
            <i class="fas ${icons[type]} text-xl mr-3"></i>
            <div>
                ${title ? `<div class="font-bold text-sm">${title}</div>` : ''}
                <div class="text-sm">${message}</div>
            </div>
        </div>
    `
    
    document.body.appendChild(notification)
    
    // إزالة الإشعار تلقائياً
    setTimeout(() => {
        if (notification && notification.parentNode) {
            notification.remove()
        }
    }, duration)
}

// جعل دالة showNotification متاحة عالمياً
window.showNotification = showNotification

/**
 * البحث عن بند في البيانات
 */
function findOpexItem(categoryId, itemId) {
    if (categoryId === 'generalOpex') {
        return opexData.generalOpex.expenses.find(expense => expense.id === itemId)
    } else if (categoryId === 'variableOpex') {
        return opexData.variableOpex.variables.find(variable => variable.id === itemId)
    } else if (categoryId === 'emergencyReserve') {
        return opexData.emergencyReserve.reserves.find(reserve => reserve.id === itemId)
    }
    return null
}

// جعل دالة findOpexItem متاحة عالمياً
window.findOpexItem = findOpexItem

