/**
 * إغلاق نافذة إضافة البند
 */
function closeAddOpexItemModal() {
    const modal = document.getElementById('add-opex-item-modal')
    if (modal) {
        modal.remove()
    }
}

/**
 * حفظ البند الجديد
 */
function saveNewOpexItem(event, categoryId) {
    event.preventDefault()
    
    const name = document.getElementById('opex-item-name').value.trim()
    const description = document.getElementById('opex-item-description').value.trim()
    
    if (!name || !description) {
        alert('يرجى ملء جميع الحقول المطلوبة')
        return
    }
    
    // إنشاء معرف فريد
    const id = `${categoryId}_${Date.now()}_${Math.random().toString(36).substr(2, 5)}`
    
    let newItem = {
        id: id,
        name: name,
        description: description
    }
    
    // إضافة الحقول حسب نوع الفئة
    if (categoryId === 'generalOpex') {
        newItem.amount = parseFloat(document.getElementById('opex-item-amount').value) || 0
        newItem.percentage = parseFloat(document.getElementById('opex-item-percentage').value) || 0
        newItem.unit = "ريال/سنة"
        
        // إضافة البند إلى البيانات
        opexData.generalOpex.expenses.push(newItem)
        
    } else if (categoryId === 'variableOpex') {
        newItem.rate = parseFloat(document.getElementById('opex-item-rate').value) || 0
        newItem.unit = document.getElementById('opex-item-unit').value
        
        // إضافة البند إلى البيانات
        opexData.variableOpex.variables.push(newItem)
        
    } else if (categoryId === 'emergencyReserve') {
        newItem.rate = parseFloat(document.getElementById('opex-item-rate').value) || 0
        newItem.unit = document.getElementById('opex-item-unit').value
        
        // إضافة البند إلى البيانات
        opexData.emergencyReserve.reserves.push(newItem)
    }
    
    console.log(`✅ تم إضافة بند جديد: ${name} للفئة ${categoryId}`)
    
    // إغلاق النافذة وإعادة تحميل النظام
    closeAddOpexItemModal()
    if (typeof renderOpexSystem === 'function') {
        renderOpexSystem()
    }
    if (typeof updateOpexSummary === 'function') {
        updateOpexSummary()
    }
    
    // إشعار للمستخدم
    showNotification(`تم إضافة البند "${name}" بنجاح`, 'success', 3000)
}

/**
 * حذف بند نفقات
 */
function deleteOpexItem(categoryId, itemId) {
    if (!confirm('هل أنت متأكد من حذف هذا البند؟ لا يمكن التراجع عن هذا الإجراء.')) {
        return
    }
    
    console.log(`🗑️ حذف البند: ${itemId} من الفئة: ${categoryId}`)
    
    if (categoryId === 'generalOpex') {
        opexData.generalOpex.expenses = opexData.generalOpex.expenses.filter(expense => expense.id !== itemId)
    } else if (categoryId === 'variableOpex') {
        opexData.variableOpex.variables = opexData.variableOpex.variables.filter(variable => variable.id !== itemId)
    } else if (categoryId === 'emergencyReserve') {
        opexData.emergencyReserve.reserves = opexData.emergencyReserve.reserves.filter(reserve => reserve.id !== itemId)
    }
    
    // إعادة تحميل النظام
    if (typeof renderOpexSystem === 'function') {
        renderOpexSystem()
    }
    if (typeof updateOpexSummary === 'function') {
        updateOpexSummary()
    }
    
    showNotification('تم حذف البند بنجاح', 'success', 2000)
}

/**
 * تعديل اسم البند مباشرة
 */
function editOpexItemName(categoryId, itemId, element) {
    const currentName = element.textContent.trim()
    const originalName = element.getAttribute('data-original')
    
    // إنشاء حقل الإدخال
    const input = document.createElement('input')
    input.type = 'text'
    input.value = currentName
    input.className = 'font-medium text-white bg-amber-500/20 border border-amber-400/40 rounded px-2 py-1 text-sm'
    input.style.width = '200px'
    
    // استبدال النص بحقل الإدخال
    element.replaceWith(input)
    input.focus()
    input.select()
    
    // حفظ التغييرات عند الضغط على Enter أو فقدان التركيز
    function saveEdit() {
        const newName = input.value.trim()
        
        if (newName && newName !== currentName) {
            // تحديث البيانات
            let item = findOpexItem(categoryId, itemId)
            if (item) {
                item.name = newName
                console.log(`✏️ تم تحديث اسم البند: ${itemId} إلى: ${newName}`)
                if (typeof updateOpexSummary === 'function') {
                    updateOpexSummary()
                }
                showNotification('تم تحديث اسم البند بنجاح', 'success', 2000)
            }
        }
        
        // إنشاء عنصر النص الجديد
        const newElement = document.createElement('h4')
        newElement.className = 'font-medium text-white editable-text cursor-pointer hover:text-amber-200'
        newElement.setAttribute('onclick', `editOpexItemName('${categoryId}', '${itemId}', this)`)
        newElement.setAttribute('data-original', newName || originalName)
        newElement.setAttribute('title', 'انقر لتعديل الاسم')
        newElement.textContent = newName || currentName
        
        input.replaceWith(newElement)
    }
    
    input.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') {
            saveEdit()
        } else if (e.key === 'Escape') {
            // إلغاء التعديل
            const cancelElement = document.createElement('h4')
            cancelElement.className = 'font-medium text-white editable-text cursor-pointer hover:text-amber-200'
            cancelElement.setAttribute('onclick', `editOpexItemName('${categoryId}', '${itemId}', this)`)
            cancelElement.setAttribute('data-original', originalName)
            cancelElement.setAttribute('title', 'انقر لتعديل الاسم')
            cancelElement.textContent = currentName
            input.replaceWith(cancelElement)
        }
    })
    
    input.addEventListener('blur', saveEdit)
}

/**
 * تعديل وصف البند مباشرة
 */
function editOpexItemDescription(categoryId, itemId, element) {
    const currentDescription = element.textContent.trim()
    const originalDescription = element.getAttribute('data-original')
    
    // إنشاء حقل النص
    const textarea = document.createElement('textarea')
    textarea.value = currentDescription
    textarea.className = 'text-sm text-white/70 bg-amber-500/20 border border-amber-400/40 rounded px-2 py-1 w-full resize-none'
    textarea.rows = 2
    
    // استبدال النص بحقل الإدخال
    element.replaceWith(textarea)
    textarea.focus()
    textarea.select()
    
    // حفظ التغييرات
    function saveEdit() {
        const newDescription = textarea.value.trim()
        
        if (newDescription && newDescription !== currentDescription) {
            // تحديث البيانات
            let item = findOpexItem(categoryId, itemId)
            if (item) {
                item.description = newDescription
                console.log(`✏️ تم تحديث وصف البند: ${itemId}`)
                showNotification('تم تحديث وصف البند بنجاح', 'success', 2000)
            }
        }
        
        // إنشاء عنصر النص الجديد
        const newElement = document.createElement('p')
        newElement.className = 'text-sm text-white/70 editable-text cursor-pointer hover:text-white/90'
        newElement.setAttribute('onclick', `editOpexItemDescription('${categoryId}', '${itemId}', this)`)
        newElement.setAttribute('data-original', newDescription || originalDescription)
        newElement.setAttribute('title', 'انقر لتعديل الوصف')
        newElement.textContent = newDescription || currentDescription
        
        textarea.replaceWith(newElement)
    }
    
    textarea.addEventListener('keypress', (e) => {
        if (e.key === 'Enter' && e.ctrlKey) {
            saveEdit()
        } else if (e.key === 'Escape') {
            // إلغاء التعديل
            const cancelElement = document.createElement('p')
            cancelElement.className = 'text-sm text-white/70 editable-text cursor-pointer hover:text-white/90'
            cancelElement.setAttribute('onclick', `editOpexItemDescription('${categoryId}', '${itemId}', this)`)
            cancelElement.setAttribute('data-original', originalDescription)
            cancelElement.setAttribute('title', 'انقر لتعديل الوصف')
            cancelElement.textContent = currentDescription
            textarea.replaceWith(cancelElement)
        }
    })
    
    textarea.addEventListener('blur', saveEdit)
}

