// Make costsData globally accessible  
window.costsData = costsData

// Dynamic Cost Management System - Enhanced Features
// ================================================

// Generate unique ID for new items
function generateUniqueId(prefix = 'item') {
    return `${prefix}_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`
}

// COST_CALCULATION_TYPES moved to top - removed duplicate

// Add new cost category
function addNewCostCategory() {
    const categoryName = prompt('أدخل اسم القسم الجديد:')
    if (!categoryName) return
    
    const categoryId = generateUniqueId('category')
    const categoryNameEn = prompt('أدخل الاسم بالإنجليزية (اختياري):') || categoryName
    
    // Available colors for categories
    const availableColors = ['red', 'blue', 'green', 'purple', 'indigo', 'pink', 'yellow', 'orange', 'teal', 'cyan']
    const selectedColor = availableColors[Object.keys(costsData).length % availableColors.length]
    
    // Available icons
    const availableIcons = ['🏗️', '💼', '📋', '🔧', '⚡', '🛠️', '📊', '💰', '🎯', '⚙️', '📝', '🏢']
    const selectedIcon = availableIcons[Object.keys(costsData).length % availableIcons.length]
    
    // Ask for category type
    const categoryTypeChoice = prompt('نوع القسم:\n\n1 = إنشائي (Construction)\n2 = إضافي (Additional)\n\nأدخل 1 أو 2:', '2');
    const categoryType = categoryTypeChoice === "1" ? 'construction' : 'additional';
    
    // Create new category
    costsData[categoryId] = {
        id: categoryId,
        name: categoryName,
        nameEn: categoryNameEn,
        color: selectedColor,
        icon: selectedIcon,
        categoryType: categoryType, // إضافي افتراضياً
        isCustom: true,
        costs: [],
        description: `قسم مخصص: ${categoryName}`
    }
    
    dataLogger.info(`تم إضافة قسم جديد: ${categoryName}`)
    renderCostsSystem()
}

// Delete cost category
function deleteCostCategory(categoryId) {
    if (!costsData[categoryId]) return
    
    const category = costsData[categoryId]
    if (confirm(`هل تريد حذف قسم "${category.name}" وجميع بنوده؟`)) {
        delete costsData[categoryId]
        dataLogger.info(`تم حذف القسم: ${category.name}`)
        renderCostsSystem()
        updateCostsSummary()
    }
}

// Duplicate cost category
function duplicateCostCategory(categoryId) {
    const category = costsData[categoryId]
    if (!category) {
        console.error('❌ Category not found:', categoryId)
        return
    }
    
    const newId = generateUniqueId('category')
    const newCategory = JSON.parse(JSON.stringify(category)) // Deep clone
    newCategory.name = `${category.name} (نسخة)`
    newCategory.name_en = category.name_en ? `${category.name_en} (Copy)` : ''
    
    // Generate new IDs for all costs
    if (newCategory.costs && Array.isArray(newCategory.costs)) {
        newCategory.costs = newCategory.costs.map(cost => ({
            ...cost,
            id: generateUniqueId('cost')
        }))
    }
    
    costsData[newId] = newCategory
    localStorage.setItem('costsData', JSON.stringify(costsData))
    renderCostsSystem()
    updateCostsSummary()
    console.log(`✅ Category duplicated: ${categoryId} → ${newId}`)
}

// Toggle cost category visibility
// Add new cost item to category
function addNewCostItem(categoryId) {
    const category = costsData[categoryId]
    if (!category) return
    
    const itemName = prompt('أدخل اسم البند:')
    if (!itemName) return
    
    const itemId = generateUniqueId('cost')
    const description = prompt('أدخل وصف البند (اختياري):') || ''
    
    // Show calculation type selection dialog
    showCalculationTypeDialog((calculationType, value, unit) => {
        const newCostItem = {
            id: itemId,
            name: itemName,
            description: description,
            calculationType: calculationType,
            value: value,
            unit: unit,
            isCustom: true,
            timeline_activity: null // Can be set later if needed
        }
        
        // Add legacy 'cost' field for backward compatibility
        if (calculationType === COST_CALCULATION_TYPES.FIXED_AMOUNT) {
            newCostItem.value = value
        } else if (calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA || 
                   calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA) {
            newCostItem.value = value
        }
        
        // Initialize costs array if it doesn't exist
        if (!category.costs) {
            category.costs = []
        }
        
        category.costs.push(newCostItem)
        
        dataLogger.info(`تم إضافة بند جديد: ${itemName} إلى ${category.name}`)
        renderCostsSystem()
        updateCostsSummary()
    })
}

// Delete cost item
function deleteCostItem(categoryId, itemId) {
    const category = costsData[categoryId]
    if (!category || !category.costs) return
    
    const itemIndex = category.costs.findIndex(item => item.id === itemId)
    if (itemIndex === -1) return
    
    const item = category.costs[itemIndex]
    if (confirm(`هل تريد حذف البند "${item.name}"؟`)) {
        category.costs.splice(itemIndex, 1)
        dataLogger.info(`تم حذف البند: ${item.name}`)
        renderCostsSystem()
        updateCostsSummary()
    }
}

// Show calculation type selection dialog
function showCalculationTypeDialog(callback) {
    const dialogHTML = `
        <div id="calculationTypeDialog" class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center" style="z-index: 9999;">
            <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-6 max-w-md w-full mx-4">
                <h3 class="text-xl font-bold mb-4">اختر طريقة حساب التكلفة</h3>
                
                <div class="space-y-3 mb-6">
                    <label class="flex items-center">
                        <input type="radio" name="calculationType" value="${COST_CALCULATION_TYPES.FIXED_AMOUNT}" class="mr-2" checked>
                        <span>مبلغ ثابت (ريال)</span>
                    </label>
                    <label class="flex items-center">
                        <input type="radio" name="calculationType" value="${COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION}" class="mr-2">
                        <span>نسبة مئوية من التكلفة الإنشائية (%)</span>
                    </label>
                    <label class="flex items-center">
                        <input type="radio" name="calculationType" value="${COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL}" class="mr-2">
                        <span>نسبة مئوية من إجمالي التكلفة (%)</span>
                    </label>
                    <label class="flex items-center">
                        <input type="radio" name="calculationType" value="${COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA}" class="mr-2">
                        <span>ريال لكل متر مربع (إجمالي المساحة)</span>
                    </label>
                    <label class="flex items-center">
                        <input type="radio" name="calculationType" value="${COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA}" class="mr-2">
                        <span>ريال لكل متر مربع (المساحة القابلة للتأجير)</span>
                    </label>
                </div>
                
                <div class="mb-4">
                    <label class="block text-sm font-medium mb-2">القيمة:</label>
                    <input type="number" id="costValue" class="w-full border border-white/20 rounded px-3 py-2" step="0.01" min="0" required>
                </div>
                
                <div class="flex justify-end space-x-3">
                    <button onclick="closeCalculationTypeDialog()" class="px-4 py-2 text-white/80 border border-white/20 rounded hover:bg-white/5 backdrop-filter backdrop-blur-sm/5">
                        إلغاء
                    </button>
                    <button onclick="confirmCalculationType()" class="px-4 py-2 bg-blue-500/200 text-white rounded hover:bg-blue-600">
                        تأكيد
                    </button>
                </div>
            </div>
        </div>
    `
    
    document.body.insertAdjacentHTML('beforeend', dialogHTML)
    
    // Store callback for later use
    window._calculationTypeCallback = callback
}

// Close calculation type dialog
function closeCalculationTypeDialog() {
    const dialog = $('calculationTypeDialog')
    if (dialog) {
        dialog.remove()
    }
    delete window._calculationTypeCallback
}

// Confirm calculation type selection
function confirmCalculationType() {
    const selectedType = document.querySelector('input[name="calculationType"]:checked')?.value
    const value = num('costValue', 0)
    
    if (!selectedType || value <= 0) {
        alert('يرجى اختيار طريقة الحساب وإدخال قيمة صحيحة')
        return
    }
    
    let unit = ''
    switch (selectedType) {
        case COST_CALCULATION_TYPES.FIXED_AMOUNT:
            unit = 'ريال'
            break
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION:
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL:
            unit = '%'
            break
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA:
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA:
            unit = 'ريال/م²'
            break
        default:
            unit = 'ريال'
    }
    
    if (window._calculationTypeCallback) {
        window._calculationTypeCallback(selectedType, value, unit)
    }
    
    closeCalculationTypeDialog()
}

// Calculate area for specific use type
function calculateUseTypeArea(useTypeId) {
    if (!useTypeId) {
        console.warn('⚠️ No use type specified for calculation')
        return 0
    }
    
    try {
        // Use calculationResults if available, otherwise fallback to calculateTotalAreaForUse
        const totalArea = calculationResults?.areas?.useBreakdown?.[useTypeId]?.gla || calculateTotalAreaForUse(useTypeId)
        console.log(`📊 Total area for ${useTypeId}: ${(totalArea || 0).toLocaleString('en-US')} m²`)
        return totalArea
        
    } catch (error) {
        console.error(`❌ Error calculating area for use type ${useTypeId}:`, error)
        return 0
    }
}

// Calculate cost item value based on its calculation type
// Calculate cost item value with proper system integration
// Calculate cost item value based on calculation type
// Global flags to prevent circular dependency
let isCalculatingConstructionCost = false;
let isCalculatingAdditionalCost = false;
let isCalculatingTotalCost = false;

function calculateCostItemValue(costItem) {
    if (!costItem.calculationType) {
        // For legacy items without calculationType, treat as fixed amount
        return costItem.value || 0
    }
    
    const value = parseFloat(costItem.value) || 0
    if (value === 0) return 0
    
    try {
        switch (costItem.calculationType) {
            case COST_CALCULATION_TYPES.FIXED_AMOUNT:
                return value
                
            case COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION:
                // ⚠️ CRITICAL: Prevent circular dependency
                if (isCalculatingConstructionCost) {
                    console.warn(`⚠️ [CIRCULAR DEPENDENCY] Skipping percentage calculation for: ${costItem.name || 'بند'} (already calculating construction cost)`);
                    return 0; // Return 0 to break the cycle
                }
                const constructionCost = calculateTotalConstructionCost()
                const constructionResult = (value / 100) * constructionCost
                console.log(`📊 [نسبة من التكلفة الإنشائية] ${costItem.name || 'بند'}: ${value}% × ${constructionCost.toLocaleString('en-US')} = ${constructionResult.toLocaleString('en-US')} ريال`)
                return constructionResult
                
            case COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL:
                // ⚠️ CRITICAL: Prevent circular dependency
                if (isCalculatingTotalCost) {
                    console.warn(`⚠️ [CIRCULAR DEPENDENCY] Skipping percentage calculation for: ${costItem.name || 'بند'} (already calculating total cost)`);
                    return 0; // Return 0 to break the cycle
                }
                const totalProjectCost = calculateTotalProjectCostForPercentage()
                const totalResult = (value / 100) * totalProjectCost
                console.log(`📊 [نسبة من إجمالي التكلفة] ${costItem.name || 'بند'}: ${value}% × ${totalProjectCost.toLocaleString('en-US')} (إنشائي + إضافي) = ${totalResult.toLocaleString('en-US')} ريال`)
                return totalResult
                
            case COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE:
                const useTypeArea = calculateUseTypeArea(costItem.useType)
                console.log(`🏗️ Use type area calculation: ${value} × ${(useTypeArea || 0).toLocaleString('en-US')} m² (${costItem.useType}) = ${((value * (useTypeArea || 0)) || 0).toLocaleString('en-US')}`)
                return value * useTypeArea
                
            case COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA:
                const totalGFA = calculateTotalGFA()
                console.log(`🏗️ GFA calculation: ${value} × ${(totalGFA || 0).toLocaleString('en-US')} m² = ${((value * (totalGFA || 0)) || 0).toLocaleString('en-US')}`)
                return value * totalGFA
                
            case COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA:
                const totalGLA = calculateTotalGLA()
                console.log(`🏗️ GLA calculation: ${value} × ${(totalGLA || 0).toLocaleString('en-US')} m² = ${((value * (totalGLA || 0)) || 0).toLocaleString('en-US')}`)
                return value * totalGLA
                
            case COST_CALCULATION_TYPES.PER_SQUARE_METER_LAND:
                const landArea = parseFloat(document.getElementById('landArea')?.value) || 0
                console.log(`🏗️ Land area calculation: ${value} × ${(landArea || 0).toLocaleString('en-US')} m² = ${((value * (landArea || 0)) || 0).toLocaleString('en-US')}`)
                return value * landArea
                
            case COST_CALCULATION_TYPES.PER_UNIT:
                const totalUnits = calculateTotalUnits()
                console.log(`🏗️ Units calculation: ${value} × ${totalUnits.toLocaleString('en-US')} units = ${(value * totalUnits).toLocaleString('en-US')}`)
                return value * totalUnits
                
            default:
                console.warn(`⚠️ Unknown calculation type: ${costItem.calculationType}`)
                return value
        }
    } catch (error) {
        console.error(`❌ Error calculating cost item value:`, error)
        return value // Fallback to raw value
    }
}

