/**
 * Calculate base construction costs with detailed breakdown
 * This is the core calculation function that serves as the foundation
 * @param {number} gfa - Gross Floor Area in square meters
 * @param {number} landArea - Land area in square meters  
 * @returns {Object} Detailed construction cost breakdown
 */
function computeBaseConstructionCosts(gfa, landArea) {
    const financeLogger = LOG.ns('FINANCE')
    financeLogger.info('Computing base construction costs', { gfa, landArea })
    
    try {
        // Core construction costs per square meter (industry standards for Saudi Arabia)
        const rates = {
            structure: 1800,        // Structural work: 1800 SAR/m²
            finishes: 1200,         // Finishing work: 1200 SAR/m² 
            mep: 800,              // MEP systems: 800 SAR/m²
            infrastructure: 150,    // Infrastructure: 150 SAR/m² of land
            landscaping: 100       // Landscaping: 100 SAR/m² of land
        }
        
        // Fixed costs (independent of area)
        const fixedCosts = {
            design: 500000,         // Design and supervision
            permits: 300000         // Permits and approvals
        }
        
        // Calculate area-based costs
        const areaCosts = {
            structure: gfa * rates.structure,
            finishes: gfa * rates.finishes, 
            mep: gfa * rates.mep,
            infrastructure: landArea * rates.infrastructure,
            landscaping: landArea * rates.landscaping
        }
        
        // Combine all costs
        const breakdown = {
            // Area-based costs
            ...areaCosts,
            // Fixed costs  
            ...fixedCosts,
            // Totals
            totalAreaBased: Object.values(areaCosts).reduce((sum, cost) => sum + cost, 0),
            totalFixed: Object.values(fixedCosts).reduce((sum, cost) => sum + cost, 0)
        }
        
        breakdown.total = breakdown.totalAreaBased + breakdown.totalFixed
        
        financeLogger.info('Construction cost breakdown completed', {
            gfa: gfa.toLocaleString('en-US'),
            landArea: landArea.toLocaleString('en-US'), 
            structure: breakdown.structure.toLocaleString('en-US'),
            finishes: breakdown.finishes.toLocaleString('en-US'),
            mep: breakdown.mep.toLocaleString('en-US'),
            infrastructure: breakdown.infrastructure.toLocaleString('en-US'),
            landscaping: breakdown.landscaping.toLocaleString('en-US'),
            design: breakdown.design.toLocaleString('en-US'),
            permits: breakdown.permits.toLocaleString('en-US'),
            total: breakdown.total.toLocaleString('en-US')
        })
        
        return breakdown
        
    } catch (error) {
        financeLogger.error('Error computing base construction costs', { error: error.message, gfa, landArea })
        return {
            structure: 0, finishes: 0, mep: 0, infrastructure: 0, 
            landscaping: 0, design: 0, permits: 0,
            totalAreaBased: 0, totalFixed: 0, total: 0
        }
    }
}

/**
 * Unified investment snapshot calculator - Single source of truth
 * Returns complete financial snapshot with all calculations
 * @returns {Object} Complete investment calculation snapshot
 */
function computeInvestmentSnapshot() {
    const financeLogger = LOG.ns('FINANCE')
    financeLogger.info('Computing unified investment snapshot...')
    
    try {
        // 1. Get basic parameters from UI
        const landArea = num($('landArea')?.value) || 10000
        const landPrice = num($('purchasePrice')?.value) || 2000  
        const far = num($('far')?.value) || 3.5
        const gfa = landArea * far
        
        financeLogger.debug('Basic parameters extracted', {
            landArea: landArea.toLocaleString('en-US'),
            landPrice: landPrice.toLocaleString('en-US'),
            far,
            gfa: gfa.toLocaleString('en-US')
        })
        
        // 2. Calculate base construction costs
        const constructionBreakdown = computeBaseConstructionCosts(gfa, landArea)
        
        // 3. Calculate land acquisition cost
        const landCost = landArea * landPrice
        
        // 4. Calculate additional costs (percentages and extras)
        const additionalCosts = calculateAdditionalCosts(constructionBreakdown.total)
        
        // 5. Create complete financial snapshot
        const snapshot = {
            // Input parameters
            parameters: {
                landArea,
                landPrice, 
                far,
                gfa
            },
            
            // Construction costs breakdown
            construction: constructionBreakdown,
            
            // Land costs
            land: {
                area: landArea,
                pricePerSqm: landPrice,
                total: landCost
            },
            
            // Additional costs
            additional: additionalCosts,
            
            // Summary totals
            totals: {
                construction: constructionBreakdown.total,
                land: landCost,
                additional: additionalCosts.total,
                investment: constructionBreakdown.total + landCost + additionalCosts.total
            },
            
            // Metadata
            timestamp: Date.now(),
            version: '1.0.0'
        }
        
        financeLogger.info('Investment snapshot completed', {
            construction: snapshot.totals.construction.toLocaleString('en-US'),
            land: snapshot.totals.land.toLocaleString('en-US'), 
            additional: snapshot.totals.additional.toLocaleString('en-US'),
            totalInvestment: snapshot.totals.investment.toLocaleString('en-US')
        })
        
        return snapshot
        
    } catch (error) {
        financeLogger.error('Error computing investment snapshot', { error: error.message })
        
        // Return safe default snapshot
        return {
            parameters: { landArea: 0, landPrice: 0, far: 0, gfa: 0 },
            construction: { total: 0 },
            land: { total: 0 },
            additional: { total: 0 },
            totals: { construction: 0, land: 0, additional: 0, investment: 0 },
            timestamp: Date.now(),
            version: '1.0.0',
            error: error.message
        }
    }
}

/**
 * Calculate additional costs (government fees, consultant fees, etc.)
 * @param {number} baseConstructionCost - Base construction cost for percentage calculations
 * @returns {Object} Additional costs breakdown
 */
function calculateAdditionalCosts(baseConstructionCost) {
    const financeLogger = LOG.ns('FINANCE')
    
    try {
        // Get percentages from UI (with defaults)
        const percentages = {
            govFees: num($('govFees')?.value) || 8,
            consultantFees: num($('consultantFees')?.value) || 5, 
            supervisionFees: num($('supervisionFees')?.value) || 3,
            developerFees: num($('developerFees')?.value) || 10,
            contingency: num($('contingency')?.value) || 7
        }
        
        // Calculate percentage-based costs
        const costs = {}
        let total = 0
        
        Object.entries(percentages).forEach(([key, percentage]) => {
            const cost = (baseConstructionCost * percentage) / 100
            costs[key] = cost
            total += cost
        })
        
        const breakdown = {
            ...costs,
            total,
            percentages
        }
        
        financeLogger.debug('Additional costs calculated', {
            baseConstructionCost: baseConstructionCost.toLocaleString('en-US'),
            govFees: costs.govFees?.toLocaleString('en-US'),
            consultantFees: costs.consultantFees?.toLocaleString('en-US'),
            supervisionFees: costs.supervisionFees?.toLocaleString('en-US'), 
            developerFees: costs.developerFees?.toLocaleString('en-US'),
            contingency: costs.contingency?.toLocaleString('en-US'),
            total: total.toLocaleString('en-US')
        })
        
        return breakdown
        
    } catch (error) {
        financeLogger.error('Error calculating additional costs', { error: error.message })
        return { total: 0 }
    }
}

