/**
 * حساب التكلفة الإجمالية للمشروع (إنشائية + إضافية)
 * يُستخدم لحساب النسب المئوية من إجمالي التكلفة
 * يجمع: التكاليف الإنشائية + التكاليف الإضافية (باستثناء النسب المئوية لمنع التكرار اللانهائي)
 * 
 * الصيغة: إجمالي التكلفة = التكاليف الإنشائية + التكاليف الإضافية
 */
function calculateTotalProjectCostForPercentage() {
    // Prevent infinite recursion
    if (isCalculatingTotalProjectCost) {
        console.log('⚠️ [calculateTotalProjectCostForPercentage] منع التكرار اللانهائي')
        return 0
    }
    
    isCalculatingTotalProjectCost = true
    
    try {
        console.log(`💰 [calculateTotalProjectCostForPercentage] ═══════════════════════════════════════════`)
        console.log(`💰 [calculateTotalProjectCostForPercentage] بدء حساب التكلفة الإجمالية للمشروع...`)
        console.log(`💰 [calculateTotalProjectCostForPercentage] ═══════════════════════════════════════════`)
        
        // 1️⃣ حساب التكاليف الإنشائية (جميع الأقسام ذات categoryType='construction')
        const constructionTotal = calculateTotalConstructionCost()
        console.log(`💰 [calculateTotalProjectCostForPercentage] 1️⃣ التكاليف الإنشائية: ${constructionTotal.toLocaleString('en-US')} ريال`)
        
        // 2️⃣ حساب التكاليف الإضافية (جميع الأقسام ذات categoryType='additional')
        const additionalTotal = calculateTotalAdditionalCost()
        console.log(`💰 [calculateTotalProjectCostForPercentage] 2️⃣ التكاليف الإضافية: ${additionalTotal.toLocaleString('en-US')} ريال`)
        
        // 3️⃣ الإجمالي = إنشائي + إضافي
        const total = constructionTotal + additionalTotal
        console.log(`💰 [calculateTotalProjectCostForPercentage] ═══════════════════════════════════════════`)
        console.log(`💰 [calculateTotalProjectCostForPercentage] 3️⃣ التكلفة الإجمالية = ${constructionTotal.toLocaleString('en-US')} + ${additionalTotal.toLocaleString('en-US')} = ${total.toLocaleString('en-US')} ريال`)
        console.log(`💰 [calculateTotalProjectCostForPercentage] ═══════════════════════════════════════════`)
        
        return total
        
    } catch (error) {
        console.error(`❌ [calculateTotalProjectCostForPercentage] خطأ في حساب التكلفة الإجمالية:`, error)
        return 0
    } finally {
        // Reset the flag
        isCalculatingTotalProjectCost = false
    }
}

// Calculate total GFA (Gross Floor Area) from floors management system
function calculateTotalGFA() {
    let totalGFA = 0
    
    try {
        // First try to get from floors management system (more accurate)
        if (typeof floorsData !== 'undefined' && floorsData && Object.keys(floorsData).length > 0) {
            Object.values(floorsData).forEach(floor => {
                const floorGFA = parseFloat(floor.totalArea || 0)
                if (floorGFA > 0) {
                    totalGFA += floorGFA
                    gfaLogger.debug(`Floor "${floor.name || 'Unknown'}": ${floorGFA.toLocaleString('en-US')} m² GFA`)
                }
            })
            if (totalGFA > 0) {
                gfaLogger.info(`Total GFA from floors system: ${totalGFA.toLocaleString('en-US')} m²`)
                return totalGFA
            }
        }
        
        // Fallback: Calculate from land area × FAR if floors system is empty
        const landArea = num('landArea', 0)
        const far = num('far', 0)
        if (landArea > 0 && far > 0) {
            totalGFA = landArea * far
            console.log(`🏗️ GFA calculated from land area × FAR: ${landArea.toLocaleString('en-US')} × ${far} = ${totalGFA.toLocaleString('en-US')} m²`)
            return totalGFA
        }
        
        // Second fallback: Get from enhanced uses management system
        if (typeof usesData !== 'undefined' && usesData) {
            Object.values(usesData).forEach(use => {
                const useGFA = parseFloat(use.totalArea) || 0
                if (useGFA > 0) {
                    totalGFA += useGFA
                    console.log(`🏗️ Use "${use.name || 'Unknown'}": ${useGFA.toLocaleString('en-US')} m² GFA`)
                }
            })
        }
        
        console.log(`🏗️ Total GFA from uses system: ${totalGFA.toLocaleString('en-US')} m²`)
        return totalGFA
        
    } catch (error) {
        console.error(`❌ Error calculating GFA:`, error)
        return 0
    }
}

// Calculate total GLA (Gross Leasable Area) from uses management system
function calculateTotalGLA() {
    let totalGLA = 0
    
    try {
        // Get from enhanced uses management system
        if (typeof usesData !== 'undefined' && usesData) {
            Object.values(usesData).forEach(use => {
                const useGLA = parseFloat(use.totalGLA || use.leasableArea || 0)
                // ✅ CRITICAL: احترام countInGLA filter - استثناء الاستخدامات الخدمية
                const shouldCount = use.countInGLA !== false
                if (useGLA > 0 && shouldCount) {
                    totalGLA += useGLA
                    console.log(`🏗️ Use "${use.name || 'Unknown'}": ${useGLA.toLocaleString('en-US')} m² GLA ✅ محسوب`)
                } else if (useGLA > 0 && !shouldCount) {
                    console.log(`🏗️ Use "${use.name || 'Unknown'}": ${useGLA.toLocaleString('en-US')} m² GLA ❌ خدمي (مستثنى)`)
                }
            })
        }
        
        // If no GLA data from uses system, try to calculate from GFA with typical ratio
        if (totalGLA === 0) {
            const totalGFA = calculateTotalGFA()
            if (totalGFA > 0) {
                // Assume 85% efficiency ratio for commercial buildings
                totalGLA = totalGFA * 0.85
                console.log(`🏗️ GLA estimated from GFA: ${totalGFA.toLocaleString('en-US')} × 0.85 = ${totalGLA.toLocaleString('en-US')} m²`)
            }
        }
        
        console.log(`🏗️ Total GLA from uses system: ${totalGLA.toLocaleString('en-US')} m²`)
        return totalGLA
        
    } catch (error) {
        console.error(`❌ Error calculating GLA:`, error)
        return 0
    }
}

// Calculate total units count from uses management system
function calculateTotalUnits() {
    let totalUnits = 0
    
    // Get from enhanced uses management system
    if (typeof usesData !== 'undefined' && usesData) {
        Object.values(usesData).forEach(use => {
            const useUnits = parseFloat(use.totalUnits || 0)
            if (useUnits > 0) {
                totalUnits += useUnits
                console.log(`🏗️ Use "${use.name || 'Unknown'}": ${useUnits.toLocaleString('en-US')} units`)
            }
        })
    }
    
    console.log(`🏗️ Total units from uses system: ${totalUnits.toLocaleString('en-US')} units`)
    return totalUnits
}

// Update cost item value
function updateCostItemValue(categoryId, itemId, newValue) {
    const category = costsData[categoryId]
    if (!category || !category.costs) return
    
    const item = category.costs.find(cost => cost.id === itemId)
    if (!item) return
    
    item.value = newValue
    
    // Update legacy 'cost' field for backward compatibility
    if (item.calculationType === COST_CALCULATION_TYPES.FIXED_AMOUNT || 
        item.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA ||
        item.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA) {
        item.value = newValue
    }
    
    console.log(`💰 تم تحديث ${item.name}: ${newValue} ${item.unit}`)
    // CRITICAL FIX: Do NOT re-render the entire costs system to preserve user inputs
    updateCostsSummary()
}

// Edit cost item
function editCostItem(categoryId, itemId) {
    const category = costsData[categoryId]
    if (!category || !category.costs) return
    
    const item = category.costs.find(cost => cost.id === itemId)
    if (!item) return
    
    const newName = prompt('أدخل الاسم الجديد:', item.name)
    if (newName && newName !== item.name) {
        item.name = newName
    }
    
    const newDescription = prompt('أدخل الوصف الجديد:', item.description || '')
    if (newDescription !== null) {
        item.description = newDescription
    }
    
    // CRITICAL FIX: Only re-render if major changes (name/description), not value changes
    // For now, disable to preserve user inputs
    console.log('✅ Cost item edited without full system re-render')
}

// Get display text for calculation type
function getCalculationTypeDisplay(costItem) {
    if (!costItem.calculationType) {
        return 'مبلغ ثابت'
    }
    
    switch (costItem.calculationType) {
        case COST_CALCULATION_TYPES.FIXED_AMOUNT:
            return 'مبلغ ثابت'
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION:
            return `${costItem.value}% من التكلفة الإنشائية`
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL:
            return `${costItem.value}% من إجمالي التكلفة`
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA:
            return `${costItem.value} ريال/م² (إجمالي المساحة)`
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA:
            return `${costItem.value} ريال/م² (المساحة القابلة للتأجير)`
        case COST_CALCULATION_TYPES.PER_UNIT:
            return `${costItem.value} ريال/وحدة`
        default:
            return 'غير محدد'
    }
}

// Calculate total for custom cost category
function calculateCustomCategoryTotal(category) {
    if (!category.costs || !Array.isArray(category.costs)) {
        return 0
    }
    
    return category.costs.reduce((total, cost) => {
        return total + calculateCostItemValue(cost)
    }, 0)
}

