// Load translations
async function loadTranslations() {
    const fallbackBundle = TRANSLATION_FALLBACKS[currentLang] || TRANSLATION_FALLBACKS.ar || {}

    try {
        const response = await fetch(`/api/translations/${currentLang}`, {
            headers: { 'Accept': 'application/json' },
            cache: 'no-store'
        })

        if (!response.ok) {
            throw new Error(`Translation request failed with status ${response.status}`)
        }

        const payload = await response.json()
        translations = { ...fallbackBundle, ...payload }
    } catch (error) {
        console.error('Failed to load translations:', error)
        translations = { ...fallbackBundle }
    }

    if (typeof window !== 'undefined') {
        window.translations = translations
    }

    if (typeof document !== 'undefined') {
        if (translations.locale) {
            document.documentElement.lang = translations.locale
        }
        if (translations.direction) {
            document.documentElement.dir = translations.direction
        }
    }

    updateUI()
}

// Toggle language
async function toggleLanguage() {
    currentLang = currentLang === 'ar' ? 'en' : 'ar'
    await loadTranslations()
    
    // Update document direction and font
    document.documentElement.lang = currentLang
    document.body.className = currentLang === 'ar' ? 'bg-white/5 arabic rtl' : 'bg-white/5 english ltr'
    
    // Update language button text
    const langText = $('langText')
    if (langText) langText.textContent = currentLang === 'ar' ? 'English' : 'العربية'
    
    // Update map translations if map is available
    if (typeof updateMapTranslations === 'function') {
        updateMapTranslations()
    }
}

// City selection handler for dropdown
function onCitySelect(cityName) {
    // Get the selected option element
    const selectElement = $('city');
    const selectedOption = selectElement.querySelector('option[value="' + cityName + '"]');
    
    if (selectedOption) {
        const lat = parseFloat(selectedOption.dataset.lat);
        const lng = parseFloat(selectedOption.dataset.lng);
        
        // Update map location if map functions are available
        if (typeof updateMapLocation === 'function') {
            updateMapLocation(lat, lng, cityName);
        }
    }
}

// Make function globally available
window.onCitySelect = onCitySelect;

/**
 * تحديث موقع الخريطة الرئيسية بناءً على الإحداثيات
 * @param {number} lat - خط العرض
 * @param {number} lng - خط الطول
 * @param {string} locationName - اسم الموقع
 */
function updateMapLocation(lat, lng, locationName) {
    console.log(`🗺️ تحديث موقع الخريطة: ${locationName} (${lat}, ${lng})`);
    
    // تحديث حقول الإحداثيات
    const latField = document.getElementById('currentLatitude');
    const lngField = document.getElementById('currentLongitude');
    const nameField = document.getElementById('currentLocationName');
    
    if (latField) latField.value = lat;
    if (lngField) lngField.value = lng;
    if (nameField) nameField.textContent = locationName;
    
    // تحديث الخريطة إذا كانت موجودة
    if (typeof window.mainMap !== 'undefined' && window.mainMap) {
        window.mainMap.setView([lat, lng], 13);
        if (window.mainMarker) {
            window.mainMarker.setLatLng([lat, lng]);
            window.mainMarker.bindPopup(`<b>${locationName}</b>`).openPopup();
        }
    }
    
    console.log('✅ تم تحديث موقع الخريطة بنجاح');
}

/**
 * تحديث الخريطة من حقول الإحداثيات
 */
function updateMapFromCoordinates() {
    const latField = document.getElementById('currentLatitude');
    const lngField = document.getElementById('currentLongitude');
    const nameField = document.getElementById('currentLocationName');
    
    if (!latField || !lngField) {
        console.warn('⚠️ حقول الإحداثيات غير موجودة');
        return;
    }
    
    const lat = parseFloat(latField.value);
    const lng = parseFloat(lngField.value);
    const locationName = nameField?.textContent || 'موقع مخصص';
    
    if (isNaN(lat) || isNaN(lng)) {
        console.warn('⚠️ إحداثيات غير صحيحة');
        return;
    }
    
    updateMapLocation(lat, lng, locationName);
}

/**
 * توسيط الخريطة على الإحداثيات الحالية
 */
function centerMapOnCoordinates() {
    console.log('📍 توسيط الخريطة على الإحداثيات الحالية...');
    updateMapFromCoordinates();
}

/**
 * التحقق من صحة الإحداثيات
 */
function validateCoordinates() {
    const latField = document.getElementById('currentLatitude');
    const lngField = document.getElementById('currentLongitude');
    
    if (!latField || !lngField) return;
    
    let lat = parseFloat(latField.value);
    let lng = parseFloat(lngField.value);
    
    // التحقق من النطاق الصحيح
    if (isNaN(lat) || lat < -90 || lat > 90) {
        console.warn('⚠️ خط عرض غير صحيح، استخدام الرياض');
        lat = 24.7136;
        latField.value = lat;
    }
    
    if (isNaN(lng) || lng < -180 || lng > 180) {
        console.warn('⚠️ خط طول غير صحيح، استخدام الرياض');
        lng = 46.6753;
        lngField.value = lng;
    }
}

