/**
 * إبطال cache عند تغيير البيانات
 */
function invalidateCalculationCache() {
    calculationCache.timestamp = 0
    calculationCache.result = null
    console.log('🔄 تم إبطال cache الحسابات')
}

/**
 * إعداد آلية مراقبة شاملة لتحديث معاملات الاستثمار تلقائياً (مع منع التداخل)
 */
function setupInvestmentParametersMonitoring() {
    console.log('🚀 بدء إعداد مراقبة معاملات الاستثمار...')
    
    // قائمة الحقول المهمة للمراقبة
    const importantFields = [
        // معاملات المشروع الأساسية
        'landArea',
        'far', 
        'purchasePrice',
        
        // معاملات التمويل
        'equityRatio',
        'interestRate',
        'financingTerm',
        'constructionPeriod',
        'operatingPeriod'
    ]
    
    // إضافة مستمعين للحقول المهمة
    let setupCount = 0
    importantFields.forEach(fieldId => {
        const field = document.getElementById(fieldId)
        if (field) {
            // مراقبة التغييرات الفورية والمتأخرة
            ['input', 'change', 'blur'].forEach(eventType => {
                field.addEventListener(eventType, function() {
                    console.log(`🔄 تغير في ${fieldId}: ${this.value}`)
                    
                    // إبطال cache عند الحاجة فقط
                    if (fieldId === 'landArea' || fieldId === 'purchasePrice') {
                        invalidateCalculationCache()
                    }
                    
                    // تأخير أطول وتحديث محدود
                    replaceableTimeout(() => {
                        if (!isUpdatingInvestmentParameters) {
                            console.log(`🔧 تحديث محدود لـ ${fieldId}`)
                            // تحديث محدود بدلاً من التحديث الشامل
                            if (fieldId === 'landArea' || fieldId === 'purchasePrice') {
                                updateTotalInvestmentField()
                            }
                        }
                    }, 800, 'investmentUpdate', `تحديث معاملات الاستثمار لـ ${fieldId}`)
                })
            })
            setupCount++
            console.log(`✅ تم إعداد مراقبة ${fieldId}`)
        } else {
            console.warn(`⚠️ لم يتم العثور على الحقل ${fieldId}`)
        }
    })
    
    // مراقبة التغييرات في حقول التكاليف بشكل محدود ومُتحكم
    const costInputs = document.querySelectorAll('.cost-value, .cost-percentage, input[name*="cost"], input[id*="cost"]')
    let costUpdateDelay = 1500 // زيادة التأخير لمنع التحديثات المفرطة
    
    costInputs.forEach(input => {
        ['change', 'blur'].forEach(eventType => { // إزالة 'input' لتقليل التحديثات
            input.addEventListener(eventType, function() {
                console.log('💰 تغير في التكاليف - تحديث محدود')
                
                // إبطال cache فقط عند الحاجة
                invalidateCalculationCache()
                
                replaceableTimeout(() => {
                    if (!isUpdatingInvestmentParameters) {
                        // تحديث محدود بدلاً من التحديث الشامل
                        console.log('🔄 تحديث محدود للاستثمار')
                    }
                }, costUpdateDelay, 'costUpdate', 'تحديث محدود للتكاليف')
            })
        })
    })
    
    // مراقبة تغييرات DOM للعناصر المضافة ديناميكياً
    if (window.MutationObserver) {
        const observer = new MutationObserver(mutations => {
            mutations.forEach(mutation => {
                if (mutation.type === 'childList') {
                    mutation.addedNodes.forEach(node => {
                        if (node.nodeType === 1) { // Element node
                            // إذا تمت إضافة حقول تكاليف جديدة
                            const newCostInputs = node.querySelectorAll?.('.cost-value, .cost-percentage, input[name*="cost"], input[id*="cost"]') || []
                            newCostInputs.forEach(input => {
                                ['input', 'change'].forEach(eventType => {
                                    input.addEventListener(eventType, function() {
                                        console.log('🆕 حقل تكلفة جديد - تحديث إجمالي الاستثمار')
                                        replaceableTimeout(() => {
                                            updateTotalInvestmentField()
                                        }, 300, 'newCostUpdate', 'تحديث لحقل تكلفة جديد')
                                    })
                                })
                            })
                        }
                    })
                }
            })
        })
        
        // بدء مراقبة التغييرات في كامل الصفحة
        observer.observe(document.body, {
            childList: true,
            subtree: true
        })
        
        console.log('✅ تم إعداد MutationObserver لمراقبة العناصر الجديدة')
    }
    
    console.log(`✅ تم إعداد مراقبة ${setupCount} حقل مهم + ${costInputs.length} حقل تكاليف`)
    console.log('🚀 اكتمل إعداد مراقبة معاملات الاستثمار!')
}

