function diagnoseInvestmentParametersSystem() {
    console.log('🔬 === تشخيص نظام معاملات الاستثمار ===')
    
    // فحص حالة النظام
    console.log('📊 حالة النظام:')
    console.log('  - isUpdatingInvestmentParameters:', isUpdatingInvestmentParameters)
    console.log('  - Cache timestamp:', calculationCache.timestamp)
    console.log('  - Cache result:', calculationCache.result ? calculationCache.result.toLocaleString('en-US') : 'null')
    console.log('  - Cache age:', Date.now() - calculationCache.timestamp, 'ms')
    
    // فحص وجود العناصر
    const totalInvestmentElement = document.getElementById('totalInvestment')
    console.log('🎯 عناصر الواجهة:')
    console.log('  - totalInvestment element:', !!totalInvestmentElement)
    console.log('  - Current value:', totalInvestmentElement?.value || 'N/A')
    
    // فحص بيانات الحساب
    const landArea = parseFloat(document.getElementById('landArea')?.value) || 0
    const landPrice = parseFloat(document.getElementById('purchasePrice')?.value) || 0
    console.log('💰 بيانات الحساب:')
    console.log('  - Land Area:', landArea.toLocaleString('en-US'), 'm²')
    console.log('  - Land Price:', landPrice.toLocaleString('en-US'), 'SAR/m²')
    console.log('  - Land Cost:', (landArea * landPrice).toLocaleString('en-US'), 'SAR')
    
    // حساب تجريبي
    console.log('🧪 حساب تجريبي:')
    try {
        const totalCost = calculateTotalCostUnified()
        const landCost = landArea * landPrice
        const totalInvestment = totalCost + landCost
        console.log('  - Total Cost:', totalCost.toLocaleString('en-US'), 'SAR')
        console.log('  - Total Investment:', totalInvestment.toLocaleString('en-US'), 'SAR')
        
        // مقارنة مع القيمة الحالية
        const currentValue = parseFloat(totalInvestmentElement?.value?.replace(/,/g, '') || '0')
        const difference = Math.abs(totalInvestment - currentValue)
        console.log('  - Current vs Calculated difference:', difference.toLocaleString('en-US'), 'SAR')
        
        if (difference > 1000) {
            console.warn('⚠️ هناك اختلاف كبير بين القيمة المحسوبة والقيمة المعروضة')
        } else {
            console.log('✅ القيم متطابقة')
        }
        
    } catch (error) {
        console.error('❌ خطأ في الحساب التجريبي:', error)
    }
    
    console.log('🔍 === انتهى التشخيص ===')
    
    return {
        isUpdating: isUpdatingInvestmentParameters,
        cacheAge: Date.now() - calculationCache.timestamp,
        hasElement: !!totalInvestmentElement,
        currentValue: totalInvestmentElement?.value
    }
}

