// Validate that total shares don't exceed 100% (updated for new system)
function validateSubUnitsTotal(useType) {
    try {
        const useData = usesData[useType]
        if (!useData || !useData.subUnits) return
        
        const totalPercentage = useData.subUnits.reduce((total, subUnit) => {
            return total + (subUnit.percentage || 0)
        }, 0)
        
        console.log(`🔍 Updating ${useType}: ${totalPercentage}% (${useData.subUnits.length} sub-units)`)
        
        // تحديث المؤشر الثابت
        updatePercentageIndicator(useType, totalPercentage)
        
        return totalPercentage === 100
    } catch (error) {
        console.error('❌ Error validating sub-units total:', error)
        return false
    }
}

// دالة محسّنة لتحديث مؤشر النسب مع تفاصيل إضافية
// Enhanced percentage indicator update function with additional details
function updatePercentageIndicator(useType, totalPercentage) {
    const indicatorElement = document.getElementById(`percentage-indicator-${useType}`)
    const textElement = document.getElementById(`percentage-text-${useType}`)
    const iconElement = document.getElementById(`percentage-icon-${useType}`)
    
    if (!indicatorElement || !textElement || !iconElement) return
    
    // حساب الفرق عن 100%
    const difference = 100 - totalPercentage
    
    // تحديث النص مع التفاصيل
    let displayText = `${totalPercentage.toFixed(1)}%`
    
    // تحديد اللون والأيقونة حسب النسبة
    let bgColor, textColor, icon, borderColor, extraInfo = ''
    
    if (totalPercentage === 100) {
        // 100% - أخضر
        bgColor = 'bg-emerald-500/25'
        textColor = 'text-emerald-300'
        borderColor = 'border-emerald-400/40'
        icon = 'fa-check-circle text-emerald-300'
        extraInfo = '<span class="text-xs mr-1">✓ مكتمل</span>'
    } else if (totalPercentage < 100) {
        // أقل من 100% - أصفر
        bgColor = 'bg-amber-500/25'
        textColor = 'text-amber-200'
        borderColor = 'border-amber-400/40'
        icon = 'fa-exclamation-triangle text-yellow-500'
        extraInfo = `<span class="text-xs mr-1">ينقص ${Math.abs(difference).toFixed(1)}%</span>`
    } else {
        // أكثر من 100% - أحمر
        bgColor = 'bg-red-500/25'
        textColor = 'text-red-200'
        borderColor = 'border-red-400/40'
        icon = 'fa-times-circle text-red-500'
        extraInfo = `<span class="text-xs mr-1">زائد ${Math.abs(difference).toFixed(1)}%</span>`
    }
    
    // تطبيق الأنماط
    indicatorElement.className = `flex items-center gap-2 px-3 py-1 rounded-full text-sm font-medium border ${bgColor} ${textColor} ${borderColor}`
    iconElement.className = `fas ${icon} text-xs`
    textElement.innerHTML = `${displayText} ${extraInfo}`
    
    // إضافة زر التوزيع التلقائي إذا لم تكن النسبة 100%
    const autoDistributeBtn = indicatorElement.querySelector('.auto-distribute-btn')
    
    if (totalPercentage !== 100 && !autoDistributeBtn) {
        const btn = document.createElement('button')
        btn.className = 'auto-distribute-btn ml-2 px-2 py-0.5 bg-opacity-70 hover:bg-opacity-100 rounded text-xs transition-all'
        btn.style.backgroundColor = totalPercentage < 100 ? '#EAB308' : '#DC2626'
        btn.style.color = 'white'
        btn.textContent = 'توزيع تلقائي'
        btn.onclick = () => autoDistributePercentages(useType)
        indicatorElement.appendChild(btn)
    } else if (totalPercentage === 100 && autoDistributeBtn) {
        autoDistributeBtn.remove()
    }
}

/**
 * توزيع تلقائي للنسب
 * Auto-distribute percentages
 */
function autoDistributePercentages(useId) {
    try {
        const use = usesData[useId]
        if (!use || !use.subUnits || use.subUnits.length === 0) {
            showNotification('لا توجد وحدات فرعية للتوزيع', 'warning', 2000)
            return
        }
        
        // حساب النسبة المتساوية
        const equalShare = (100 / use.subUnits.length)
        
        if (confirm(
            `هل تريد توزيع النسب بالتساوي؟\n\n` +
            `كل وحدة ستحصل على ${equalShare.toFixed(1)}%\n` +
            `(${use.subUnits.length} وحدات)`
        )) {
            // توزيع النسب
            use.subUnits.forEach((subUnit, index) => {
                if (index < use.subUnits.length - 1) {
                    subUnit.percentage = parseFloat(equalShare.toFixed(1))
                } else {
                    // الوحدة الأخيرة تأخذ الباقي لضمان 100%
                    const sumSoFar = use.subUnits.slice(0, -1).reduce((sum, sub) => sum + sub.percentage, 0)
                    subUnit.percentage = parseFloat((100 - sumSoFar).toFixed(1))
                }
            })
            
            // تحديث النظام
            updateUsesCalculations()
            renderUsesSystem()
            
            showNotification('تم التوزيع التلقائي بنجاح!', 'success', 2000)
            console.log(`✅ Auto-distributed percentages for ${useId}`)
        }
    } catch (error) {
        console.error('❌ Error in auto-distribute:', error)
        showNotification('حدث خطأ أثناء التوزيع التلقائي', 'error', 3000)
    }
}

