// 🚀 v11.0 ENHANCEMENT: Performance Optimization System
// ============================================================================

/**
 * نظام Debouncing للتحديثات
 * Debouncing System for Updates
 * 
 * يؤجل التحديثات المتكررة لتحسين الأداء
 * Delays repeated updates to improve performance
 */
const DebouncingSystem = {
    timers: {},
    
    /**
     * تنفيذ دالة مع debouncing
     * Execute function with debouncing
     */
    debounce(key, callback, delay = 300) {
        // إلغاء المؤقت السابق
        if (this.timers[key]) {
            clearTimeout(this.timers[key]);
        }
        
        // جدولة تنفيذ جديد
        this.timers[key] = setTimeout(() => {
            callback();
            delete this.timers[key];
        }, delay);
    },
    
    /**
     * إلغاء debouncing لمفتاح معين
     * Cancel debouncing for specific key
     */
    cancel(key) {
        if (this.timers[key]) {
            clearTimeout(this.timers[key]);
            delete this.timers[key];
        }
    },
    
    /**
     * تنفيذ فوري وإلغاء المؤقت
     * Execute immediately and cancel timer
     */
    flush(key, callback) {
        this.cancel(key);
        callback();
    }
};

/**
 * نظام Partial Re-render
 * Partial Re-render System
 * 
 * يحدث أجزاء محددة من الواجهة بدلاً من إعادة رسم كل شيء
 * Updates specific parts of UI instead of re-rendering everything
 */
const PartialRenderSystem = {
    /**
     * تحديث بطاقة استخدام واحدة فقط
     * Update single use card only
     */
    updateSingleUseCard(useId) {
        try {
            const use = usesData[useId];
            if (!use) {
                console.warn(`⚠️ Use ${useId} not found for partial update`);
                return false;
            }
            
            // البحث عن البطاقة الحالية
            const cardElement = document.querySelector(`[data-use-id="${useId}"]`);
            if (!cardElement) {
                console.warn(`⚠️ Card element for ${useId} not found`);
                return false;
            }
            
            // إنشاء HTML جديد
            const newCardHTML = createUseCard(use);
            
            // استبدال البطاقة القديمة
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = newCardHTML;
            const newCard = tempDiv.firstElementChild;
            
            cardElement.replaceWith(newCard);
            
            console.log(`✅ Partially updated card for ${useId}`);
            return true;
            
        } catch (error) {
            console.error('❌ Error in partial card update:', error);
            return false;
        }
    },
    
    /**
     * تحديث قيمة حقل واحد في sub-unit بدون إعادة رسم
     * Update single sub-unit field value without re-render
     */
    updateSubUnitField(useId, subUnitId, field, value) {
        try {
            const fieldElement = document.querySelector(
                `[data-subunit-id="${subUnitId}"] [data-field="${field}"]`
            );
            
            if (fieldElement) {
                if (fieldElement.tagName === 'INPUT') {
                    fieldElement.value = value;
                } else {
                    fieldElement.textContent = value;
                }
                return true;
            }
            
            return false;
        } catch (error) {
            console.error('❌ Error updating sub-unit field:', error);
            return false;
        }
    },
    
    /**
     * تحديث مؤشر النسب فقط
     * Update percentage indicator only
     */
    updatePercentageIndicatorOnly(useId, totalPercentage) {
        updatePercentageIndicator(useId, totalPercentage);
    }
};

/**
 * دالة محسّنة لتحديث sub-unit مع debouncing
 * Enhanced sub-unit update function with debouncing
 */
function updateSubUnitDebounced(useId, subUnitId, field, value) {
    try {
        // 1️⃣ تحديث فوري في الذاكرة
        const subUnit = usesData[useId].subUnits.find(sub => sub.id === subUnitId);
        if (!subUnit) {
            console.warn(`⚠️ SubUnit ${subUnitId} not found`);
            return;
        }
        
        // تحديث القيمة
        if (field === 'name') {
            subUnit[field] = value;
        } else {
            subUnit[field] = parseFloat(value) || 0;
        }
        
        // 2️⃣ تحديث فوري للواجهة (الحقل نفسه فقط)
        PartialRenderSystem.updateSubUnitField(useId, subUnitId, field, value);
        
        // 3️⃣ تحديث مؤشر النسب فوراً (إذا كان percentage)
        if (field === 'percentage') {
            const totalPercentage = usesData[useId].subUnits.reduce((sum, sub) => sum + (sub.percentage || 0), 0);
            PartialRenderSystem.updatePercentageIndicatorOnly(useId, totalPercentage);
        }
        
        // 4️⃣ تأجيل الحسابات الثقيلة والمزامنة
        const debounceKey = `subunit-${useId}-${subUnitId}`;
        
        DebouncingSystem.debounce(debounceKey, () => {
            console.log(`🔄 Processing debounced update for ${useId}.${subUnitId}.${field}`);
            
            // تحديث الحسابات
            updateUsesCalculationsOnly();
            
            // حفظ في localStorage
            localStorage.setItem('usesData', JSON.stringify(usesData));
            
            // مزامنة الأنظمة الأخرى
            if (field === 'percentage' || field === 'areaPerUnit' || field === 'units') {
                syncCostsWithUses();
                syncRevenuesWithUses();
                
                if (typeof fastParkingUpdate === 'function') {
                    fastParkingUpdate('تغيير حقل الاستخدام');
                } else if (typeof syncParkingWithUses === 'function') {
                    syncParkingWithUses();
                }
            }
            
            console.log(`✅ Debounced update completed for ${useId}.${subUnitId}.${field}`);
        }, 300); // 300ms delay
        
    } catch (error) {
        console.error('❌ Error in updateSubUnitDebounced:', error);
    }
}

/**
 * حساب إجمالي نسب الوحدات الفرعية
 * Calculate total sub-units percentage
 */
function calculateSubUnitsTotal(useId) {
    try {
        const use = usesData[useId];
        if (!use || !use.subUnits) return 0;
        
        return use.subUnits.reduce((total, subUnit) => {
            return total + (subUnit.percentage || 0);
        }, 0);
    } catch (error) {
        console.error('❌ Error calculating sub-units total:', error);
        return 0;
    }
}

