// ============================================================================
// 🚀 v11.0 ENHANCEMENT: Floors Repetition Validation System
// ============================================================================

/**
 * نظام التحقق من التكرارات المتداخلة في الأدوار
 * Nested Floors Repetition Validation System
 * 
 * يمنع إنشاء أعداد غير واقعية من الأدوار بسبب التكرارات المتداخلة
 * Prevents creating unrealistic floor counts due to nested repetitions
 */
const FloorsValidationSystem = {
    MAX_TOTAL_FLOORS: 50,
    MAX_SINGLE_REPEAT: 20,
    
    /**
     * حساب إجمالي الأدوار مع التكرارات
     * Calculate total floors with repetitions
     */
    calculateTotalFloorsWithRepetitions() {
        try {
            if (!window.floorsData || !Array.isArray(window.floorsData)) {
                return 0;
            }
            
            let totalFloors = 0;
            const warnings = [];
            
            window.floorsData.forEach((floor, index) => {
                if (floor.enabled === false) return; // تخطي الأدوار المعطلة
                
                let floorCount = floor.repeatCount || floor.repeat || 1; // ✅ استخدام repeatCount أولاً
                let multiplier = 1;
                
                // التحقق من التكرارات المتداخلة
                if (floor.reference === 'previousFloor' && index > 0) {
                    const previousFloor = window.floorsData[index - 1];
                    const previousRepeat = previousFloor.repeatCount || previousFloor.repeat || 1; // ✅ استخدام repeatCount أولاً
                    if (previousFloor && previousRepeat > 1) {
                        multiplier = previousRepeat;
                        floorCount *= multiplier;
                        
                        warnings.push({
                            floorNumber: floor.number,
                            previousFloorNumber: previousFloor.number,
                            message: `الدور "${floor.number}" يعتمد على دور متكرر "${previousFloor.number}" (${previousRepeat}×)`,
                            actualCount: floorCount
                        });
                    }
                }
                
                totalFloors += floorCount;
            });
            
            return {
                totalFloors,
                warnings,
                isValid: totalFloors <= this.MAX_TOTAL_FLOORS
            };
            
        } catch (error) {
            console.error('❌ Error calculating total floors:', error);
            return { totalFloors: 0, warnings: [], isValid: true };
        }
    },
    
    /**
     * التحقق من صحة التكرارات
     * Validate repetitions
     */
    validateRepetitions() {
        const result = this.calculateTotalFloorsWithRepetitions();
        
        // عرض التحذيرات
        if (result.warnings.length > 0) {
            console.warn('⚠️ تحذيرات التكرارات المتداخلة:', result.warnings);
        }
        
        // التحقق من الحد الأقصى
        if (!result.isValid) {
            showNotification(
                `⚠️ تحذير: إجمالي الأدوار (${result.totalFloors}) يتجاوز الحد الأقصى (${this.MAX_TOTAL_FLOORS})\n` +
                `قد يؤدي هذا إلى أرقام غير واقعية.`,
                'warning',
                6000
            );
            
            return false;
        }
        
        return true;
    },
    
    /**
     * التحقق من تكرار دور واحد
     * Validate single floor repeat
     */
    validateSingleRepeat(repeatCount) {
        if (repeatCount > this.MAX_SINGLE_REPEAT) {
            showNotification(
                `⚠️ تحذير: عدد التكرار (${repeatCount}) يتجاوز الحد الأقصى الموصى به (${this.MAX_SINGLE_REPEAT})`,
                'warning',
                4000
            );
            return false;
        }
        return true;
    },
    
    /**
     * عرض معاينة إجمالي الأدوار
     * Show total floors preview
     */
    showFloorsPreview() {
        const result = this.calculateTotalFloorsWithRepetitions();
        const previewElement = document.getElementById('floorsCountPreview');
        
        if (!previewElement) return;
        
        let statusClass = 'bg-blue-500/20 border-blue-400/30 text-blue-200';
        let icon = 'fa-building';
        let iconColor = 'text-blue-200';
        
        if (!result.isValid) {
            statusClass = 'bg-red-500/20 border-red-400/30 text-red-200';
            icon = 'fa-exclamation-triangle';
            iconColor = 'text-red-200';
        } else if (result.warnings.length > 0) {
            statusClass = 'bg-amber-500/20 border-amber-400/30 text-amber-200';
            icon = 'fa-exclamation-circle';
            iconColor = 'text-yellow-200';
        }
        
        let warningsHTML = '';
        if (result.warnings.length > 0) {
            warningsHTML = `
                <div class="mt-2 text-xs">
                    ${result.warnings.map(w => `
                        <div class="flex items-start gap-1 mb-1">
                            <i class="fas fa-info-circle mt-0.5"></i>
                            <span>${w.message}</span>
                        </div>
                    `).join('')}
                </div>
            `;
        }
        
        previewElement.innerHTML = `
            <div class="flex items-center gap-2 px-3 py-2 border rounded ${statusClass}">
                <i class="fas ${icon} ${iconColor}"></i>
                <span class="font-medium">
                    إجمالي الأدوار: <strong>${result.totalFloors}</strong>
                </span>
                ${result.totalFloors > this.MAX_TOTAL_FLOORS ? 
                    `<span class="text-xs">(يتجاوز الحد: ${this.MAX_TOTAL_FLOORS})</span>` : 
                    ''}
            </div>
            ${warningsHTML}
        `;
    },
    
    /**
     * تحديث تلقائي للمعاينة
     * Auto-update preview
     */
    enableAutoPreview() {
        // تحديث عند أي تغيير في floorsData
        const observer = new MutationObserver(() => {
            this.showFloorsPreview();
        });
        
        // مراقبة التغييرات في جدول الأدوار
        const floorsTable = document.getElementById('floorsTableBody');
        if (floorsTable) {
            observer.observe(floorsTable, {
                childList: true,
                subtree: true,
                attributes: true
            });
        }
    }
};

/**
 * دالة مساعدة للتحقق عند إضافة/تعديل دور
 * Helper function to validate when adding/editing floor
 */
function validateFloorBeforeSave(floorData) {
    // التحقق من عدد التكرار
    if (floorData.repeat && floorData.repeat > FloorsValidationSystem.MAX_SINGLE_REPEAT) {
        const confirmed = confirm(
            `عدد التكرار (${floorData.repeat}) يتجاوز الحد الموصى به (${FloorsValidationSystem.MAX_SINGLE_REPEAT}).\n\n` +
            `هل تريد المتابعة؟`
        );
        
        if (!confirmed) {
            return false;
        }
    }
    
    return true;
}

// تصدير للنطاق العام
if (typeof window !== 'undefined') {
    window.FloorsValidationSystem = FloorsValidationSystem;
    window.validateFloorBeforeSave = validateFloorBeforeSave;
}

