// Calculate feasibility
async function calculateFeasibility() {
    try {
        // Show loading state
        document.body.classList.add('loading')
        
        // Collect input data
        const formData = {
            projectName: document.getElementById('projectName').value,
            clientName: document.getElementById('clientName').value,
            city: document.getElementById('city').value,
            landArea: parseFloat(document.getElementById('landArea').value) || 0,
            far: parseFloat(document.getElementById('far').value) || 0,
            
            uses: {
                hotel: {
                    share: usesData.hotel.share,
                    efficiency: usesData.hotel.efficiency
                },
                retail: {
                    share: usesData.retail.share,
                    efficiency: usesData.retail.efficiency
                },
                office: {
                    share: usesData.office.share,
                    efficiency: usesData.office.efficiency
                },
                residential: {
                    share: usesData.residential.share,
                    efficiency: usesData.residential.efficiency
                }
            },
            
            costs: {
                hotel: {
                    finishes: 1800, // قيم افتراضية بدلاً من البيانات المحذوفة
                    mep: 800,
                    ffe: 1200
                },
                retail: {
                    finishes: 1500,
                    mep: 600,
                    ffe: 600
                },
                office: {
                    finishes: 1200,
                    mep: 500,
                    ffe: 500
                },
                residential: {
                    finishes: 1000,
                    mep: 400,
                    ffe: 400
                }
            },
            
            revenues: {
                hotel: {
                    rentPerSqm: parseFloat(document.getElementById('hotelRent').value) || 0,
                    occupancyRate: parseFloat(document.getElementById('hotelOccupancy').value) || 0,
                    salePrice: parseFloat(document.getElementById('hotelSalePrice').value) || 0
                },
                retail: {
                    rentPerSqm: parseFloat(document.getElementById('retailRent').value) || 0,
                    occupancyRate: parseFloat(document.getElementById('retailOccupancy').value) || 0,
                    salePrice: parseFloat(document.getElementById('retailSalePrice').value) || 0
                },
                office: {
                    rentPerSqm: parseFloat(document.getElementById('officeRent').value) || 0,
                    occupancyRate: parseFloat(document.getElementById('officeOccupancy').value) || 0,
                    salePrice: parseFloat(document.getElementById('officeSalePrice').value) || 0
                },
                residential: {
                    rentPerSqm: parseFloat(document.getElementById('residentialRent').value) || 0,
                    occupancyRate: parseFloat(document.getElementById('residentialOccupancy').value) || 0,
                    salePrice: parseFloat(document.getElementById('residentialSalePrice').value) || 0
                }
            },
            
            extraCosts: {
                projectManagement: costsData.projectManagement.costs.reduce((sum, c) => sum + (c.value || 0), 0),
                developerFees: costsData.developmentFees.costs.reduce((sum, c) => sum + (c.value || 0), 0),
                contingency: costsData.contingency.costs.reduce((sum, c) => sum + (c.value || 0), 0)
            },
            
            omDepreciation: {
                opexRate: parseFloat(document.getElementById('opexRate').value) || 0,
                depreciationRate: parseFloat(document.getElementById('depreciationRate').value) || 0
            }
        }
        
        // Send calculation request
        const response = await fetch('/api/calculate', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(formData)
        })
        
        if (!response.ok) {
            throw new Error('Calculation failed')
        }
        
        calculationResults = await response.json()
        displayResults()
        
    } catch (error) {
        console.error('Calculation error:', error)
        alert('حدث خطأ في الحساب. يرجى المحاولة مرة أخرى.')
    } finally {
        document.body.classList.remove('loading')
    }
}

// Display calculation results
function displayResults() {
    if (!calculationResults) return
    
    // Show results section
    document.getElementById('resultsSection').classList.remove('hidden')
    document.getElementById('noResultsMessage').classList.add('hidden')
    
    // Update key metrics
    document.getElementById('gfaValue').textContent = formatNumber(calculationResults.areas.gfa)
    document.getElementById('glaValue').textContent = formatNumber(calculationResults.areas.gla)
    document.getElementById('costValue').textContent = formatCurrency(calculationResults.costs.total)
    document.getElementById('yieldValue').textContent = calculationResults.financials.grossYield.toFixed(2) + '%'
    
    // Update detailed financial information
    updateFinancialDetails()
    updateAreasDetails()
    
    // Update charts
    updateGLAChart()
    updateCostChart()
}

