// Update GLA distribution chart
function updateGLAChart() {
    const ctx = document.getElementById('glaChart').getContext('2d')
    
    if (glaChart) {
        glaChart.destroy()
    }
    
    const useNames = {
        hotel: 'فندق',
        retail: 'تجاري', 
        office: 'مكاتب',
        residential: 'سكني'
    }
    
    const data = Object.keys(calculationResults.areas.useBreakdown).map(use => ({
        label: useNames[use] || use,
        value: calculationResults.areas.useBreakdown[use].gla
    })).filter(item => item.value > 0)
    
    // A) GLA Chart - تطبيق لوحة الألوان الموحدة
    const options = withArabicDefaults({
        plugins: { legend: { position: 'bottom' } }
    });

    const dataset = {
        data: data.map(item => item.value),
        backgroundColor: data.map((_, i) => USES_PALETTE[i % USES_PALETTE.length]),
        borderColor: '#fff',
        borderWidth: 2
    };

    glaChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: data.map(item => item.label),
            datasets: [dataset]
        },
        options
    })
}

