// Export timeline schedule to Excel
function exportTimeline() {
    try {
        console.log('📤 Exporting timeline to Excel...')
        
        // Check if timeline data exists
        if (!timelineData || !timelineData.phases || Object.keys(timelineData.phases).length === 0) {
            alert('لا توجد بيانات برنامج زمني للتصدير')
            return
        }
        
        // Create workbook and worksheets
        const workbook = XLSX.utils.book_new()
        
        // 1. Timeline Summary Worksheet
        const summaryData = []
        summaryData.push(['ملخص البرنامج الزمني'])
        summaryData.push([''])
        summaryData.push(['إجمالي المراحل', Object.keys(timelineData.phases).length])
        
        // Count total activities
        let totalActivities = 0
        Object.values(timelineData.phases).forEach(phase => {
            totalActivities += phase.activities ? phase.activities.length : 0
        })
        summaryData.push(['إجمالي الأنشطة', totalActivities])
        
        // Calculate project duration
        let maxEndMonth = 0
        Object.values(timelineData.phases).forEach(phase => {
            if (phase.activities) {
                phase.activities.forEach(activity => {
                    const endMonth = activity.startMonth + activity.duration
                    if (endMonth > maxEndMonth) maxEndMonth = endMonth
                })
            }
        })
        summaryData.push(['مدة المشروع (شهر)', maxEndMonth.toFixed(1)])
        summaryData.push(['تاريخ التصدير', new Date().toLocaleDateString('en-US')])
        
        const summarySheet = XLSX.utils.aoa_to_sheet(summaryData)
        XLSX.utils.book_append_sheet(workbook, summarySheet, 'ملخص البرنامج')
        
        // 2. Detailed Activities Worksheet
        const activitiesData = []
        activitiesData.push(['المرحلة', 'النشاط', 'بداية الشهر', 'المدة (شهر)', 'نهاية الشهر', 'نسبة الإنجاز (%)', 'حرج'])
        
        Object.entries(timelineData.phases).forEach(([phaseId, phase]) => {
            if (phase.activities) {
                phase.activities.forEach(activity => {
                    const endMonth = activity.startMonth + activity.duration
                    // const cost = activity.cost || 0 // Cost removed from activities export
                    const isCritical = activity.isCritical || activity.duration >= 6 ? 'نعم' : 'لا'
                    
                    activitiesData.push([
                        phase.name,
                        activity.name,
                        activity.startMonth.toFixed(1),
                        activity.duration.toFixed(1),
                        endMonth.toFixed(1),
                        activity.progress.toFixed(1),
                        isCritical
                    ])
                })
            }
        })
        
        const activitiesSheet = XLSX.utils.aoa_to_sheet(activitiesData)
        
        // Auto-fit columns
        const maxColWidths = [20, 30, 15, 15, 15, 15, 20, 10]
        activitiesSheet['!cols'] = maxColWidths.map(width => ({ wch: width }))
        
        XLSX.utils.book_append_sheet(workbook, activitiesSheet, 'تفاصيل الأنشطة')
        
        // 3. Cost Analysis Worksheet
        const costsData = []
        costsData.push(['تحليل التكاليف'])
        costsData.push([''])
        costsData.push(['المرحلة', 'إجمالي التكلفة (ريال)', 'عدد الأنشطة', 'متوسط التكلفة (ريال)'])
        
        let totalProjectCost = 0
        Object.entries(timelineData.phases).forEach(([phaseId, phase]) => {
            let phaseCost = 0
            let activityCount = 0
            
            if (phase.activities) {
                phase.activities.forEach(activity => {
                    phaseCost += activity.cost || 0
                    activityCount++
                })
            }
            
            totalProjectCost += phaseCost
            const avgCost = activityCount > 0 ? phaseCost / activityCount : 0
            
            costsData.push([
                phase.name,
                phaseCost.toLocaleString('en-US'),
                activityCount,
                avgCost.toLocaleString('en-US')
            ])
        })
        
        costsData.push([''])
        costsData.push(['إجمالي تكلفة المشروع', totalProjectCost.toLocaleString('en-US'), '', ''])
        
        const costsSheet = XLSX.utils.aoa_to_sheet(costsData)
        costsSheet['!cols'] = [{ wch: 25 }, { wch: 20 }, { wch: 15 }, { wch: 20 }]
        XLSX.utils.book_append_sheet(workbook, costsSheet, 'تحليل التكاليف')
        
        // Cash flow projection removed with timeline system
        
        // Generate filename with current date
        const today = new Date()
        const dateStr = today.toISOString().slice(0, 10)
        const filename = `البرنامج-الزمني-${dateStr}.xlsx`
        
        // Save the file
        XLSX.writeFile(workbook, filename)
        
        console.log('✅ Timeline exported to Excel successfully')
        alert('تم تصدير البرنامج الزمني إلى Excel بنجاح')
        
    } catch (error) {
        console.error('❌ Error exporting timeline to Excel:', error)
        alert('حدث خطأ أثناء تصدير البرنامج الزمني')
    }
}

