// Toggle use expansion
function toggleUseExpansion(useId) {
    usesData[useId].expanded = !usesData[useId].expanded
    syncAllSystems()
}



// Update use share
// تم حذف دوال updateUseShare و updateUseEfficiency
// لأن النسبة والكفاءة الآن محسوبة تلقائياً من جدول الأدوار فقط

// Update sub unit - استخدام النسخة المحسّنة مع debouncing
// Update sub unit - using enhanced version with debouncing
function updateSubUnit(useId, subUnitId, field, value) {
    // استخدام الدالة المحسّنة مع debouncing
    if (typeof updateSubUnitDebounced === 'function') {
        updateSubUnitDebounced(useId, subUnitId, field, value);
    } else {
        // Fallback للنسخة القديمة
        try {
            const subUnit = usesData[useId].subUnits.find(sub => sub.id === subUnitId)
            if (subUnit) {
                if (field === 'name') {
                    subUnit[field] = value
                } else {
                    subUnit[field] = parseFloat(value) || 0
                }
                
                if (field === 'percentage') {
                    validateSubUnitsTotal(useId)
                    updateUsesCalculationsOnly()
                } else {
                    updateUsesCalculations()
                    renderUsesSystem()
                }
                
                if (field === 'percentage' || field === 'areaPerUnit' || field === 'units') {
                    syncCostsWithUses()
                    renderCostsSystem()
                    syncRevenuesWithUses()
                    renderRevenuesSystem()
                    
                    if (typeof fastParkingUpdate === 'function') {
                        fastParkingUpdate('تغيير حقل الاستخدام')
                    } else if (typeof syncParkingWithUses === 'function') {
                        syncParkingWithUses()
                    }
                    
                    renderTimelineSystem()
                }
                
                console.log(`✅ Updated ${useId} subUnit ${subUnitId}: ${field} = ${value}`)
            }
        } catch (error) {
            console.error('❌ Error updating sub unit:', error)
        }
    }
}

// Add sub unit
function addSubUnit(useId) {
    try {
        const newId = `${useId}_${Date.now()}`
        const newSubUnit = {
            id: newId,
            name: "وحدة جديدة",
            percentage: 0,
            efficiency: 80,
            areaPerUnit: 100,
            units: 0
        }
        
        usesData[useId].subUnits.push(newSubUnit)
        
        // Update calculations
        updateUsesCalculations()
        renderUsesSystem()
        
        // Update costs and revenues systems
        console.log('🔄 Updating costs and revenues due to new sub-unit')
        syncCostsWithUses()
        renderCostsSystem()
        syncRevenuesWithUses()
        renderRevenuesSystem()
        
        // Fast update parking system for new sub-unit
        if (typeof fastParkingUpdate === 'function') {
            fastParkingUpdate('إضافة وحدة فرعية جديدة')
        } else if (typeof syncParkingWithUses === 'function') {
            syncParkingWithUses()
        }
        
        console.log(`✅ Added new sub-unit to ${useId}: ${newId}`)
    } catch (error) {
        console.error('❌ Error adding sub unit:', error)
    }
}

// Delete sub unit
function deleteSubUnit(useId, subUnitId) {
    if (confirm("هل أنت متأكد من حذف هذه الوحدة؟")) {
        try {
            usesData[useId].subUnits = usesData[useId].subUnits.filter(sub => sub.id !== subUnitId)
            
            // Update calculations
            updateUsesCalculations()
            renderUsesSystem()
            
            // Update costs and revenues systems
            console.log('🔄 Updating costs and revenues due to sub-unit deletion')
            syncCostsWithUses()
            renderCostsSystem()
            syncRevenuesWithUses()
            renderRevenuesSystem()
            
            // Fast update parking system for sub-unit deletion
            if (typeof fastParkingUpdate === 'function') {
                fastParkingUpdate('حذف وحدة فرعية')
            } else if (typeof syncParkingWithUses === 'function') {
                syncParkingWithUses()
            }
            
            console.log(`✅ Deleted sub-unit from ${useId}: ${subUnitId}`)
        } catch (error) {
            console.error('❌ Error deleting sub unit:', error)
        }
    }
}



// Update share warning
function updateShareWarning() {
    // ⚠️ استثناء الخدمات من حساب إجمالي النسب
    const totalShare = Object.values(usesData)
        .filter(use => use.id !== 'services')
        .reduce((sum, use) => sum + use.share, 0)
    const shareWarning = document.getElementById('shareWarning')
    const shareWarningText = document.getElementById('shareWarningText')
    
    if (shareWarning && shareWarningText) {
        if (Math.abs(totalShare - 100) > 0.1) {
            shareWarning.classList.remove('hidden')
            shareWarningText.innerHTML = `
                تحذير: إجمالي نسب الاستخدامات = <strong>${totalShare.toFixed(1)}%</strong>
                ${totalShare > 100 ? " (يتجاوز 100%)" : " (أقل من 100%)"}
            `
        } else {
            shareWarning.classList.add('hidden')
        }
    }
}

