// Calculate enhanced uses breakdown using new calculation system
function calculateEnhancedUsesBreakdown() {
    const breakdown = {
        useTypes: {},
        totals: {
            gfa: 0,
            gla: 0,
            units: 0,
            share: 0,
            efficiency: 0
        },
        analytics: {
            averageUnitSize: 0,
            densityPerHectare: 0,
            utilizationRatio: 0,
            diversityIndex: 0,
            efficiencyScore: 0
        }
    }
    
    try {
        // Get project data
        const landArea = getProjectLandArea()
        const far = getProjectFAR()
        const totalGFA = landArea * far
        console.log(`📊 [updateUsesSummary] landArea=${landArea}, far=${far}, totalGFA=${totalGFA}`)
        
        // Process each use type
        Object.values(usesData).forEach(use => {
            if (use.share > 0) {
                const useAnalysis = analyzeUseTypeDetails(use, totalGFA)
                breakdown.useTypes[use.id] = {
                    id: use.id,
                    name: use.name,
                    nameEn: use.nameEn || use.name,
                    icon: use.icon || '🏢',
                    color: use.color || 'blue',
                    share: use.share,
                    totalGFA: useAnalysis.totalGFA,
                    totalGLA: useAnalysis.totalGLA,
                    totalUnits: useAnalysis.totalUnits,
                    efficiency: useAnalysis.efficiency,
                    averageUnitSize: useAnalysis.averageUnitSize,
                    subUnitsCount: useAnalysis.subUnitsCount,
                    density: useAnalysis.density,
                    isPrimary: use.share >= 20 // Consider primary if >= 20%
                }
                
                // Add to totals
                breakdown.totals.gfa += useAnalysis.totalGFA
                breakdown.totals.gla += useAnalysis.totalGLA
                breakdown.totals.units += useAnalysis.totalUnits
                breakdown.totals.share += use.share
            }
        })
        
        // Calculate analytics
        breakdown.analytics.averageUnitSize = breakdown.totals.units > 0 ? breakdown.totals.gla / breakdown.totals.units : 0
        breakdown.analytics.densityPerHectare = landArea > 0 ? (breakdown.totals.units * 10000) / landArea : 0 // units per hectare
        breakdown.analytics.utilizationRatio = totalGFA > 0 ? (breakdown.totals.gla / totalGFA) * 100 : 0
        breakdown.analytics.diversityIndex = calculateUseDiversityIndex()
        breakdown.analytics.efficiencyScore = calculateOverallEfficiency()
        
        return breakdown
        
    } catch (error) {
        console.error('❌ Error calculating enhanced uses breakdown:', error)
        return breakdown
    }
}

// Analyze details for a specific use type
function analyzeUseTypeDetails(use, totalGFA) {
    const analysis = {
        totalGFA: 0,
        totalGLA: 0,
        totalUnits: 0,
        efficiency: use.efficiency || 85,
        averageUnitSize: 0,
        subUnitsCount: 0,
        density: 0
    }
    
    try {
        // Calculate GFA based on share
        analysis.totalGFA = totalGFA * (use.share / 100)
        
        // Calculate GLA based on efficiency
        analysis.totalGLA = analysis.totalGFA * (analysis.efficiency / 100)
        
        // Process sub-units
        if (use.subUnits && Array.isArray(use.subUnits)) {
            analysis.subUnitsCount = use.subUnits.filter(sub => sub.percentage > 0).length
            
            use.subUnits.forEach(subUnit => {
                if (subUnit.percentage > 0) {
                    const subGLA = analysis.totalGLA * (subUnit.percentage / 100)
                    const subUnits = subUnit.areaPerUnit > 0 ? Math.floor(subGLA / subUnit.areaPerUnit) : subUnit.units || 0
                    analysis.totalUnits += subUnits
                }
            })
        }
        
        analysis.averageUnitSize = analysis.totalUnits > 0 ? analysis.totalGLA / analysis.totalUnits : 0
        
        // Calculate density (units per 1000 sqm of GFA)
        analysis.density = analysis.totalGFA > 0 ? (analysis.totalUnits * 1000) / analysis.totalGFA : 0
        
    } catch (error) {
        console.error(`❌ Error analyzing use type ${use.id}:`, error)
    }
    
    return analysis
}

// Calculate use diversity index (Shannon diversity)
function calculateUseDiversityIndex() {
    try {
        // ⚠️ استثناء الخدمات من حساب التنوع
        const activeUses = Object.values(usesData)
            .filter(use => use.id !== 'services' && use.share > 0)
        const totalShare = activeUses.reduce((sum, use) => sum + use.share, 0)
        
        if (totalShare === 0 || activeUses.length === 0) return 0
        
        let diversityIndex = 0
        activeUses.forEach(use => {
            const proportion = use.share / totalShare
            if (proportion > 0) {
                diversityIndex -= proportion * Math.log(proportion)
            }
        })
        
        // Normalize to 0-100 scale (max diversity for 4 uses = ln(4) ≈ 1.386)
        const maxDiversity = Math.log(Math.min(activeUses.length, 4))
        return maxDiversity > 0 ? (diversityIndex / maxDiversity) * 100 : 0
        
    } catch (error) {
        console.error('❌ Error calculating diversity index:', error)
        return 0
    }
}

// Calculate overall efficiency score
function calculateOverallEfficiency() {
    try {
        // ⚠️ استثناء الخدمات من حساب الكفاءة الإجمالية
        const activeUses = Object.values(usesData)
            .filter(use => use.id !== 'services' && use.share > 0)
        if (activeUses.length === 0) return 0
        
        let weightedEfficiency = 0
        let totalWeight = 0
        
        activeUses.forEach(use => {
            const efficiency = use.efficiency || 85
            const weight = use.share / 100
            weightedEfficiency += efficiency * weight
            totalWeight += weight
        })
        
        return totalWeight > 0 ? weightedEfficiency / totalWeight : 0
        
    } catch (error) {
        console.error('❌ Error calculating efficiency score:', error)
        return 0
    }
}

// Generate enhanced uses analytics and insights
