// Get active uses (with sub-units having percentage > 0)
function getActiveUses() {
    const activeUses = []
    
    Object.entries(usesData).forEach(([useType, useData]) => {
        // ✅ CRITICAL FIX: Check main share first (this is the primary activation criteria)
        if (useData.share && useData.share > 0) {
            // If main share > 0, the use type is active regardless of sub-unit percentages
            activeUses.push(useType)
            console.log(`🎯 Active use type found: ${useType} (${useData.name}) - share: ${useData.share}%`)
        }
        // Secondary check: if no main share but has active sub-units
        else if (useData.subUnits && Array.isArray(useData.subUnits)) {
            const hasActiveSubUnits = useData.subUnits.some(subUnit => 
                subUnit.percentage && subUnit.percentage > 0
            )
            
            if (hasActiveSubUnits) {
                activeUses.push(useType)
                console.log(`🎯 Active use type found via subUnits: ${useType} (${useData.name})`)
            }
        }
        // Fallback: check legacy percentage field if available
        else if (useData.percentage && useData.percentage > 0) {
            activeUses.push(useType)
            console.log(`🎯 Active use type found via percentage: ${useType} (${useData.name}) - percentage: ${useData.percentage}%`)
        }
    })
    
    console.log(`🏢 Total active uses found: ${activeUses.length} - [${activeUses.join(', ')}]`)
    return activeUses
}

