// Get unit based on calculation type
function getCalculationTypeUnit(calculationType) {
    switch(calculationType) {
        case COST_CALCULATION_TYPES.FIXED_AMOUNT:
            return 'ريال'
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION:
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL:
            return '%'
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE:
            return 'ريال/م²'
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA:
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA:
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_LAND:
            return 'ريال/م²'
        case COST_CALCULATION_TYPES.PER_UNIT:
            return 'ريال/وحدة'
        default:
            return 'ريال'
    }
}

// Update cost item field directly in table
function updateCostItemField(categoryId, costId, field, value) {
    if (!costsData[categoryId]) return
    
    const costItem = costsData[categoryId].costs.find(c => c.id === costId)
    if (!costItem) return
    
    // Update the field
    costItem[field] = value
    
    // If updating calculation type, update unit display and recalculate
    if (field === 'calculationType') {
        costItem.unit = getCalculationTypeUnit(value)
        
        // Log the data sources being used
        console.log(`🔄 Updating calculation type for "${costItem.name}" to: ${value}`)
        logSystemDataSources()
        
        // IMMEDIATE UPDATE: Calculate and update the new value instantly
        const newCalculatedValue = calculateCostItemValue(costItem)
        console.log(`🧮 New calculated value after type change: ${(newCalculatedValue || 0).toLocaleString('en-US')}`)
        
        // Find the row for this cost item and update use type dropdown state
        const dropdownRows = document.querySelectorAll(`#expanded-cost-${categoryId} tr`)
        dropdownRows.forEach(row => {
            const nameInput = row.querySelector('input[type="text"]')
            if (nameInput && nameInput.value === costItem.name) {
                const useTypeSelect = row.querySelector('select[onchange*="useType"]')
                if (useTypeSelect) {
                    const isUseTypeCalculation = value === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE
                    if (isUseTypeCalculation) {
                        useTypeSelect.disabled = false
                        useTypeSelect.style.opacity = '1'
                        useTypeSelect.style.cursor = 'pointer'
                    } else {
                        useTypeSelect.disabled = true
                        useTypeSelect.style.opacity = '0.5'
                        useTypeSelect.style.cursor = 'not-allowed'
                        costItem.useType = '' // Clear use type when not needed
                        useTypeSelect.value = ''
                    }
                }
                
                // Update the unit display in the table (6th column due to use type column)
                const unitSpan = row.querySelector('td:nth-child(6)')
                if (unitSpan) {
                    unitSpan.textContent = costItem.unit
                }
            }
        })
        
        // Recalculate and update displayed value with proper system integration
        const calculatedValue = calculateCostItemValue(costItem)
        // Update calculated value in the correct column (7th column)
        const valueRows = document.querySelectorAll(`#expanded-cost-${categoryId} tr`)
        valueRows.forEach(row => {
            const nameInput = row.querySelector('input[type="text"]')
            if (nameInput && nameInput.value === costItem.name) {
                const valueSpan = row.querySelector('td:nth-child(7)')
                if (valueSpan) {
                    valueSpan.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
                }
            }
        })
        
        // Show calculation details in console
        showCalculationDetails(costItem, calculatedValue)
    }
    
    // If updating value, also recalculate
    if (field === 'value' || field === 'cost') {
        const calculatedValue = calculateCostItemValue(costItem)
        // Update calculated value in the correct column (7th column)
        const updateRows = document.querySelectorAll(`#expanded-cost-${categoryId} tr`)
        updateRows.forEach(row => {
            const nameInput = row.querySelector('input[type="text"]')
            if (nameInput && nameInput.value === costItem.name) {
                const valueSpan = row.querySelector('td:nth-child(7)')
                if (valueSpan) {
                    valueSpan.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
                }
            }
        })
    }
    
    // Update calculations and summaries
    console.log('🔄 [updateCostItemField] Calling updateCostsSummary for general costs update...')
    console.log('🔄 [updateCostItemField] Category:', categoryId, 'Cost:', costId, 'Field:', field, 'Value:', value)
    try {
        updateCostsSummary()
        console.log('✅ [updateCostItemField] updateCostsSummary completed for general costs')
    } catch (error) {
        console.error('❌ [updateCostItemField] Error in updateCostsSummary:', error)
    }
    
    // SMART FIX: Update calculated values dynamically (same as contingency)
    updateAllCalculatedValuesInCurrentView()
    
    // SPECIAL FIX: Update category total display immediately (unified interface)
    const categoryTotalElement = document.getElementById(`categoryTotal-${categoryId}`)
    if (categoryTotalElement) {
        let newTotal = 0
        if (categoryId === 'generalCosts') {
            newTotal = calculateGeneralCostsTotal()
        } else {
            // For all other categories, calculate using the unified function
            newTotal = calculateCustomCategoryTotal(costsData[categoryId])
        }
        categoryTotalElement.textContent = `${(newTotal || 0).toLocaleString('en-US')} ريال`
        console.log(`💰 [updateCostItemField] Updated category total for ${categoryId}: ${(newTotal || 0).toLocaleString('en-US')} ريال`)
    } else {
        console.warn(`⚠️ Category total element not found for ${categoryId}`)
    }
    
    // LEGACY FIX: Keep the old general costs total for backward compatibility
    if (categoryId === 'generalCosts') {
        const generalTotalElement = document.getElementById('generalCostsTotalDisplay')
        if (generalTotalElement) {
            const newTotal = calculateGeneralCostsTotal()
            generalTotalElement.textContent = `${(newTotal || 0).toLocaleString('en-US')} ريال`
        }
    }
    
    console.log('✅ Cost item updated with preserved inputs and updated calculations')
    
    console.log(`✅ Updated ${field} for cost item ${costId}:`, value)
}

// Smart update: Update only calculated values without re-rendering tables
function updateCalculatedValueInTable(categoryId, costId) {
    try {
        const costItem = costsData[categoryId]?.costs?.find(c => c.id === costId)
        if (!costItem) return
        
        // Calculate the new value
        const calculatedValue = calculateCostItemValue(costItem)
        console.log(`🧮 Calculated value for "${costItem.name}": ${(calculatedValue || 0).toLocaleString('en-US')}`)
        
        // Find and update the calculated value cell
        const tableRows = document.querySelectorAll(`#expanded-cost-${categoryId} tr, .cost-table-row`)
        tableRows.forEach(row => {
            const nameInput = row.querySelector('input[type="text"]')
            if (nameInput && nameInput.value === costItem.name) {
                // Find the calculated value column (usually last or second to last)
                const calculatedValueCell = row.querySelector('td:nth-last-child(2)')
                if (calculatedValueCell) {
                    calculatedValueCell.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
                    console.log(`✅ Updated calculated value display for "${costItem.name}"`)
                }
            }
        })
        
        // Also try alternative selectors for different table structures
        const allRows = document.querySelectorAll('tr')
        allRows.forEach(row => {
            const cells = row.querySelectorAll('td')
            if (cells.length > 0) {
                const nameCell = cells[0]?.querySelector('input[type="text"]')
                if (nameCell && nameCell.value === costItem.name) {
                    // Look for calculated value column (typically 7th column)
                    const calculatedCell = cells[6] || cells[cells.length - 2]
                    if (calculatedCell) {
                        calculatedCell.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
                    }
                }
            }
        })
        
    } catch (error) {
        console.error('❌ Error updating calculated value in table:', error)
    }
}

// Log system data sources for debugging
function logSystemDataSources() {
    console.log(`📊 System Data Sources:`)
    
    // Land area from project settings
    const landArea = parseFloat(document.getElementById('landArea')?.value) || 0
    console.log(`🏗️ Land Area (Project Settings): ${landArea.toLocaleString('en-US')} m²`)
    
    // GFA from floors or calculation
    const gfa = calculateTotalGFA()
    console.log(`🏗️ Total GFA (Floors System): ${gfa.toLocaleString('en-US')} m²`)
    
    // GLA from uses system
    const gla = calculateTotalGLA()
    console.log(`🏗️ Total GLA (Uses System): ${gla.toLocaleString('en-US')} m²`)
    
    // Units from uses system
    const units = calculateTotalUnits()
    console.log(`🏗️ Total Units (Uses System): ${units.toLocaleString('en-US')} units`)
    
    // Construction cost from cost system
    const constructionCost = calculateTotalConstructionCost()
    console.log(`💰 Construction Cost (Cost System): ${constructionCost.toLocaleString('en-US')} SAR`)
    
    // Total project cost from cost system
    const totalCost = calculateTotalProjectCostForPercentage()
    console.log(`💰 Total Project Cost (Cost System): ${totalCost.toLocaleString('en-US')} SAR`)
}

// Show calculation details for specific cost item
function showCalculationDetails(costItem, calculatedValue) {
    console.log(`🧮 Calculation Details for "${costItem.name}":`)
    console.log(`   Type: ${costItem.calculationType}`)
    console.log(`   Input Value: ${costItem.value}`)
    console.log(`   Calculated Result: ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
    
    switch (costItem.calculationType) {
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION:
            const constructionCost = calculateTotalConstructionCost()
            console.log(`   Formula: ${costItem.value}% × ${constructionCost.toLocaleString('en-US')} SAR = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        case COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL:
            const totalCost = calculateTotalProjectCostForPercentage()
            console.log(`   Formula: ${costItem.value}% × ${totalCost.toLocaleString('en-US')} SAR = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA:
            const gfa = calculateTotalGFA()
            console.log(`   Formula: ${costItem.value} SAR/m² × ${gfa.toLocaleString('en-US')} m² = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_GLA:
            const gla = calculateTotalGLA()
            console.log(`   Formula: ${costItem.value} SAR/m² × ${gla.toLocaleString('en-US')} m² = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        case COST_CALCULATION_TYPES.PER_SQUARE_METER_LAND:
            const landArea = parseFloat(document.getElementById('landArea')?.value) || 0
            console.log(`   Formula: ${costItem.value} SAR/m² × ${landArea.toLocaleString('en-US')} m² = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        case COST_CALCULATION_TYPES.PER_UNIT:
            const units = calculateTotalUnits()
            console.log(`   Formula: ${costItem.value} SAR/unit × ${units.toLocaleString('en-US')} units = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
        default:
            console.log(`   Formula: Fixed amount = ${(calculatedValue || 0).toLocaleString('en-US')} SAR`)
            break
    }
}

// Delete cost item directly from table
function deleteCostItemDirect(categoryId, costId) {
    if (!costsData[categoryId]) return
    
    const costItem = costsData[categoryId].costs.find(c => c.id === costId)
    if (!costItem) return
    
    // Confirm deletion
    if (!confirm(`هل أنت متأكد من حذف البند "${costItem.name}"؟`)) {
        return
    }
    
    // Remove the cost item
    costsData[categoryId].costs = costsData[categoryId].costs.filter(c => c.id !== costId)
    
    // Re-render the costs system
    renderCostsSystem()
    
    console.log(`✅ Deleted cost item: ${costItem.name}`)
}

// Add new cost item directly from table
function addNewCostItemDirect(categoryId) {
    const nameInput = document.getElementById(`new-cost-name-${categoryId}`)
    const descriptionInput = document.getElementById(`new-cost-description-${categoryId}`)
    const typeSelect = document.getElementById(`new-cost-type-${categoryId}`)
    const useTypeSelect = document.getElementById(`new-cost-use-type-${categoryId}`)
    const valueInput = document.getElementById(`new-cost-value-${categoryId}`)
    
    if (!nameInput || !nameInput.value.trim()) {
        alert('يرجى إدخال اسم البند')
        nameInput?.focus()
        return
    }
    
    const calculationType = typeSelect?.value || COST_CALCULATION_TYPES.FIXED_AMOUNT
    
    // Check if use type is required but not selected
    if (calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE && !useTypeSelect?.value) {
        alert('يرجى اختيار نوع الاستخدام')
        useTypeSelect?.focus()
        return
    }
    
    // Create new cost item
    const newCostItem = {
        id: generateUniqueId(),
        name: nameInput.value.trim(),
        description: descriptionInput?.value.trim() || '',
        calculationType: calculationType,
        useType: (calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) ? useTypeSelect?.value : '',
        value: parseFloat(valueInput?.value) || 0,
        cost: parseFloat(valueInput?.value) || 0, // For backward compatibility
        unit: getCalculationTypeUnit(calculationType),
        isCustom: true
    }
    
    // Add to category
    if (!costsData[categoryId].costs) {
        costsData[categoryId].costs = []
    }
    
    costsData[categoryId].costs.push(newCostItem)
    
    // Re-render the costs system
    renderCostsSystem()
    
    console.log(`✅ Added new cost item: ${newCostItem.name}`)
}

/**
 * إنشاء خيارات أنواع الاستخدام ديناميكياً من بيانات الاستخدامات
 */
function createUseTypeOptions(selectedValue = '') {
    console.log('🏗️ إنشاء خيارات القائمة المنسدلة...')
    console.log('📊 عدد الاستخدامات المتاحة:', Object.keys(usesData).length)
    console.log('🎯 القيمة المحددة:', selectedValue)
    
    let options = '<option value="">اختر الاستخدام</option>'
    
    // جمع جميع أنواع الاستخدام من usesData
    Object.entries(usesData).forEach(([useId, useData]) => {
        const isSelected = selectedValue === useId ? 'selected' : ''
        options += `<option value="${useId}" ${isSelected}>${useData.name}</option>`
        console.log(`   ➕ إضافة خيار: ${useId} - ${useData.name}`)
    })
    
    console.log('✅ تم إنشاء الخيارات بنجاح، العدد الإجمالي:', Object.keys(usesData).length + 1)
    return options
}

/**
 * تحديث جميع القوائم المنسدلة لأنواع الاستخدام في نظام التكاليف
 */
function updateAllUseTypeDropdowns() {
    console.log('🔄 تحديث جميع القوائم المنسدلة لأنواع الاستخدام في التكاليف...')
    console.log('📊 البيانات المتاحة في usesData:', Object.keys(usesData))
    
    // البحث عن جميع القوائم المنسدلة لأنواع الاستخدام
    const dropdownSelectors = [
        'select[id*="use-type"]',
        'select[id*="useType"]',
        'select[name*="useType"]',
        'select.use-type-dropdown'
    ]
    
    let updatedCount = 0
    
    dropdownSelectors.forEach(selector => {
        document.querySelectorAll(selector).forEach(select => {
            const currentValue = select.value
            const oldHTML = select.innerHTML
            select.innerHTML = createUseTypeOptions(currentValue)
            
            console.log(`📋 تم تحديث القائمة: ${select.id || select.name || 'no-id'} - القيمة المحددة: ${currentValue}`)
            console.log(`   القائمة القديمة: ${oldHTML.substring(0, 100)}...`)
            console.log(`   القائمة الجديدة: ${select.innerHTML.substring(0, 100)}...`)
            updatedCount++
        })
    })
    
    console.log(`✅ تم تحديث ${updatedCount} قائمة منسدلة لأنواع الاستخدام`)
    
    if (updatedCount === 0) {
        console.warn('⚠️ لم يتم العثور على أي قوائم منسدلة للتحديث!')
        console.log('🔍 جميع عناصر select في الصفحة:', document.querySelectorAll('select').length)
        
        // تشخيص إضافي
        console.log('🔍 فحص تفصيلي لعناصر select:')
        document.querySelectorAll('select').forEach((select, index) => {
            console.log(`  ${index + 1}. ID: ${select.id}, Name: ${select.name}, Classes: ${select.className}`)
        })
    }
}

/**
 * حساب إجمالي التكاليف لكل استخدام من جميع أقسام التكاليف
 */
function calculateCostsByUseType() {
    console.log('🧮 حساب إجمالي التكاليف حسب الاستخدام...')
    
    const costsByUse = {}
    
    // تهيئة البيانات لكل استخدام (حتى لو كان share = 0 أو GLA غير مفعّل)
    Object.keys(usesData).forEach(useId => {
        const useData = usesData[useId];
        // ✅ استخدام totalGFA مباشرة بدلاً من calculateTotalAreaForUse
        const totalArea = useData.totalGFA || 0;
        const totalUnits = useData.totalUnits || 0;
        
        // تخطي الاستخدامات التي ليس لها مساحة أو وحدات
        if (totalArea > 0 || totalUnits > 0) {
            
            costsByUse[useId] = {
                id: useId,
                name: useData.name || useId,
                color: useData.color || 'blue',
                icon: useData.icon || '🏢',
                share: useData.share || 0,
                total: 0,
                area: totalArea,
                units: totalUnits,
                costPerSqm: 0,
                costPerUnit: 0,
                breakdown: {},
                countInGLA: useData.countInGLA !== false  // تتبع حالة GLA
            };
            
            console.log(`📊 [${useData.name}] تهيئة التكاليف: GFA=${totalArea.toLocaleString('en-US')} م², Units=${totalUnits}, countInGLA=${useData.countInGLA}`);
        }
    })
    
    // جمع التكاليف من جميع الأقسام
    Object.values(costsData).forEach(category => {
        if (category.id === 'usageBasedCosts') return // تخطي القسم المحذوف
        
        console.log(`📋 معالجة قسم: ${category.name}`)
        
        // معالجة البنود العامة
        if (category.costs) {
            category.costs.forEach(cost => {
                if (cost.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE && cost.useType) {
                    if (costsByUse[cost.useType]) {
                        const calculatedValue = calculateCostItemValue(cost)
                        costsByUse[cost.useType].total += calculatedValue
                        costsByUse[cost.useType].breakdown[cost.name] = calculatedValue
                        console.log(`  💰 ${cost.name} للاستخدام ${cost.useType}: ${calculatedValue.toLocaleString('en-US')} ريال`)
                    }
                }
            })
        }
        
        // معالجة مراحل التكاليف
        if (category.phases) {
            Object.values(category.phases).forEach(phase => {
                if (phase.activities) {
                    phase.activities.forEach(activity => {
                        if (activity.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE && activity.useType) {
                            if (costsByUse[activity.useType]) {
                                const calculatedValue = calculateCostItemValue(activity)
                                costsByUse[activity.useType].total += calculatedValue
                                costsByUse[activity.useType].breakdown[activity.name] = calculatedValue
                                console.log(`  💰 ${activity.name} للاستخدام ${activity.useType}: ${calculatedValue.toLocaleString('en-US')} ريال`)
                            }
                        }
                    })
                }
            })
        }
        
        // معالجة التراخيص والرخص
        if (category.permits) {
            category.permits.forEach(permit => {
                if (permit.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE && permit.useType) {
                    if (costsByUse[permit.useType]) {
                        const calculatedValue = calculateCostItemValue(permit)
                        costsByUse[permit.useType].total += calculatedValue
                        costsByUse[permit.useType].breakdown[permit.name] = calculatedValue
                        console.log(`  💰 ${permit.name} للاستخدام ${permit.useType}: ${calculatedValue.toLocaleString('en-US')} ريال`)
                    }
                }
            })
        }
    })
    
    // حساب التكلفة لكل متر مربع ولكل وحدة
    Object.keys(costsByUse).forEach(useId => {
        const use = costsByUse[useId]
        use.costPerSqm = use.area > 0 ? use.total / use.area : 0
        use.costPerUnit = use.units > 0 ? use.total / use.units : 0
    })
    
    console.log('✅ تم حساب إجمالي التكاليف حسب الاستخدام:', costsByUse)
    return costsByUse
}

