// Toggle use type dropdown for new items
function toggleNewItemUseType(categoryId, calculationType) {
    const useTypeSelect = document.getElementById(`new-cost-use-type-${categoryId}`)
    const unitSpan = document.getElementById(`new-cost-unit-${categoryId}`)
    
    if (useTypeSelect && unitSpan) {
        const isUseTypeCalculation = calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE
        
        if (isUseTypeCalculation) {
            useTypeSelect.disabled = false
            useTypeSelect.style.opacity = '1'
            useTypeSelect.style.cursor = 'pointer'
            // تحديث الخيارات عند تفعيل القائمة
            useTypeSelect.innerHTML = createUseTypeOptions(useTypeSelect.value)
        } else {
            useTypeSelect.disabled = true
            useTypeSelect.style.opacity = '0.5'
            useTypeSelect.style.cursor = 'not-allowed'
            useTypeSelect.value = ''
        }
        
        // Update unit display
        unitSpan.textContent = getCalculationTypeUnit(calculationType)
    }
}

// ✅ NEW: Apply selected calculation type to all items in category
function applyCalcTypeToAll(categoryId) {
    const quickSelect = document.getElementById(`quick-calc-type-${categoryId}`)
    if (!quickSelect) return
    
    const selectedCalcType = quickSelect.value
    const category = costsData[categoryId]
    
    if (!category || !category.costs) {
        console.error(`❌ Category ${categoryId} not found`)
        return
    }
    
    // Get the display name
    const calcTypeName = quickSelect.options[quickSelect.selectedIndex].text
    const itemCount = category.costs.length
    
    if (itemCount === 0) {
        alert('⚠️ لا توجد بنود في هذا القسم')
        return
    }
    
    const confirmMsg = `هل تريد تطبيق نوع الحساب "${calcTypeName}" على ${itemCount} بند؟`
    
    if (!confirm(confirmMsg)) return
    
    // Apply to all items
    category.costs.forEach(cost => {
        cost.calculationType = selectedCalcType
        cost.unit = getCalculationTypeUnit(selectedCalcType)
        
        // If switching away from PER_SQUARE_METER_USE_TYPE, clear useType
        if (selectedCalcType !== COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) {
            cost.useType = ''
        }
    })
    
    // Save and re-render
    localStorage.setItem('costsData', JSON.stringify(costsData))
    console.log(`✅ تم تطبيق نوع الحساب "${calcTypeName}" على ${itemCount} بند في القسم: ${category.name}`)
    
    // Re-render the costs system to show updated values
    renderCostsSystem()
    updateCostsSummary()
    
    // Show success message
    alert(`✅ تم التطبيق بنجاح على ${itemCount} بند`)
}

// ✅ NEW: Apply selected use type to all items in category
function applyUseTypeToAll(categoryId) {
    const quickSelect = document.getElementById(`quick-use-type-${categoryId}`)
    if (!quickSelect) return
    
    const selectedUseType = quickSelect.value
    const category = costsData[categoryId]
    
    if (!category || !category.costs) {
        console.error(`❌ Category ${categoryId} not found`)
        return
    }
    
    // Count how many items can use useType (only PER_SQUARE_METER_USE_TYPE supports it)
    let affectedCount = 0
    category.costs.forEach(cost => {
        if (cost.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) {
            affectedCount++
        }
    })
    
    if (affectedCount === 0) {
        alert('⚠️ لا توجد بنود بنوع حساب "ريال/م² لاستخدام محدد"\n\nفقط هذا النوع يدعم تحديد نوع الاستخدام.')
        return
    }
    
    const useTypeName = quickSelect.options[quickSelect.selectedIndex].text
    const confirmMsg = `هل تريد تطبيق نوع الاستخدام "${useTypeName}" على ${affectedCount} بند؟\n\n(سيتم تطبيقه فقط على البنود من نوع "ريال/م² لاستخدام محدد")`
    
    if (!confirm(confirmMsg)) return
    
    // Apply to eligible items only
    category.costs.forEach(cost => {
        if (cost.calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) {
            cost.useType = selectedUseType
        }
    })
    
    // Save and re-render
    localStorage.setItem('costsData', JSON.stringify(costsData))
    console.log(`✅ تم تطبيق نوع الاستخدام "${useTypeName}" على ${affectedCount} بند في القسم: ${category.name}`)
    
    // Re-render the costs system to show updated values
    renderCostsSystem()
    updateCostsSummary()
    
    // Show success message
    alert(`✅ تم التطبيق بنجاح على ${affectedCount} بند`)
}

