// Update general cost field
function updateGeneralCostField(costId, field, value) {
    const costItem = costsData.generalCosts.costs.find(c => c.id === costId)
    if (!costItem) return
    
    costItem[field] = value
    
    // If updating calculation type, update unit display
    if (field === 'calculationType') {
        costItem.unit = getCalculationTypeUnit(value)
        updateCostsSummary()
        // SMART FIX: Update calculated values dynamically (same as contingency)
        updateAllCalculatedValuesInCurrentView()
        
        // SPECIAL FIX: Update general costs total display immediately
        const generalTotalElement = document.getElementById('generalCostsTotalDisplay')
        if (generalTotalElement) {
            const newTotal = calculateGeneralCostsTotal()
            generalTotalElement.textContent = `${(newTotal || 0).toLocaleString('en-US')} ريال`
            console.log(`💰 [updateGeneralCostField-calcType] Updated general costs total display: ${(newTotal || 0).toLocaleString('en-US')} ريال`)
        }
        return
    }
    
    updateCostsSummary()
    // SMART FIX: Update calculated values dynamically (same as contingency)
    updateAllCalculatedValuesInCurrentView()
    
    // SPECIAL FIX: Update general costs total display immediately
    const generalTotalElement = document.getElementById('generalCostsTotalDisplay')
    if (generalTotalElement) {
        const newTotal = calculateGeneralCostsTotal()
        generalTotalElement.textContent = `${(newTotal || 0).toLocaleString('en-US')} ريال`
        console.log(`💰 [updateGeneralCostField] Updated general costs total display: ${(newTotal || 0).toLocaleString('en-US')} ريال`)
    }
    
    console.log(`✅ Updated general cost ${field}:`, value)
}

// Smart update for general costs calculated values
function updateGeneralCalculatedValueInTable(costId) {
    try {
        const costItem = costsData.generalCosts.costs.find(c => c.id === costId)
        if (!costItem) return
        
        // Calculate the new value
        const calculatedValue = calculateCostItemValue(costItem)
        console.log(`🧮 General cost calculated value for "${costItem.name}": ${(calculatedValue || 0).toLocaleString('en-US')}`)
        
        // Find and update the calculated value cell in general costs table
        const generalRows = document.querySelectorAll('.general-costs-table tr, #generalCosts tr')
        generalRows.forEach(row => {
            const nameInput = row.querySelector('input[type="text"]')
            if (nameInput && nameInput.value === costItem.name) {
                // Find the calculated value column (7th column typically)
                const calculatedValueCell = row.querySelector('td:nth-child(7)')
                if (calculatedValueCell) {
                    calculatedValueCell.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
                    console.log(`✅ Updated general cost calculated value for "${costItem.name}"`)
                }
            }
        })
        
    } catch (error) {
        console.error('❌ Error updating general cost calculated value:', error)
    }
}

// Toggle use type dropdown for new general items
function toggleGeneralUseType(calculationType) {
    const useTypeSelect = document.getElementById('new-general-use-type')
    const unitSpan = document.getElementById('new-general-unit')
    
    if (useTypeSelect) {
        const isUseTypeCalculation = calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE
        
        if (isUseTypeCalculation) {
            useTypeSelect.disabled = false
            useTypeSelect.style.opacity = '1'
            useTypeSelect.style.cursor = 'pointer'
        } else {
            useTypeSelect.disabled = true
            useTypeSelect.style.opacity = '0.5'
            useTypeSelect.style.cursor = 'not-allowed'
            useTypeSelect.value = ''
        }
    }
    
    if (unitSpan) {
        unitSpan.textContent = getCalculationTypeUnit(calculationType)
    }
}

// Add new general cost item
function addNewGeneralCostItem() {
    const nameInput = document.getElementById('new-general-name')
    const descriptionInput = document.getElementById('new-general-description')
    const typeSelect = document.getElementById('new-general-type')
    const useTypeSelect = document.getElementById('new-general-use-type')
    const valueInput = document.getElementById('new-general-value')
    
    if (!nameInput?.value.trim()) {
        alert('يرجى إدخال اسم البند')
        nameInput?.focus()
        return
    }
    
    const calculationType = typeSelect?.value || COST_CALCULATION_TYPES.PER_SQUARE_METER_GFA
    
    // Check if use type is required but not selected
    if (calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE && !useTypeSelect?.value) {
        alert('يرجى اختيار نوع الاستخدام')
        useTypeSelect?.focus()
        return
    }
    
    const newCostItem = {
        id: generateUniqueId(),
        name: nameInput.value.trim(),
        description: descriptionInput?.value.trim() || '',
        calculationType: calculationType,
        useType: (calculationType === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) ? useTypeSelect?.value : '',
        cost: parseFloat(valueInput?.value) || 0,
        value: parseFloat(valueInput?.value) || 0,
        unit: getCalculationTypeUnit(calculationType),
        isCustom: true
    }
    
    costsData.generalCosts.costs.push(newCostItem)
    renderCostsSystem()
    
    console.log(`✅ Added new general cost item: ${newCostItem.name}`)
}

// Delete general cost item
function deleteGeneralCostItem(costId) {
    const costItem = costsData.generalCosts.costs.find(c => c.id === costId)
    if (!costItem) return
    
    if (!confirm(`هل أنت متأكد من حذف البند "${costItem.name}"؟`)) {
        return
    }
    
    costsData.generalCosts.costs = costsData.generalCosts.costs.filter(c => c.id !== costId)
    renderCostsSystem()
    
    console.log(`✅ Deleted general cost item: ${costItem.name}`)
}

