// Toggle individual usage category content
function toggleUsageCategoryContent(useType) {
    try {
        const content = document.getElementById(`usage-category-content-${useType}`)
        const chevron = document.getElementById(`chevron-usage-${useType}`)
        
        if (!content) {
            console.warn(`⚠️ Usage category content not found: ${useType}`)
            return
        }
        
        const isVisible = content.style.display !== 'none'
        
        if (isVisible) {
            content.style.display = 'none'
            if (chevron) chevron.className = 'fas fa-chevron-left'
        } else {
            content.style.display = 'block'
            if (chevron) chevron.className = 'fas fa-chevron-down'
        }
        
        console.log(`✅ ${isVisible ? 'طي' : 'توسيع'} استخدام: ${useType}`)
        
    } catch (error) {
        console.error('❌ Error toggling usage category content:', error)
    }
}

// Update usage-based cost field
function updateUsageBasedCostField(useType, costId, field, value) {
    const category = costsData.usageBasedCosts.categories[useType]
    if (!category) return
    
    const costItem = category.costs.find(c => c.id === costId)
    if (!costItem) return
    
    costItem[field] = value
    
    // If updating calculation type, update unit and set useType if needed
    if (field === 'calculationType') {
        costItem.unit = getCalculationTypeUnit(value)
        
        // For usage-based costs, automatically set useType to match the category
        if (value === COST_CALCULATION_TYPES.PER_SQUARE_METER_USE_TYPE) {
            costItem.useType = useType
        }
    }
    
    updateCostsSummary()
    // SMART FIX: Update calculated values dynamically (same as contingency)
    updateAllCalculatedValuesInCurrentView()
    
    // IMMEDIATE FIX: Update the calculated value in the correct column right away
    const calculatedValue = calculateCostItemValue(costItem)
    
    // 🎯 ROBUST SOLUTION: Use more specific selector within usage category context
    // Find the specific usage category container first, then look for the calculated value cell
    const usageCategoryContainer = document.querySelector(`#usage-category-content-${useType}`)
    let calculatedValueCell = null
    
    if (usageCategoryContainer) {
        // Look for calculated value cell within this specific category only
        calculatedValueCell = usageCategoryContainer.querySelector(`#calculated-value-usage-${useType}-${costId}`)
        console.log(`🎯 [updateUsageBasedCostField] Found category container for ${useType}, cell found: ${!!calculatedValueCell}`)
    }
    
    // Fallback to global search if container approach fails
    if (!calculatedValueCell) {
        calculatedValueCell = document.getElementById(`calculated-value-usage-${useType}-${costId}`)
        console.log(`🎯 [updateUsageBasedCostField] Fallback global search, cell found: ${!!calculatedValueCell}`)
    }
    
    if (calculatedValueCell) {
        calculatedValueCell.textContent = `${(calculatedValue || 0).toLocaleString('en-US')} ريال`
        console.log(`✅ [updateUsageBasedCostField] Updated calculated value for "${costItem.name}" in ${useType}: ${(calculatedValue || 0).toLocaleString('en-US')}`)
    } else {
        console.error(`❌ [updateUsageBasedCostField] Could not find calculated value cell for ${useType}-${costId}`)
        // List all elements with similar IDs for debugging
        const allCells = document.querySelectorAll('[id*="calculated-value-usage"]')
        console.log(`🔍 [updateUsageBasedCostField] All calculated value cells found:`, Array.from(allCells).map(el => el.id))
    }
    
    // SPECIAL FIX: Update usage-based cost total display immediately
    const usageTotalElement = document.getElementById(`usageBasedCostTotal-${useType}`)
    if (usageTotalElement) {
        const totalArea = calculationResults?.areas?.useBreakdown?.[useType]?.gla || calculateTotalAreaForUse(useType)
        const newTotal = calculateUsageBasedCostTotal(category, totalArea)
        usageTotalElement.textContent = `${(newTotal || 0).toLocaleString('en-US')} ريال`
        console.log(`💰 [updateUsageBasedCostField] Updated usage total for ${useType}: ${(newTotal || 0).toLocaleString('en-US')} ریال`)
    }
    
    console.log(`✅ Updated usage-based cost ${field}:`, value)
}

