// Update project management field
function updateProjectManagementField(serviceId, field, value) {
    const service = costsData.projectManagement.services.find(s => s.id === serviceId)
    if (!service) return
    
    service[field] = value
    
    // If updating calculation type, update unit and recalculate
    if (field === 'calculationType') {
        service.unit = getCalculationTypeUnit(value)
        console.log(`🔄 Updated project management calculation type for "${service.name}" to: ${value}`)
        logSystemDataSources()
        
        const calculatedValue = calculateCostItemValue(service)
        showCalculationDetails(service, calculatedValue)
    }
    
    updateCostsSummary()
    // SMART FIX: Update calculated values dynamically
    updateAllCalculatedValuesInCurrentView()
    
    console.log(`✅ Updated project management ${field}:`, value)
}

// Add new project management item
function addNewProjectManagementItem() {
    const nameInput = document.getElementById('new-pm-name')
    const descriptionInput = document.getElementById('new-pm-description')
    const typeSelect = document.getElementById('new-pm-type')
    const valueInput = document.getElementById('new-pm-value')
    
    if (!nameInput?.value.trim()) {
        alert('يرجى إدخال اسم الخدمة')
        nameInput?.focus()
        return
    }
    
    const newService = {
        id: generateUniqueId(),
        name: nameInput.value.trim(),
        description: descriptionInput?.value.trim() || '',
        calculationType: typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION,
        percentage: parseFloat(valueInput?.value) || 0,
        value: parseFloat(valueInput?.value) || 0,
        unit: getCalculationTypeUnit(typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION),
        isCustom: true
    }
    
    costsData.projectManagement.services.push(newService)
    renderCostsSystem()
    
    console.log(`✅ Added new project management service: ${newService.name}`)
}

// Delete project management item
function deleteProjectManagementItem(serviceId) {
    const service = costsData.projectManagement.services.find(s => s.id === serviceId)
    if (!service) return
    
    if (!confirm(`هل أنت متأكد من حذف الخدمة "${service.name}"؟`)) {
        return
    }
    
    costsData.projectManagement.services = costsData.projectManagement.services.filter(s => s.id !== serviceId)
    renderCostsSystem()
    
    console.log(`✅ Deleted project management service: ${service.name}`)
}

