// Update fee field
function updateFeeField(categoryId, feeId, field, value) {
    const category = costsData[categoryId]
    if (!category || !category.fees) return
    
    const fee = category.fees.find(f => f.id === feeId)
    if (!fee) return
    
    fee[field] = value
    
    // If updating calculation type, update unit
    if (field === 'calculationType') {
        fee.unit = getCalculationTypeUnit(value)
    }
    
    updateCostsSummary()
    // SMART FIX: Update calculated values dynamically
    updateAllCalculatedValuesInCurrentView()
    
    console.log(`✅ Updated fee ${field}:`, value)
}

// Update contingency field (now uses the same system as other cost items)  
function updateContingencyField(categoryId, contingencyId, field, value) {
    const category = costsData[categoryId]
    if (!category || !category.costs) return
    
    const contingency = category.costs.find(c => c.id === contingencyId)
    if (!contingency) return
    
    contingency[field] = value
    
    // Handle special field updates
    if (field === 'calculationType') {
        contingency.unit = getCalculationTypeUnit(value)
    }
    
    updateCostsSummary()
    // SMART FIX: Update calculated values dynamically
    updateAllCalculatedValuesInCurrentView()
    
    console.log(`✅ Updated contingency ${field}:`, value)
}

// Add new fee item
function addNewFeeItem(categoryId) {
    const nameInput = document.getElementById(`new-fee-name-${categoryId}`)
    const descriptionInput = document.getElementById(`new-fee-description-${categoryId}`)
    const typeSelect = document.getElementById(`new-fee-type-${categoryId}`)
    const valueInput = document.getElementById(`new-fee-value-${categoryId}`)
    
    if (!nameInput?.value.trim()) {
        alert('يرجى إدخال نوع الأتعاب')
        nameInput?.focus()
        return
    }
    
    const newFee = {
        id: generateUniqueId(),
        name: nameInput.value.trim(),
        description: descriptionInput?.value.trim() || '',
        calculationType: typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL,
        value: parseFloat(valueInput?.value) || 0,
        unit: getCalculationTypeUnit(typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL),
        isCustom: true
    }
    
    costsData[categoryId].costs.push(newFee)
    renderCostsSystem()
    
    console.log(`✅ Added new fee: ${newFee.name}`)
}

// Add new contingency item
function addNewContingencyItem(categoryId) {
    const nameInput = document.getElementById(`new-contingency-name-${categoryId}`)
    const descriptionInput = document.getElementById(`new-contingency-description-${categoryId}`)
    const typeSelect = document.getElementById(`new-contingency-type-${categoryId}`)
    const valueInput = document.getElementById(`new-contingency-value-${categoryId}`)
    
    if (!nameInput?.value.trim()) {
        alert('يرجى إدخال نوع الطوارئ')
        nameInput?.focus()
        return
    }
    
    const newContingency = {
        id: generateUniqueId(),
        name: nameInput.value.trim(),
        description: descriptionInput?.value.trim() || '',
        calculationType: typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL,
        value: parseFloat(valueInput?.value) || 0,
        unit: getCalculationTypeUnit(typeSelect?.value || COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL),
        isCustom: true
    }
    
    costsData[categoryId].costs.push(newContingency)
    renderCostsSystem()
    
    console.log(`✅ Added new contingency: ${newContingency.name}`)
}

// Delete fee item
function deleteFeeItem(categoryId, feeId) {
    const fee = costsData[categoryId].costs.find(f => f.id === feeId)
    if (!fee) return
    
    if (!confirm(`هل أنت متأكد من حذف الأتعاب "${fee.name}"؟`)) {
        return
    }
    
    costsData[categoryId].costs = costsData[categoryId].costs.filter(f => f.id !== feeId)
    renderCostsSystem()
    
    console.log(`✅ Deleted fee: ${fee.name}`)
}

// Delete contingency item
function deleteContingencyItem(categoryId, contingencyId) {
    const contingency = costsData[categoryId].costs.find(c => c.id === contingencyId)
    if (!contingency) return
    
    if (!confirm(`هل أنت متأكد من حذف الطوارئ "${contingency.name}"؟`)) {
        return
    }
    
    costsData[categoryId].costs = costsData[categoryId].costs.filter(c => c.id !== contingencyId)
    renderCostsSystem()
    
    console.log(`✅ Deleted contingency: ${contingency.name}`)
}

