// Calculate total area for a specific use type based on sub-units
function calculateTotalAreaForUse(useType) {
    const useData = usesData[useType]
    if (!useData) return 0
    
    // ✅ استخدام totalGFA مباشرة (التكاليف تُحسب على أساس المساحة الكاملة)
    if (useData.totalGFA && useData.totalGFA > 0) {
        console.log(`📏 [${useData.name}] استخدام totalGFA: ${useData.totalGFA.toLocaleString('en-US')} م²`);
        return useData.totalGFA;
    }
    
    // Fallback: حساب من subUnits (للحالات القديمة)
    if (useData.subUnits && Array.isArray(useData.subUnits)) {
        const total = useData.subUnits.reduce((sum, subUnit) => {
            if (subUnit.percentage && subUnit.percentage > 0) {
                return sum + (subUnit.units * subUnit.areaPerUnit)
            }
            return sum
        }, 0);
        console.log(`📏 [${useData.name}] حساب من subUnits: ${total.toLocaleString('en-US')} م²`);
        return total;
    }
    
    // Fallback: use subCategories (old structure)
    if (useData.subCategories) {
        const total = Object.values(useData.subCategories).reduce((sum, subCategory) => {
            return sum + (subCategory.units * subCategory.areaPerUnit)
        }, 0);
        return total;
    }
    
    console.warn(`⚠️ [${useData.name}] لا توجد مساحة متاحة`);
    return 0
}

// دالة حساب إجمالي الوحدات لاستخدام محدد
function calculateTotalUnitsForUse(useType) {
    const useData = usesData[useType]
    if (!useData) return 0
    
    // Use subUnits (new structure)
    if (useData.subUnits && Array.isArray(useData.subUnits)) {
        return useData.subUnits.reduce((total, subUnit) => {
            // Only count sub-units with percentage > 0
            if (subUnit.percentage && subUnit.percentage > 0) {
                return total + (subUnit.units || 0)
            }
            return total
        }, 0)
    }
    
    // Fallback: use subCategories (old structure)
    if (useData.subCategories) {
        return Object.values(useData.subCategories).reduce((total, subCategory) => {
            return total + (subCategory.units || 0)
        }, 0)
    }
    
    return 0
}

