// Helper functions for comprehensive costs calculation

function calculateGeneralCostByType(costType) {
    const generalCost = costsData.generalCosts.costs.find(c => c.id === costType)
    if (!generalCost) return 0
    
    const totalGFA = calculateTotalGFA()
    return generalCost.value * totalGFA
}

function calculateUsageBasedCostByType(costType) {
    let total = 0
    
    getActiveUses().forEach(useType => {
        const category = costsData.usageBasedCosts.categories[useType]
        if (category) {
            const cost = category.costs.find(c => c.id === costType)
            if (cost) {
                const totalArea = calculateTotalAreaForUse(useType)
                total += cost.value * totalArea
            }
        }
    })
    
    return total
}

function calculatePhaseCostsByType(phaseType) {
    const phase = costsData.phaseCosts.phases[phaseType]
    if (!phase) return { total: 0, activities: {} }
    
    const activities = {}
    let total = 0
    
    phase.activities.forEach(activity => {
        activities[activity.id] = activity.cost
        total += activity.cost
    })
    
    return { total, activities }
}

function calculateProjectManagementByType(serviceType) {
    const service = costsData.projectManagement.services.find(s => s.id === serviceType)
    if (!service) return 0
    
    const totalConstructionCost = calculateTotalConstructionCost()
    return (service.percentage / 100) * totalConstructionCost
}

function calculatePermitCostByType(permitType) {
    const permit = costsData.permits.permits.find(p => p.id === permitType)
    return permit ? permit.value : 0
}

// Calculate professional fees based on percentage of construction cost
function calculateProfessionalFees(feeType) {
    try {
        // Calculate base construction cost
        const totalGFA = calculateTotalGFA()
        const generalConstructionCost = costsData.generalCosts.costs.reduce((total, cost) => {
            return total + (cost.value * totalGFA)
        }, 0)
        
        // Add usage-based costs
        const usageBasedCost = getActiveUses().reduce((total, useType) => {
            return total + costsData.usageBasedCosts.costs.reduce((useTotal, cost) => {
                const area = calculationResults.areas.useBreakdown[useType]
                const costPerSqm = getCostPerSqmForUse(cost.id, useType)
                return useTotal + (costPerSqm * (area ? area.gla : 0))
            }, 0)
        }, 0)
        
        const totalConstructionCost = generalConstructionCost + usageBasedCost
        
        // Professional fee percentages (typical Saudi Arabia rates)
        const feeRates = {
            design: 0.06,          // 6% for architectural and design services
            engineering: 0.04,     // 4% for engineering services
            projectManagement: 0.03, // 3% for project management
            supervision: 0.04      // 4% for construction supervision
        }
        
        return totalConstructionCost * (feeRates[feeType] || 0)
        
    } catch (error) {
        console.error(`❌ Error calculating ${feeType} fees:`, error)
        return 0
    }
}

// Calculate total permit costs
function calculateTotalPermitCosts() {
    try {
        return costsData.permits.permits.reduce((total, permit) => {
            return total + permit.value
        }, 0)
    } catch (error) {
        console.error('❌ Error calculating total permit costs:', error)
        return 0
    }
}

// Calculate contingency costs based on project complexity
function calculateContingencyCosts(contingencyType) {
    try {
        // Calculate base construction cost
        const totalGFA = calculateTotalGFA()
        const generalConstructionCost = costsData.generalCosts.costs.reduce((total, cost) => {
            return total + (cost.value * totalGFA)
        }, 0)
        
        // Add usage-based costs
        const usageBasedCost = getActiveUses().reduce((total, useType) => {
            return total + costsData.usageBasedCosts.costs.reduce((useTotal, cost) => {
                const area = calculationResults.areas.useBreakdown[useType]
                const costPerSqm = getCostPerSqmForUse(cost.id, useType)
                return useTotal + (costPerSqm * (area ? area.gla : 0))
            }, 0)
        }, 0)
        
        const totalConstructionCost = generalConstructionCost + usageBasedCost
        
        // Contingency percentages based on Saudi market standards
        const contingencyRates = {
            construction: 0.05,    // 5% for construction contingency
            escalation: 0.03,      // 3% for price escalation
            delays: 0.02,          // 2% for project delays
            regulatory: 0.01       // 1% for regulatory changes
        }
        
        return totalConstructionCost * (contingencyRates[contingencyType] || 0)
        
    } catch (error) {
        console.error(`❌ Error calculating ${contingencyType} contingency:`, error)
        return 0
    }
}



// Calculate cost item value based on calculation type and project parameters


// Helper function to calculate base total cost for percentage calculations (避免循环引用)
function calculateBaseTotalCostForPercentages() {
    try {
        let baseCost = 0

        // إضافة التكاليف العامة
        if (costsData.generalCosts && costsData.generalCosts.costs) {
            costsData.generalCosts.costs.forEach(cost => {
                if (cost.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                    baseCost += calculateCostItemValue(cost)
                }
            })
        }

        // تم إلغاء التكاليف المرتبطة بالاستخدام - يتم حسابها من البنود العامة

        // إضافة تكاليف المراحل
        if (costsData.phaseCosts && costsData.phaseCosts.phases) {
            Object.values(costsData.phaseCosts.phases).forEach(phase => {
                if (phase.activities) {
                    phase.activities.forEach(activity => {
                        if (activity.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                            baseCost += calculateCostItemValue(activity)
                        }
                    })
                }
            })
        }

        // إضافة إدارة المشروع (إذا لم تكن بالنسبة)
        if (costsData.projectManagement && costsData.projectManagement.costs) {
            costsData.projectManagement.costs.forEach(cost => {
                if (cost.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                    baseCost += calculateCostItemValue(cost)
                }
            })
        }

        // إضافة التراخيص
        if (costsData.permits && costsData.permits.permits) {
            costsData.permits.permits.forEach(permit => {
                if (permit.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                    baseCost += calculateCostItemValue(permit)
                }
            })
        }

        console.log(`💰 Base total cost for percentages: ${baseCost.toLocaleString('en-US')} SAR`)
        return baseCost

    } catch (error) {
        console.error('❌ Error calculating base total cost:', error)
        return 0
    }
}

/**
 * حساب التكلفة الإنشائية الأساسية (بدون النسب المئوية من الإنشاء)
 * لتجنب المراجع الدائرية في حسابات النسب المئوية
 */
function calculateBaseConstructionCostForPercentages() {
    try {
        let baseCost = 0

        // إضافة التكاليف العامة (البنود الأساسية فقط)
        if (costsData.generalCosts && costsData.generalCosts.costs) {
            costsData.generalCosts.costs.forEach(cost => {
                if (cost.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION &&
                    cost.calculationType !== COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                    baseCost += calculateCostItemValue(cost)
                }
            })
        }

        // تم إلغاء التكاليف المرتبطة بالاستخدام - يتم حسابها من البنود العامة

        console.log(`🏗️ Base construction cost for percentages: ${baseCost.toLocaleString('en-US')} SAR`)
        return baseCost

    } catch (error) {
        console.error('❌ Error calculating base construction cost:', error)
        return 0
    }
}

/**
 * نسخة محسنة لحساب التكلفة الإجمالية مع منع المراجع الدائرية
 */
function calculateTotalProjectCostForPercentageImproved() {
    try {
        let totalCost = 0

        // 1. البداية بالتكاليف الأساسية (بدون النسب المئوية)
        const baseCost = calculateBaseTotalCostForPercentages()
        totalCost += baseCost

        // 2. إضافة النسب المئوية من التكلفة الإنشائية
        const baseConstructionCost = calculateBaseConstructionCostForPercentages()
        let constructionPercentageCosts = 0

        // حساب النسب المئوية من التكلفة الإنشائية
        Object.values(costsData).forEach(category => {
            if (category.costs && Array.isArray(category.costs)) {
                category.costs.forEach(cost => {
                    if (cost.calculationType === COST_CALCULATION_TYPES.PERCENTAGE_OF_CONSTRUCTION) {
                        constructionPercentageCosts += baseConstructionCost * (cost.value / 100)
                    }
                })
            }
        })

        totalCost += constructionPercentageCosts

        // 3. حساب النسب المئوية من التكلفة الإجمالية (مرة واحدة فقط)
        let totalPercentageCosts = 0
        Object.values(costsData).forEach(category => {
            if (category.costs && Array.isArray(category.costs)) {
                category.costs.forEach(cost => {
                    if (cost.calculationType === COST_CALCULATION_TYPES.PERCENTAGE_OF_TOTAL) {
                        // استخدام التكلفة الحالية (الأساسية + نسب الإنشاء) كقاعدة
                        totalPercentageCosts += totalCost * (cost.value / 100)
                    }
                })
            }
        })

        totalCost += totalPercentageCosts

        console.log(`💰 Improved total project cost: ${totalCost.toLocaleString('en-US')} SAR`)
        console.log(`  - Base cost: ${baseCost.toLocaleString('en-US')}`)
        console.log(`  - Construction %: ${constructionPercentageCosts.toLocaleString('en-US')}`)
        console.log(`  - Total %: ${totalPercentageCosts.toLocaleString('en-US')}`)

        return totalCost

    } catch (error) {
        console.error('❌ Error calculating improved total project cost:', error)
        return 0
    }
}

// Calculate total cost for a category using enhanced calculation system
function calculateCategoryTotal(category) {
    let total = 0
    
    try {
        console.log(`💰 Calculating total for category: ${category.name || category.id}`)
        
        // Calculate costs from different arrays within the category
        const calculateFromArray = (items, arrayName) => {
            if (!Array.isArray(items)) return 0
            
            let arrayTotal = 0
            items.forEach(item => {
                const itemValue = calculateCostItemValue(item)
                arrayTotal += itemValue
                console.log(`💰 ${arrayName} "${item.name}": ${itemValue.toLocaleString('en-US')} SAR`)
            })
            
            if (arrayTotal > 0) {
                console.log(`💰 Total ${arrayName}: ${arrayTotal.toLocaleString('en-US')} SAR`)
            }
            return arrayTotal
        }
        
        // Standard cost arrays
        if (category.costs) {
            total += calculateFromArray(category.costs, 'Costs')
        }
        
        if (category.services) {
            total += calculateFromArray(category.services, 'Services')
        }
        
        if (category.permits) {
            total += calculateFromArray(category.permits, 'Permits')
        }
        
        if (category.fees) {
            total += calculateFromArray(category.fees, 'Fees')
        }
        
        if (category.contingencies) {
            total += calculateFromArray(category.contingencies, 'Contingencies')
        }
        
        // Phase costs (for phaseCosts category)
        if (category.phases) {
            Object.values(category.phases).forEach(phase => {
                if (phase.activities) {
                    total += calculateFromArray(phase.activities, `Phase ${phase.name} Activities`)
                }
            })
        }
        
        // Sub-categories (for nested structures)
        if (category.categories) {
            Object.values(category.categories).forEach(subCategory => {
                const subTotal = calculateCategoryTotal(subCategory)
                total += subTotal
                console.log(`💰 Sub-category "${subCategory.name}": ${subTotal.toLocaleString('en-US')} SAR`)
            })
        }
        
        console.log(`✅ Total for category "${category.name || category.id}": ${total.toLocaleString('en-US')} SAR`)
        return total
        
    } catch (error) {
        console.error(`❌ Error calculating category total for ${category.name || category.id}:`, error)
        return 0
    }
}

