// Calculate enhanced cost breakdown using new calculation system
function calculateEnhancedCostBreakdown() {
    
    const breakdown = {
        categories: {},
        byUseType: {},
        totals: {
            construction: 0,
            soft: 0,
            total: 0,
            contingency: 0
        },
        analytics: {
            costPerSqmGFA: 0,
            costPerSqmGLA: 0,
            costPerUnit: 0,
            costPerSqmLand: 0
        }
    }
    
    try {
        // Calculate all cost categories using enhanced calculation functions
        Object.values(costsData).forEach(category => {
            if (!category.id) return
            
            // تخطي قسم التكاليف المحذوف
            if (category.id === 'usageBasedCosts') {
                console.log('⏭️ تخطي قسم التكاليف حسب الاستخدام المحذوف')
                return
            }
            
            const categoryTotal = calculateCategoryTotal(category)
            if (category.id === 'generalCosts') {
                console.log(`📊 [calculateEnhancedCostBreakdown] General costs total: ${categoryTotal.toLocaleString('en-US')} ريال`)
            }
            const categoryAnalytics = analyzeCategoryDetails(category)
            
            breakdown.categories[category.id] = {
                id: category.id,
                name: category.name,
                nameEn: category.nameEn || category.name,
                color: category.color || 'gray',
                icon: category.icon || '📊',
                total: categoryTotal,
                items: categoryAnalytics.items,
                calculationTypes: categoryAnalytics.calculationTypes,
                isConstruction: categoryAnalytics.isConstruction
            }
            
            // Add to totals
            if (categoryAnalytics.isConstruction) {
                breakdown.totals.construction += categoryTotal
            } else {
                breakdown.totals.soft += categoryTotal
            }
            breakdown.totals.total += categoryTotal
        })
        
        // Calculate costs by use type with enhanced accuracy
        if (typeof usesData !== 'undefined' && usesData) {
            Object.values(usesData).forEach(use => {
                if (use.share > 0) {
                    const useCosts = calculateUseTypeCosts(use)
                    if (useCosts.total > 0) {
                        breakdown.byUseType[use.id] = {
                            id: use.id,
                            name: use.name,
                            nameEn: use.nameEn || use.name,
                            icon: use.icon || '🏢',
                            color: use.color || 'blue',
                            total: useCosts.total,
                            area: use.totalGLA || use.totalArea || 0,
                            units: use.totalUnits || 0,
                            costPerSqm: useCosts.costPerSqm,
                            costPerUnit: useCosts.costPerUnit,
                            share: use.share || 0
                        }
                    }
                }
            })
        }
        
        // Calculate enhanced analytics
        const totalGFA = calculateTotalGFA()
        const totalGLA = calculateTotalGLA()
        const totalUnits = calculateTotalUnits()
        const landArea = parseFloat(document.getElementById('landArea')?.value) || 0
        
        breakdown.analytics.costPerSqmGFA = totalGFA > 0 ? breakdown.totals.total / totalGFA : 0
        breakdown.analytics.costPerSqmGLA = totalGLA > 0 ? breakdown.totals.total / totalGLA : 0
        breakdown.analytics.costPerUnit = totalUnits > 0 ? breakdown.totals.total / totalUnits : 0
        breakdown.analytics.costPerSqmLand = landArea > 0 ? breakdown.totals.total / landArea : 0
        
        return breakdown
        
    } catch (error) {
        console.error('❌ Error calculating enhanced cost breakdown:', error)
        return breakdown
    }
}



// Analyze category details for enhanced reporting
function analyzeCategoryDetails(category) {
    const analysis = {
        items: 0,
        calculationTypes: {},
        isConstruction: false
    }
    
    try {
        // Determine if this is construction-related category using dynamic categoryType
        // Support both new categoryType system and legacy fallback
        if (category.categoryType) {
            // Use new dynamic category type system
            analysis.isConstruction = category.categoryType === 'construction'
            console.log(`📊 [analyzeCategoryDetails] ${category.id}: categoryType="${category.categoryType}" → isConstruction=${analysis.isConstruction}`)
        } else {
            // Legacy fallback for categories without categoryType
            const constructionCategories = ['generalCosts']
            analysis.isConstruction = constructionCategories.includes(category.id)
            console.log(`📊 [analyzeCategoryDetails] ${category.id}: Using legacy fallback → isConstruction=${analysis.isConstruction}`)
        }
        
        // Count items and analyze calculation types
        const analyzeItems = (items) => {
            if (!Array.isArray(items)) return
            
            items.forEach(item => {
                analysis.items++
                const calcType = item.calculationType || 'fixed_amount'
                analysis.calculationTypes[calcType] = (analysis.calculationTypes[calcType] || 0) + 1
            })
        }
        
        if (category.costs) analyzeItems(category.costs)
        if (category.services) analyzeItems(category.services)
        if (category.permits) analyzeItems(category.permits)
        if (category.fees) analyzeItems(category.fees)
        if (category.contingencies) analyzeItems(category.contingencies)
        
        if (category.phases) {
            Object.values(category.phases).forEach(phase => {
                if (phase.activities) analyzeItems(phase.activities)
            })
        }
        
        if (category.categories) {
            Object.values(category.categories).forEach(subCategory => {
                if (subCategory.costs) analyzeItems(subCategory.costs)
            })
        }
        
    } catch (error) {
        console.error(`❌ Error analyzing category ${category.id}:`, error)
    }
    
    return analysis
}

// Calculate costs for specific use type
function calculateUseTypeCosts(use) {
    const result = {
        total: 0,
        costPerSqm: 0,
        costPerUnit: 0
    }
    
    try {
        // Get usage-based costs for this use type
        const category = costsData.usageBasedCosts?.categories?.[use.id]
        if (category && category.costs) {
            category.costs.forEach(cost => {
                result.total += calculateCostItemValue(cost)
            })
        }
        
        // Calculate per-area and per-unit costs
        // ✅ استخدام GFA دائماً (التكاليف غير مرتبطة بـ GLA)
        const area = use.totalGFA || 0;
        const units = use.totalUnits || 0;
        
        if (area > 0) {
            console.log(`💰 [${use.name}] حساب التكلفة على أساس GFA: ${area.toLocaleString('en-US')} م²`);
        }
        
        result.costPerSqm = area > 0 ? result.total / area : 0
        result.costPerUnit = units > 0 ? result.total / units : 0
        
    } catch (error) {
        console.error(`❌ Error calculating costs for use type ${use.id}:`, error)
    }
    
    return result
}

// Generate comprehensive cost analytics and insights
function generateCostAnalytics(costBreakdown, totalGFA, totalGLA, landArea) {
    const analytics = {
        kpis: {},
        insights: [],
        trends: {},
        benchmarks: {}
    }
    
    try {
        // Key Performance Indicators
        analytics.kpis = {
            totalCost: costBreakdown.totals.total,
            constructionCost: costBreakdown.totals.construction,
            softCost: costBreakdown.totals.soft,
            costPerSqmGFA: costBreakdown.analytics.costPerSqmGFA,
            costPerSqmGLA: costBreakdown.analytics.costPerSqmGLA,
            costPerUnit: costBreakdown.analytics.costPerUnit,
            costPerSqmLand: costBreakdown.analytics.costPerSqmLand,
            constructionRatio: costBreakdown.totals.total > 0 ? (costBreakdown.totals.construction / costBreakdown.totals.total) * 100 : 0,
            softCostRatio: costBreakdown.totals.total > 0 ? (costBreakdown.totals.soft / costBreakdown.totals.total) * 100 : 0,
            efficiency: totalGLA > 0 && totalGFA > 0 ? (totalGLA / totalGFA) * 100 : 0
        }
        
        // Generate intelligent insights
        analytics.insights = generateCostInsights(analytics.kpis, costBreakdown)
        
        // Calculate trends and comparisons
        analytics.trends = {
            highestCategory: findHighestCostCategory(costBreakdown.categories),
            lowestCategory: findLowestCostCategory(costBreakdown.categories),
            mostExpensiveUse: findMostExpensiveUseType(costBreakdown.byUseType),
            averageCostPerSqm: analytics.kpis.costPerSqmGFA
        }
        
        // Industry benchmarks (Saudi market)
        analytics.benchmarks = {
            residential: { min: 2500, max: 4500, avg: 3500 },
            retail: { min: 3000, max: 6000, avg: 4500 },
            office: { min: 2800, max: 5500, avg: 4000 },
            hotel: { min: 8000, max: 15000, avg: 11000 }
        }
        
    } catch (error) {
        console.error('❌ Error generating cost analytics:', error)
    }
    
    return analytics
}

// Generate intelligent cost insights
function generateCostInsights(kpis, costBreakdown) {
    const insights = []
    
    try {
        // Construction vs soft cost ratio analysis
        if (kpis.constructionRatio > 85) {
            insights.push({
                type: 'warning',
                icon: '⚠️',
                title: 'نسبة عالية للتكاليف الإنشائية',
                description: `نسبة التكاليف الإنشائية (${kpis.constructionRatio.toFixed(1)}%) مرتفعة. قد تحتاج لمراجعة التكاليف الإضافية.`
            })
        }
        
        // Cost per sqm analysis
        if (kpis.costPerSqmGFA > 6000) {
            insights.push({
                type: 'info',
                icon: '💡',
                title: 'تكلفة مرتفعة للمتر المربع',
                description: `متوسط التكلفة ${kpis.costPerSqmGFA.toFixed(0)} ريال/م² يشير إلى مشروع عالي الجودة.`
            })
        } else if (kpis.costPerSqmGFA < 2500) {
            insights.push({
                type: 'success',
                icon: '✅',
                title: 'تكلفة اقتصادية للمتر المربع',
                description: `متوسط التكلفة ${kpis.costPerSqmGFA.toFixed(0)} ريال/م² يشير إلى مشروع اقتصادي.`
            })
        }
        
        // Efficiency analysis
        if (kpis.efficiency > 85) {
            insights.push({
                type: 'success',
                icon: '🎯',
                title: 'كفاءة ممتازة في المساحات',
                description: `كفاءة المساحات ${kpis.efficiency.toFixed(1)}% ممتازة وتحقق استغلال أمثل.`
            })
        }
        
        // Use type cost analysis
        const expensiveUse = findMostExpensiveUseType(costBreakdown.byUseType)
        if (expensiveUse) {
            insights.push({
                type: 'info',
                icon: '📊',
                title: `أعلى تكلفة: ${expensiveUse.name}`,
                description: `استخدام ${expensiveUse.name} يمثل أعلى تكلفة بـ ${formatCurrency(expensiveUse.total)}.`
            })
        }
        
    } catch (error) {
        console.error('❌ Error generating insights:', error)
    }
    
    return insights
}

// Find highest cost category
function findHighestCostCategory(categories) {
    let highest = null
    let maxCost = 0
    
    Object.values(categories).forEach(category => {
        if (category.total > maxCost) {
            maxCost = category.total
            highest = category
        }
    })
    
    return highest
}

// Find lowest cost category
function findLowestCostCategory(categories) {
    let lowest = null
    let minCost = Infinity
    
    Object.values(categories).forEach(category => {
        if (category.total > 0 && category.total < minCost) {
            minCost = category.total
            lowest = category
        }
    })
    
    return lowest
}

// Find most expensive use type
function findMostExpensiveUseType(useTypes) {
    let mostExpensive = null
    let maxCost = 0
    
    Object.values(useTypes).forEach(use => {
        if (use.total > maxCost) {
            maxCost = use.total
            mostExpensive = use
        }
    })
    
    return mostExpensive
}

