KPI_COLOR_PALETTES.violet = KPI_COLOR_PALETTES.purple
KPI_COLOR_PALETTES.fuchsia = KPI_COLOR_PALETTES.pink
Object.freeze(KPI_COLOR_PALETTES)

// Create KPI card component
function createKPICard({
    title = '',
    subtitle = '',
    value = '',
    icon = 'fas fa-chart-line',
    color = 'blue'
} = {}) {
    const safeColor = typeof color === 'string' && color.trim() ? color.trim() : 'blue'
    const safeIcon = typeof icon === 'string' && icon.trim() ? icon.trim() : 'fas fa-chart-line'
    const safeTitle = typeof title === 'string' ? title : ''
    const safeSubtitle = typeof subtitle === 'string' ? subtitle : ''
    const safeValue = typeof value === 'number'
        ? value.toLocaleString('en-US')
        : (typeof value === 'string' ? value : '')

    const palette = KPI_COLOR_PALETTES[safeColor] || KPI_COLOR_PALETTES.blue

    return `
        <div class="bg-gradient-to-br ${palette.from} ${palette.to} rounded-xl p-4 border ${palette.border} hover:shadow-md transition-all duration-200">
            <div class="flex items-center justify-between mb-2">
                <i class="${safeIcon} ${palette.icon} text-lg"></i>
                <div class="w-2 h-2 ${palette.dot} rounded-full"></div>
            </div>
            <div class="text-2xl font-bold ${palette.value} mb-1">${safeValue}</div>
            <div class="text-xs font-medium ${palette.title} mb-1">${safeTitle}</div>
            <div class="text-xs ${palette.subtitle}">${safeSubtitle}</div>
        </div>
    `
}

// Get insight color based on type
function getInsightColor(type) {
    const colors = {
        success: 'green',
        warning: 'yellow',
        info: 'blue',
        error: 'red'
    }
    return colors[type] || 'gray'
}

