// Calculate enhanced revenue breakdown using new calculation system
function calculateEnhancedRevenueBreakdown() {
    const breakdown = {
        categories: {},
        byUseType: {},
        totals: {
            rental: 0,
            sales: 0,
            additional: 0,
            optimization: 0,
            total: 0
        },
        analytics: {
            revenuePerSqmGFA: 0,
            revenuePerSqmGLA: 0,
            revenuePerUnit: 0,
            revenuePerSqmLand: 0,
            yieldRatio: 0
        }
    }
    
    try {
        // Calculate rental revenues
        let totalRentalRevenues = 0
        if (revenuesData?.rentalRevenues?.subUnits) {
            Object.values(revenuesData.rentalRevenues.subUnits).forEach(subUnit => {
                totalRentalRevenues += getSubUnitRentalTotal(subUnit)
            })
        }
        
        // Calculate sales revenues
        let totalSalesRevenues = 0
        if (revenuesData?.salesRevenues?.subUnits) {
            Object.values(revenuesData.salesRevenues.subUnits).forEach(subUnit => {
                totalSalesRevenues += getSubUnitSalesTotal(subUnit)
            })
        }
        
        // Calculate additional revenues
        const totalAdditionalRevenues = revenuesData?.additionalRevenues?.revenues?.reduce((sum, revenue) => sum + (revenue.amount || 0), 0) || 0
        
        // Calculate optimization impact
        const totalOptimizationImpact = revenuesData?.revenueOptimization?.strategies?.reduce((sum, strategy) => sum + (strategy.impact || 0), 0) || 0
        const optimizedRentalRevenues = totalRentalRevenues * (1 + totalOptimizationImpact / 100)
        const optimizationValue = optimizedRentalRevenues - totalRentalRevenues

        // Set up categories
        breakdown.categories = {
            rentalRevenues: {
                id: 'rentalRevenues',
                name: 'إيرادات الإيجار',
                nameEn: 'Rental Revenues',
                color: 'emerald',
                icon: '🏠',
                total: optimizedRentalRevenues,
                baseTotal: totalRentalRevenues,
                optimizationBonus: optimizationValue,
                isRecurring: true
            },
            salesRevenues: {
                id: 'salesRevenues',
                name: 'إيرادات المبيعات',
                nameEn: 'Sales Revenues',
                color: 'cyan',
                icon: '💰',
                total: totalSalesRevenues,
                isRecurring: false
            },
            additionalRevenues: {
                id: 'additionalRevenues',
                name: 'الإيرادات الإضافية',
                nameEn: 'Additional Revenues',
                color: 'violet',
                icon: '➕',
                total: totalAdditionalRevenues,
                isRecurring: true
            }
        }

        // Calculate totals
        breakdown.totals.rental = optimizedRentalRevenues
        breakdown.totals.sales = totalSalesRevenues
        breakdown.totals.additional = totalAdditionalRevenues
        breakdown.totals.optimization = optimizationValue
        breakdown.totals.total = optimizedRentalRevenues + totalSalesRevenues + totalAdditionalRevenues

        // Calculate revenues by use type with enhanced accuracy
        if (typeof usesData !== 'undefined' && usesData) {
            Object.values(usesData).forEach(use => {
                if (use.share > 0) {
                    const useRevenues = calculateUseTypeRevenues(use)
                    if (useRevenues.total > 0) {
                        breakdown.byUseType[use.id] = {
                            id: use.id,
                            name: use.name,
                            nameEn: use.nameEn || use.name,
                            icon: use.icon || '🏢',
                            color: use.color || 'blue',
                            total: useRevenues.total,
                            rental: useRevenues.rental,
                            sales: useRevenues.sales,
                            area: use.totalGLA || use.totalArea || 0,
                            units: use.totalUnits || 0,
                            revenuePerSqm: useRevenues.revenuePerSqm,
                            revenuePerUnit: useRevenues.revenuePerUnit,
                            share: use.share || 0
                        }
                    }
                }
            })
        }

        // Calculate enhanced analytics
        const totalGFA = calculateTotalGFA()
        const totalGLA = calculateTotalGLA()
        const totalUnits = calculateTotalUnits()
        const landArea = parseFloat(document.getElementById('landArea')?.value) || 0

        breakdown.analytics.revenuePerSqmGFA = totalGFA > 0 ? breakdown.totals.total / totalGFA : 0
        breakdown.analytics.revenuePerSqmGLA = totalGLA > 0 ? breakdown.totals.total / totalGLA : 0
        breakdown.analytics.revenuePerUnit = totalUnits > 0 ? breakdown.totals.total / totalUnits : 0
        breakdown.analytics.revenuePerSqmLand = landArea > 0 ? breakdown.totals.total / landArea : 0
        
        // Calculate yield ratio (revenue vs cost)
        const totalCost = calculateTotalProjectCostForPercentage()
        breakdown.analytics.yieldRatio = totalCost > 0 ? (breakdown.totals.rental / totalCost) * 100 : 0

        return breakdown
        
    } catch (error) {
        console.error('❌ Error calculating enhanced revenue breakdown:', error)
        return breakdown
    }
}

// Calculate revenues for specific use type
function calculateUseTypeRevenues(use) {
    const result = {
        total: 0,
        rental: 0,
        sales: 0,
        revenuePerSqm: 0,
        revenuePerUnit: 0
    }
    
    try {
        // Calculate rental revenue for this use type
        if (revenuesData?.rentalRevenues?.subUnits) {
            Object.values(revenuesData.rentalRevenues.subUnits).forEach(subUnit => {
                if (subUnit?.parentUse === use.id) {
                    result.rental += getSubUnitRentalTotal(subUnit)
                }
            })
        }
        
        // Calculate sales revenue for this use type
        if (revenuesData?.salesRevenues?.subUnits) {
            Object.values(revenuesData.salesRevenues.subUnits).forEach(subUnit => {
                if (subUnit?.parentUse === use.id) {
                    result.sales += getSubUnitSalesTotal(subUnit)
                }
            })
        }
        
        // Apply optimization impact to rental revenues
        const optimizationImpact = revenuesData?.revenueOptimization?.strategies?.reduce((sum, strategy) => sum + (strategy.impact || 0), 0) || 0
        result.rental = result.rental * (1 + optimizationImpact / 100)
        
        result.total = result.rental + result.sales
        
        // Calculate per unit metrics
        const area = use.totalGLA || use.totalArea || 0
        const units = use.totalUnits || 0
        
        result.revenuePerSqm = area > 0 ? result.total / area : 0
        result.revenuePerUnit = units > 0 ? result.total / units : 0
        
    } catch (error) {
        console.error(`❌ Error calculating revenues for use type ${use.id}:`, error)
    }
    
    return result
}

// Generate enhanced revenue analytics and insights
function generateRevenueAnalytics(revenueBreakdown, totalGFA, totalGLA, landArea) {
    const analytics = {
        kpis: {
            totalRevenue: revenueBreakdown.totals.total,
            rentalRevenue: revenueBreakdown.totals.rental,
            salesRevenue: revenueBreakdown.totals.sales,
            additionalRevenue: revenueBreakdown.totals.additional,
            optimizationBonus: revenueBreakdown.totals.optimization,
            revenuePerSqmGFA: revenueBreakdown.analytics.revenuePerSqmGFA,
            revenuePerSqmGLA: revenueBreakdown.analytics.revenuePerSqmGLA,
            revenuePerUnit: revenueBreakdown.analytics.revenuePerUnit,
            revenuePerSqmLand: revenueBreakdown.analytics.revenuePerSqmLand,
            yieldRatio: revenueBreakdown.analytics.yieldRatio,
            rentalRatio: revenueBreakdown.totals.total > 0 ? (revenueBreakdown.totals.rental / revenueBreakdown.totals.total) * 100 : 0,
            salesRatio: revenueBreakdown.totals.total > 0 ? (revenueBreakdown.totals.sales / revenueBreakdown.totals.total) * 100 : 0
        },
        insights: []
    }
    
    try {
        // Generate smart insights based on revenue data
        
        // Insight 1: Revenue composition analysis
        if (analytics.kpis.rentalRatio > 70) {
            analytics.insights.push({
                type: 'success',
                icon: '🏠',
                title: 'هيكل إيرادات مستقر',
                description: `الإيجارات تمثل ${analytics.kpis.rentalRatio.toFixed(1)}% من الإيرادات، مما يضمن دخل مستمر ومستقر`
            })
        } else if (analytics.kpis.salesRatio > 60) {
            analytics.insights.push({
                type: 'warning',
                icon: '💰',
                title: 'اعتماد عالي على المبيعات',
                description: `المبيعات تمثل ${analytics.kpis.salesRatio.toFixed(1)}% من الإيرادات، قد يؤثر على استقرار التدفق النقدي`
            })
        }

        // Insight 2: Revenue optimization analysis
        const optimizationPercentage = analytics.kpis.rentalRevenue > 0 ? (analytics.kpis.optimizationBonus / (analytics.kpis.rentalRevenue - analytics.kpis.optimizationBonus)) * 100 : 0
        if (optimizationPercentage > 15) {
            analytics.insights.push({
                type: 'success',
                icon: '🚀',
                title: 'تحسين ممتاز للإيرادات',
                description: `استراتيجيات التحسين تزيد الإيرادات بنسبة ${optimizationPercentage.toFixed(1)}% (${formatCurrency(analytics.kpis.optimizationBonus)})`
            })
        } else if (optimizationPercentage < 5) {
            analytics.insights.push({
                type: 'info',
                icon: '💡',
                title: 'فرصة لزيادة الإيرادات',
                description: 'يمكن تطوير استراتيجيات إضافية لتحسين الإيرادات والوصول لإمكانات أعلى'
            })
        }

        // Insight 3: Revenue per sqm analysis
        if (analytics.kpis.revenuePerSqmGLA > 2000) {
            analytics.insights.push({
                type: 'success',
                icon: '📏',
                title: 'كفاءة مساحية عالية',
                description: `إيراد ${Math.round(analytics.kpis.revenuePerSqmGLA).toLocaleString('en-US')} ريال/م² يعكس استغلال ممتاز للمساحة`
            })
        } else if (analytics.kpis.revenuePerSqmGLA < 1000) {
            analytics.insights.push({
                type: 'warning',
                icon: '📐',
                title: 'إمكانية تحسين الكفاءة المساحية',
                description: `الإيراد الحالي ${Math.round(analytics.kpis.revenuePerSqmGLA).toLocaleString('en-US')} ريال/م² قابل للتحسين`
            })
        }

        // Insight 4: Yield ratio analysis
        if (analytics.kpis.yieldRatio > 12) {
            analytics.insights.push({
                type: 'success',
                icon: '📈',
                title: 'عائد استثماري ممتاز',
                description: `نسبة العائد ${analytics.kpis.yieldRatio.toFixed(1)}% تفوق معايير السوق المحلية`
            })
        } else if (analytics.kpis.yieldRatio < 6) {
            analytics.insights.push({
                type: 'warning',
                icon: '📉',
                title: 'عائد منخفض نسبياً',
                description: `نسبة العائد ${analytics.kpis.yieldRatio.toFixed(1)}% قد تحتاج مراجعة التكاليف أو زيادة الإيرادات`
            })
        }

        // Insight 5: Use type diversity analysis
        const useTypesCount = Object.keys(revenueBreakdown.byUseType).length
        if (useTypesCount >= 3) {
            analytics.insights.push({
                type: 'success',
                icon: '🏢',
                title: 'تنويع جيد للاستخدامات',
                description: `المشروع يضم ${useTypesCount} أنواع استخدام مختلفة، مما يقلل المخاطر ويزيد الاستقرار`
            })
        } else if (useTypesCount === 1) {
            analytics.insights.push({
                type: 'info',
                icon: '🎯',
                title: 'مشروع متخصص',
                description: 'المشروع يركز على نوع استخدام واحد، مما قد يزيد المخاطر ولكن يحقق تخصص أعمق'
            })
        }

    } catch (error) {
        console.error('❌ Error generating revenue analytics:', error)
    }

    return analytics
}

