// Update comprehensive timeline summary with advanced analytics
function updateComprehensiveTimelineSummary() {
    try {
        const summaryElement = document.getElementById('comprehensiveTimelineSummary')
        const performanceElement = document.getElementById('timelinePerformanceAnalysis')
        
        if (!summaryElement) return
        
        // Calculate comprehensive metrics
        const totalProjectDuration = calculateTotalProjectDuration()
        const allActivities = Object.values(timelineData.phases).flatMap(phase => phase.activities)
        const totalActivities = allActivities.length
        const totalProjectCost = allActivities.reduce((total, activity) => total + (activity.cost || 0), 0)
        
        // Phase analysis
        const phaseAnalysis = Object.entries(timelineData.phases).map(([id, phase]) => {
            const phaseCost = phase.activities.reduce((sum, activity) => sum + (activity.cost || 0), 0)
            const phaseDuration = Math.max(...phase.activities.map(activity => 
                (activity.calculatedStartOffset || activity.startOffset) + (activity.adjustedDuration || activity.duration)
            )) - Math.min(...phase.activities.map(activity => activity.calculatedStartOffset || activity.startOffset))
            
            return {
                name: phase.name,
                icon: phase.icon,
                cost: phaseCost,
                duration: phaseDuration,
                activities: phase.activities.length,
                costPercentage: (phaseCost / totalProjectCost) * 100
            }
        }).sort((a, b) => b.cost - a.cost)
        
        // Critical activities analysis
        const criticalActivities = allActivities.filter(activity => 
            activity.duration >= 3 || (activity.cost || 0) > 1000000
        )
        
        // Cost efficiency analysis
        const avgCostPerMonth = totalProjectCost / totalProjectDuration
        const avgCostPerActivity = totalProjectCost / totalActivities
        
        // Timeline efficiency
        const parallelismScore = Math.max(...Object.values(timelineData.phases).map(phase => phase.activities.length)) / totalActivities * 100
        
        // Financial insights
        const highCostActivities = allActivities.filter(activity => (activity.cost || 0) > avgCostPerActivity * 2).length
        const costDistribution = {
            lowCost: allActivities.filter(activity => (activity.cost || 0) < avgCostPerActivity * 0.5).length,
            mediumCost: allActivities.filter(activity => (activity.cost || 0) >= avgCostPerActivity * 0.5 && (activity.cost || 0) <= avgCostPerActivity * 2).length,
            highCost: highCostActivities
        }
        
        // Generate insights
        let insights = []
        
        if (totalProjectDuration > 24) {
            insights.push('⚠️ المشروع طويل المدى (أكثر من سنتين) - يتطلب مراقبة دقيقة للمخاطر')
        }
        
        if (avgCostPerMonth > 5000000) {
            insights.push('💰 كثافة إنفاق عالية - متوسط 5+ مليون ريال شهرياً')
        }
        
        if (parallelismScore > 60) {
            insights.push('⚡ توزيع جيد للأنشطة المتوازية - يسرع وقت التنفيذ')
        }
        
        if (criticalActivities.length > totalActivities * 0.3) {
            insights.push('🔴 نسبة عالية من الأنشطة الحرجة - تتطلب إدارة مخاطر مكثفة')
        }
        
        if (phaseAnalysis[0].costPercentage > 40) {
            insights.push(`💸 تركز ${phaseAnalysis[0].costPercentage.toFixed(1)}% من التكلفة في مرحلة ${phaseAnalysis[0].name}`)
        }
        
        // Update main summary
        summaryElement.innerHTML = `
            <!-- Key Metrics Row -->
            <div class="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-4 border border-blue-400/30 text-center">
                    <div class="text-2xl font-bold text-blue-200">${totalProjectDuration.toFixed(1)}</div>
                    <div class="text-sm text-white/80 mt-1">مدة المشروع (شهر)</div>
                </div>
                <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-4 border border-emerald-400/30 text-center">
                    <div class="text-2xl font-bold text-emerald-200">${totalActivities}</div>
                    <div class="text-sm text-white/80 mt-1">إجمالي الأنشطة</div>
                </div>
                <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-4 border border-purple-400/30 text-center">
                    <div class="text-xl font-bold text-purple-200">${(totalProjectCost / 1000000).toFixed(1)}م</div>
                    <div class="text-sm text-white/80 mt-1">التكلفة (مليون ريال)</div>
                </div>
                <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-4 border border-orange-400/30 text-center">
                    <div class="text-xl font-bold text-orange-200">${(avgCostPerMonth / 1000000).toFixed(1)}م</div>
                    <div class="text-sm text-white/80 mt-1">متوسط التكلفة الشهرية</div>
                </div>
            </div>
            
            <!-- Phase Analysis -->
            <div class="mb-6">
                <h4 class="font-semibold text-white mb-3 flex items-center">
                    <span class="w-6 h-6 bg-indigo-500/200 text-white rounded-full flex items-center justify-center text-xs mr-2">📋</span>
                    تحليل المراحل
                </h4>
                <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
                    ${phaseAnalysis.slice(0, 4).map(phase => `
                        <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-3 border border-white/15 flex items-center justify-between">
                            <div class="flex items-center">
                                <span class="text-lg mr-2">${phase.icon}</span>
                                <div>
                                    <div class="font-medium text-sm">${phase.name}</div>
                                    <div class="text-xs text-white/70">${phase.activities} نشاط</div>
                                </div>
                            </div>
                            <div class="text-right">
                                <div class="font-bold text-sm">${(phase.cost / 1000000).toFixed(1)}م ريال</div>
                                <div class="text-xs text-white/70">${phase.costPercentage.toFixed(1)}%</div>
                            </div>
                        </div>
                    `).join('')}
                </div>
            </div>
            
            <!-- Cost Distribution -->
            <div class="mb-6">
                <h4 class="font-semibold text-white mb-3 flex items-center">
                    <span class="w-6 h-6 bg-emerald-500/200 text-white rounded-full flex items-center justify-center text-xs mr-2">💰</span>
                    توزيع التكاليف
                </h4>
                <div class="grid grid-cols-3 gap-3">
                    <div class="bg-emerald-500/20 rounded-lg p-3 text-center border border-emerald-400/30">
                        <div class="text-lg font-bold text-emerald-200">${costDistribution.lowCost}</div>
                        <div class="text-xs text-white/80">أنشطة منخفضة التكلفة</div>
                    </div>
                    <div class="bg-amber-500/20 rounded-lg p-3 text-center border border-amber-400/30">
                        <div class="text-lg font-bold text-yellow-200">${costDistribution.mediumCost}</div>
                        <div class="text-xs text-white/80">أنشطة متوسطة التكلفة</div>
                    </div>
                    <div class="bg-red-500/20 rounded-lg p-3 text-center border border-red-400/30">
                        <div class="text-lg font-bold text-red-200">${costDistribution.highCost}</div>
                        <div class="text-xs text-white/80">أنشطة عالية التكلفة</div>
                    </div>
                </div>
            </div>
            
            <!-- Key Insights -->
            <div>
                <h4 class="font-semibold text-white mb-3 flex items-center">
                    <span class="w-6 h-6 bg-amber-500/200 text-white rounded-full flex items-center justify-center text-xs mr-2">💡</span>
                    الاستنتاجات والتحليلات الذكية
                </h4>
                <div class="space-y-2">
                    ${insights.map(insight => `
                        <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-3 border-l-4 border-yellow-400 text-sm">
                            ${insight}
                        </div>
                    `).join('')}
                    ${insights.length === 0 ? '<div class="text-white/70 text-center py-4">لا توجد تحليلات خاصة - المشروع ضمن المعايير الطبيعية</div>' : ''}
                </div>
            </div>
        `
        
        // Update performance analysis if element exists
        if (performanceElement) {
            performanceElement.innerHTML = `
                <div class="grid grid-cols-2 gap-4 text-sm">
                    <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-3 border">
                        <div class="flex items-center justify-between">
                            <span class="text-white/80">الأنشطة الحرجة:</span>
                            <span class="font-bold text-red-200">${criticalActivities.length}</span>
                        </div>
                    </div>
                    <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-3 border">
                        <div class="flex items-center justify-between">
                            <span class="text-white/80">درجة التوازي:</span>
                            <span class="font-bold text-emerald-200">${parallelismScore.toFixed(1)}%</span>
                        </div>
                    </div>
                </div>
            `
        }
        
        // Update timestamp
        const timestampElement = document.getElementById('timelineSummaryLastUpdate')
        if (timestampElement) {
            timestampElement.textContent = new Date().toLocaleString('en-US')
        }
        
        console.log('✅ Comprehensive timeline summary updated')
        
    } catch (error) {
        console.error('❌ Error updating comprehensive timeline summary:', error)
    }
}









