// Initialize cost categories donut chart
function initializeCostCategoriesDonutChart(categories) {
    const canvas = document.getElementById('costCategoriesDonutChart')
    if (!canvas) return
    
    // Destroy existing chart if it exists
    if (window.costCategoriesChart) {
        window.costCategoriesChart.destroy()
    }
    
    const ctx = canvas.getContext('2d')
    const data = Object.values(categories).filter(cat => cat.total > 0)
    
    const colors = [
        '#EF4444', '#3B82F6', '#10B981', '#F59E0B', '#8B5CF6', 
        '#EC4899', '#14B8A6', '#F97316', '#6366F1', '#84CC16'
    ]
    
    window.costCategoriesChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: data.map(cat => cat.name),
            datasets: [{
                data: data.map(cat => cat.total),
                backgroundColor: data.map((cat, index) => colors[index % colors.length]),
                borderColor: data.map((cat, index) => colors[index % colors.length]),
                borderWidth: 2,
                hoverOffset: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'bottom',
                    labels: {
                        padding: 20,
                        usePointStyle: true,
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    }
                },
                tooltip: {
                    callbacks: {
                        label: function(context) {
                            const label = context.label || ''
                            const value = formatCurrency(context.parsed)
                            const total = context.dataset.data.reduce((a, b) => a + b, 0)
                            const percentage = ((context.parsed / total) * 100).toFixed(1)
                            return `${label}: ${value} (${percentage}%)`
                        }
                    },
                    titleFont: {
                        family: 'Tajawal, sans-serif'
                    },
                    bodyFont: {
                        family: 'Tajawal, sans-serif'
                    }
                }
            },
            animation: {
                animateRotate: true,
                animateScale: true,
                duration: 1000,
                easing: 'easeInOutQuart'
            }
        }
    })
}

// Initialize use types bar chart
function initializeUseTypesBarChart(useTypes) {
    const canvas = document.getElementById('useTypesBarChart')
    if (!canvas) return
    
    // Destroy existing chart if it exists
    if (window.useTypesChart) {
        window.useTypesChart.destroy()
    }
    
    const ctx = canvas.getContext('2d')
    const data = Object.values(useTypes).filter(use => use.total > 0)
    
    if (data.length === 0) {
        ctx.fillStyle = '#6B7280'
        ctx.font = '16px Tajawal, sans-serif'
        ctx.textAlign = 'center'
        ctx.fillText('لا توجد بيانات لعرضها', canvas.width / 2, canvas.height / 2)
        return
    }
    
    const colors = {
        hotel: '#EF4444',
        retail: '#3B82F6', 
        office: '#10B981',
        residential: '#F59E0B',
        parking: '#6B7280',
        services: '#8B5CF6'
    }
    
    window.useTypesChart = new Chart(ctx, {
        type: 'bar',
        data: {
            labels: data.map(use => use.name),
            datasets: [
                {
                    label: 'إجمالي التكلفة (ريال)',
                    data: data.map(use => use.total),
                    backgroundColor: data.map(use => colors[use.id] || '#6B7280'),
                    borderColor: data.map(use => colors[use.id] || '#6B7280'),
                    borderWidth: 2,
                    borderRadius: 4
                },
                {
                    label: 'التكلفة/م² (ريال)',
                    data: data.map(use => use.costPerSqm || 0),
                    type: 'line',
                    borderColor: '#DC2626',
                    backgroundColor: 'rgba(220, 38, 38, 0.1)',
                    borderWidth: 3,
                    fill: false,
                    tension: 0.4,
                    yAxisID: 'y1'
                }
            ]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            interaction: {
                mode: 'index',
                intersect: false,
            },
            scales: {
                x: {
                    grid: {
                        display: false
                    },
                    ticks: {
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    }
                },
                y: {
                    type: 'linear',
                    display: true,
                    position: 'right',
                    beginAtZero: true,
                    ticks: {
                        callback: function(value) {
                            return formatNumber(value) + ' ريال'
                        },
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    },
                    grid: {
                        drawOnChartArea: true,
                    }
                },
                y1: {
                    type: 'linear',
                    display: true,
                    position: 'left',
                    beginAtZero: true,
                    ticks: {
                        callback: function(value) {
                            return formatNumber(value) + ' ريال/م²'
                        },
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    },
                    grid: {
                        drawOnChartArea: false,
                    }
                }
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        padding: 20,
                        usePointStyle: true,
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    }
                },
                tooltip: {
                    callbacks: {
                        title: function(context) {
                            return context[0].label
                        },
                        label: function(context) {
                            if (context.datasetIndex === 0) {
                                return `إجمالي التكلفة: ${formatCurrency(context.parsed.y)}`
                            } else {
                                return `التكلفة/م²: ${Math.round(context.parsed.y).toLocaleString('en-US')} ريال/م²`
                            }
                        }
                    },
                    titleFont: {
                        family: 'Tajawal, sans-serif'
                    },
                    bodyFont: {
                        family: 'Tajawal, sans-serif'
                    }
                }
            },
            animation: {
                duration: 1200,
                easing: 'easeInOutQuart'
            }
        }
    })
}

// Initialize cost breakdown radar chart
function initializeCostBreakdownRadarChart(costBreakdown, analytics) {
    const canvas = document.getElementById('costBreakdownRadarChart')
    if (!canvas) return
    
    // Destroy existing chart if it exists
    if (window.costBreakdownChart) {
        window.costBreakdownChart.destroy()
    }
    
    const ctx = canvas.getContext('2d')
    
    // Prepare radar chart data
    const labels = ['التكلفة الإجمالية', 'التكلفة الإنشائية', 'التكاليف الإضافية', 'ريال/م² GFA', 'ريال/م² GLA', 'الكفاءة']
    const maxValues = [
        Math.max(costBreakdown.totals.total, 50000000), // 50M max for total cost
        Math.max(costBreakdown.totals.construction, 40000000), // 40M max for construction
        Math.max(costBreakdown.totals.soft, 10000000), // 10M max for soft costs
        Math.max(analytics.kpis.costPerSqmGFA, 8000), // 8000 max for cost per sqm GFA
        Math.max(analytics.kpis.costPerSqmGLA, 10000), // 10000 max for cost per sqm GLA
        100 // 100% max for efficiency
    ]
    
    const actualValues = [
        costBreakdown.totals.total,
        costBreakdown.totals.construction, 
        costBreakdown.totals.soft,
        analytics.kpis.costPerSqmGFA,
        analytics.kpis.costPerSqmGLA,
        analytics.kpis.efficiency
    ]
    
    // Normalize values to 0-100 scale for radar chart
    const normalizedValues = actualValues.map((value, index) => (value / maxValues[index]) * 100)
    
    window.costBreakdownChart = new Chart(ctx, {
        type: 'radar',
        data: {
            labels: labels,
            datasets: [{
                label: 'قيم المشروع الحالية',
                data: normalizedValues,
                borderColor: 'rgb(59, 130, 246)',
                backgroundColor: 'rgba(59, 130, 246, 0.2)',
                borderWidth: 3,
                pointBackgroundColor: 'rgb(59, 130, 246)',
                pointBorderColor: '#fff',
                pointHoverBackgroundColor: '#fff',
                pointHoverBorderColor: 'rgb(59, 130, 246)',
                pointRadius: 6,
                pointHoverRadius: 8
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                r: {
                    beginAtZero: true,
                    max: 100,
                    ticks: {
                        stepSize: 20,
                        callback: function(value) {
                            return value + '%'
                        },
                        font: {
                            family: 'Tajawal, sans-serif',
                            size: 10
                        }
                    },
                    pointLabels: {
                        font: {
                            family: 'Tajawal, sans-serif',
                            size: 12
                        }
                    },
                    grid: {
                        color: 'rgba(0, 0, 0, 0.1)'
                    },
                    angleLines: {
                        color: 'rgba(0, 0, 0, 0.1)'
                    }
                }
            },
            plugins: {
                legend: {
                    position: 'top',
                    labels: {
                        font: {
                            family: 'Tajawal, sans-serif'
                        }
                    }
                },
                tooltip: {
                    callbacks: {
                        title: function(context) {
                            return context[0].label
                        },
                        label: function(context) {
                            const index = context.dataIndex
                            const actualValue = actualValues[index]
                            
                            switch(index) {
                                case 0:
                                case 1: 
                                case 2:
                                    return formatCurrency(actualValue)
                                case 3:
                                case 4:
                                    return Math.round(actualValue).toLocaleString('en-US') + ' ريال/م²'
                                case 5:
                                    return actualValue.toFixed(1) + '%'
                                default:
                                    return actualValue.toLocaleString('en-US')
                            }
                        }
                    },
                    titleFont: {
                        family: 'Tajawal, sans-serif'
                    },
                    bodyFont: {
                        family: 'Tajawal, sans-serif'
                    }
                }
            },
            animation: {
                duration: 1500,
                easing: 'easeInOutQuart'
            }
        }
    })
}

