// Initialize revenue categories donut chart
function initializeRevenueCategoriesDonutChart(categories) {
    const canvas = document.getElementById('revenueCategoriesDonutChart')
    if (!canvas) return
    
    // Destroy existing chart if it exists
    if (window.revenueCategoriesChart) {
        window.revenueCategoriesChart.destroy()
    }
    
    const ctx = canvas.getContext('2d')
    const data = Object.values(categories).filter(cat => cat.total > 0)
    
    const colors = [
        '#10B981', '#06B6D4', '#8B5CF6', '#F59E0B', '#EF4444', 
        '#EC4899', '#14B8A6', '#F97316', '#6366F1', '#84CC16'
    ]
    
    window.revenueCategoriesChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: data.map(cat => cat.name),
            datasets: [{
                data: data.map(cat => cat.total),
                backgroundColor: data.map((cat, index) => colors[index % colors.length]),
                borderColor: data.map((cat, index) => colors[index % colors.length]),
                borderWidth: 2,
                hoverOffset: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'bottom',
                    rtl: true,
                    labels: {
                        font: {
                            family: 'Cairo, sans-serif',
                            size: 12
                        },
                        generateLabels: function(chart) {
                            const datasets = chart.data.datasets
                            const labels = chart.data.labels
                            return labels.map((label, i) => ({
                                text: label,
                                fillStyle: datasets[0].backgroundColor[i],
                                strokeStyle: datasets[0].borderColor[i],
                                lineWidth: datasets[0].borderWidth,
                                hidden: false,
                                index: i
                            }))
                        }
                    }
                },
                tooltip: {
                    rtl: true,
                    titleFont: {
                        family: 'Cairo, sans-serif'
                    },
                    bodyFont: {
                        family: 'Cairo, sans-serif'
                    },
                    callbacks: {
                        label: function(context) {
                            const total = context.dataset.data.reduce((a, b) => a + b, 0)
                            const percentage = ((context.raw / total) * 100).toFixed(1)
                            return `${context.label}: ${context.raw.toLocaleString('en-US')} ريال (${percentage}%)`
                        }
                    }
                }
            }
        }
    })
}

