// Initialize use types distribution donut chart
function initializeUseTypesDistributionDonutChart(useTypes) {
    const canvas = document.getElementById('useTypesDistributionDonutChart')
    if (!canvas) return
    
    // Destroy existing chart if it exists
    if (window.useTypesDistributionChart) {
        window.useTypesDistributionChart.destroy()
    }
    
    const ctx = canvas.getContext('2d')
    const data = Object.values(useTypes).filter(use => use.share > 0)
    
    const colors = [
        '#3B82F6', '#10B981', '#F59E0B', '#EF4444', '#8B5CF6', 
        '#EC4899', '#14B8A6', '#F97316', '#6366F1', '#84CC16'
    ]
    
    window.useTypesDistributionChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: data.map(use => use.name),
            datasets: [{
                data: data.map(use => use.share),
                backgroundColor: data.map((use, index) => colors[index % colors.length]),
                borderColor: data.map((use, index) => colors[index % colors.length]),
                borderWidth: 2,
                hoverOffset: 4
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'bottom',
                    rtl: true,
                    labels: {
                        font: {
                            family: 'Cairo, sans-serif',
                            size: 12
                        },
                        generateLabels: function(chart) {
                            const datasets = chart.data.datasets
                            const labels = chart.data.labels
                            return labels.map((label, i) => ({
                                text: label,
                                fillStyle: datasets[0].backgroundColor[i],
                                strokeStyle: datasets[0].borderColor[i],
                                lineWidth: datasets[0].borderWidth,
                                hidden: false,
                                index: i
                            }))
                        }
                    }
                },
                tooltip: {
                    rtl: true,
                    titleFont: {
                        family: 'Cairo, sans-serif'
                    },
                    bodyFont: {
                        family: 'Cairo, sans-serif'
                    },
                    callbacks: {
                        label: function(context) {
                            const percentage = context.raw.toFixed(1)
                            return `${context.label}: ${percentage}% من المشروع`
                        }
                    }
                }
            }
        }
    })
}

