// Analyze parking situation
function analyzeParkingSituation() {
    // Calculate requirements from parkingData
    let totalRequired = 0
    if (parkingData && parkingData.analysis && parkingData.analysis.breakdown) {
        totalRequired = Object.values(parkingData.analysis.breakdown).reduce((sum, req) => {
            return sum + (req.required || 0)
        }, 0)
        
        // Add visitor parking if exists
        if (parkingData.analysis.visitorParking) {
            totalRequired += parkingData.analysis.visitorParking
        }
    }
    
    // Calculate supply
    let totalSupply = 0
    if (parkingData && parkingData.supply) {
        totalSupply = (parkingData.supply.ground.count || 0) + 
                     (parkingData.supply.aboveGround.count || 0) + 
                     (parkingData.supply.basement.count || 0)
    }
    
    const surplus = Math.max(0, totalSupply - totalRequired)
    const deficit = Math.max(0, totalRequired - totalSupply)
    const utilizationRate = totalSupply > 0 ? (totalRequired / totalSupply) * 100 : 0
    
    return {
        required: totalRequired,
        supply: totalSupply,
        surplus: surplus,
        deficit: deficit,
        utilizationRate: utilizationRate
    }
}

// Create parking requirements pie chart
function createParkingRequirementsChart() {
    const canvas = document.getElementById('parkingRequirementsChart')
    if (!canvas) {
        console.error('❌ لم يتم العثور على عنصر parkingRequirementsChart')
        return
    }
    
    console.log('✅ إنشاء رسم احتياجات المواقف البياني...')
    
    const ctx = canvas.getContext('2d')
    
    // Destroy existing chart safely
    if (window.parkingRequirementsChart && typeof window.parkingRequirementsChart.destroy === 'function') {
        try {
            window.parkingRequirementsChart.destroy()
        } catch (e) {
            console.log('Chart destroy failed, continuing...')
        }
    }
    
    const breakdown = parkingData.analysis.breakdown || {}
    const labels = Object.values(breakdown).map(req => req.details.split(':')[0])
    const data = Object.values(breakdown).map(req => req.required)
    const colors = ['#3B82F6', '#8B5CF6', '#F97316', '#10B981']
    
    window.parkingRequirementsChart = new Chart(ctx, {
        type: 'doughnut',
        data: {
            labels: labels,
            datasets: [{
                data: data,
                backgroundColor: colors,
                borderColor: '#ffffff',
                borderWidth: 3,
                hoverBorderWidth: 4,
                hoverOffset: 8,
                cutout: '60%' // This creates the doughnut hole
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
                legend: {
                    position: 'bottom',
                    labels: {
                        padding: 20,
                        usePointStyle: true,
                        font: {
                            size: 13,
                            weight: '500'
                        },
                        boxWidth: 15,
                        boxHeight: 15
                    }
                },
                tooltip: {
                    backgroundColor: 'rgba(0, 0, 0, 0.8)',
                    titleFont: {
                        size: 14,
                        weight: 'bold'
                    },
                    bodyFont: {
                        size: 13
                    },
                    padding: 12,
                    cornerRadius: 8,
                    callbacks: {
                        label: function(context) {
                            const total = context.dataset.data.reduce((a, b) => a + b, 0)
                            const percentage = ((context.parsed * 100) / total).toFixed(1)
                            return `${context.label}: ${context.parsed.toLocaleString('en-US')} موقف (${percentage}%)`
                        }
                    }
                }
            },
            layout: {
                padding: 20
            }
        }
    })
}

