// Update parking requirements summary display
function updateParkingRequirementsSummary() {
    const summaryElement = document.getElementById('parkingRequirementsSummary')
    if (!summaryElement) return
    
    const breakdown = parkingData.analysis.breakdown || {}
    const visitorParking = parkingData.analysis.visitorParking || 0
    
    let totalRequired = Object.values(breakdown).reduce((sum, item) => sum + (item.required || 0), 0)
    
    let html = `
        <div class="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-4">
    `
    
    // Requirements by use type - use live uses data
    Object.keys(breakdown).forEach(useId => {
        const item = breakdown[useId]
        const useData = usesData[useId]
        
        // ✅ تخطي الاستخدامات التي لا تتطلب مواقف
        if (!useData || useData.share === 0 || item.requiresParking === false) return
        
        // Get display name from uses system
        const displayName = useData.name || useData.nameEn || useId
        const displayIcon = useData.icon || '📋'
        
        html += `
            <div class="bg-white/5 backdrop-filter backdrop-blur-sm/5 backdrop-filter backdrop-blur-sm rounded-lg p-4 border border-emerald-400/30">
                <div class="text-sm font-medium text-white/80 mb-1 flex items-center">
                    <span class="mr-2">${displayIcon}</span>
                    ${displayName}
                </div>
                <div class="text-xl font-bold text-emerald-200">${Math.round(item.required || 0)}</div>
                <div class="text-xs text-white/70">مواقف</div>
                <div class="text-xs text-blue-500 mt-1">
                    ${item.method === 'units' ? `حسب الوحدات (${item.rate || 0} موقف/وحدة)` : 
                      item.method === 'custom' ? 'حساب تفصيلي' :
                      `حسب المساحة (${item.rate || 0} م²/موقف)`}
                </div>
                ${item.method === 'area' && item.areaType ? `
                <div class="text-xs text-white/60 mt-0.5">
                    ${item.areaType === 'GLA' ? 'GLA للاستخدام' : 
                      item.areaType === 'GFA' ? 'GFA للاستخدام' : 
                      item.areaType === 'totalGLA' ? 'إجمالي GLA' :
                      item.areaType === 'totalGFA' ? 'إجمالي GFA' :
                      'مساحة مخصصة'}
                </div>
                ` : ''}
                ${item.method === 'custom' && item.customUseId && usesData[item.customUseId] ? `
                <div class="text-xs text-purple-500 mt-0.5">
                    من: ${usesData[item.customUseId].icon} ${usesData[item.customUseId].name}
                </div>
                ` : ''}
            </div>
        `
    })
    
    html += `
        </div>
        
        <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div class="bg-blue-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-blue-100 mb-1">إجمالي المواقف الأساسية</div>
                <div class="text-2xl font-bold text-blue-200">${totalRequired}</div>
            </div>
            
            <div class="bg-purple-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-purple-100 mb-1">مواقف الزوار</div>
                <div class="text-2xl font-bold text-purple-200">${visitorParking}</div>
            </div>
            
            <div class="bg-emerald-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-emerald-100 mb-1">إجمالي الاحتياجات</div>
                <div class="text-2xl font-bold text-emerald-200">${totalRequired + visitorParking}</div>
            </div>
        </div>
    `
    
    summaryElement.innerHTML = html
}

// Update parking supply summary display
function updateParkingSupplySummary() {
    const summaryElement = document.getElementById('parkingSupplySummary')
    if (!summaryElement) return
    
    const supply = parkingData.supply || {}
    const ground = supply.ground || { count: 0 }
    const aboveGround = supply.aboveGround || { count: 0 }
    const basement = supply.basement || { count: 0 }
    
    const totalSupply = ground.count + aboveGround.count + basement.count
    
    const html = `
        <div class="grid grid-cols-1 lg:grid-cols-4 gap-4">
            <div class="bg-white/5 backdrop-filter backdrop-blur-sm/8 rounded-lg p-4">
                <div class="text-sm font-medium text-white mb-1">المواقف الأرضية</div>
                <div class="text-2xl font-bold text-white/80">${ground.count}</div>
                <div class="text-xs text-white/70">${ground.floors || 0} طابق</div>
            </div>
            
            <div class="bg-blue-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-blue-100 mb-1">المواقف العلوية</div>
                <div class="text-2xl font-bold text-blue-200">${aboveGround.count}</div>
                <div class="text-xs text-blue-500">${aboveGround.floors || 0} طابق</div>
            </div>
            
            <div class="bg-purple-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-purple-100 mb-1">مواقف القبو</div>
                <div class="text-2xl font-bold text-purple-200">${basement.count}</div>
                <div class="text-xs text-purple-500">${basement.levels || 0} مستوى</div>
            </div>
            
            <div class="bg-emerald-500/25 rounded-lg p-4">
                <div class="text-sm font-medium text-emerald-100 mb-1">إجمالي المعروض</div>
                <div class="text-2xl font-bold text-emerald-200">${totalSupply}</div>
                <div class="text-xs text-emerald-300">موقف</div>
            </div>
        </div>
    `
    
    summaryElement.innerHTML = html
}

