/**
 * تكامل المكون 7 مع النظام - دوال القراءة من المكونات السابقة
 */

/**
 * قراءة بيانات مساحة الأرض من المكون 1
 */
function getLandAreaFromComponent1() {
    try {
        const landAreaElement = document.getElementById('landArea')
        const landArea = parseFloat(landAreaElement?.value || '0')
        console.log(`🏞️ مساحة الأرض من المكون 1: ${landArea.toLocaleString('en-US')} م²`)
        return landArea
    } catch (error) {
        console.error('❌ خطأ في قراءة مساحة الأرض من المكون 1:', error)
        return 0 // عدم فرض قيمة افتراضية - الحفاظ على قيم المستخدم
    }
}

/**
 * قراءة تكلفة البناء الإجمالية من المكونات 2-4 (الأدوار + التكاليف + الاستخدامات)
 */
function getConstructionCostFromComponents() {
    try {
        // 🔧 استخدام دالة الحساب الموحدة المُحدثة بدلاً من الحساب المنفصل
        const totalConstructionCost = calculateTotalCostUnified()
        
        console.log(`🏗️ [getConstructionCostFromComponents] تكلفة البناء من الدالة الموحدة: ${totalConstructionCost.toLocaleString('en-US')} ريال`)
        return totalConstructionCost
        
    } catch (error) {
        console.error('❌ خطأ في حساب تكلفة البناء من المكونات:', error)
        return 0
    }
}

/**
 * قراءة الإيرادات السنوية من المكونات 5-6 (الاستخدامات + الإيرادات)
 */
function getAnnualRevenueFromComponents() {
    try {
        let totalAnnualRevenue = 0
        let totalNetArea = 0
        
        // حساب من بيانات الأدوار مع افتراض متوسط إيجار لكل استخدام
        if (typeof window !== 'undefined' && window.floorsData && Array.isArray(window.floorsData)) {
            window.floorsData.forEach(floor => {
                if (floor.enabled && floor.netArea) {
                    const netArea = parseFloat(floor.netArea || 0)
                    totalNetArea += netArea
                    
                    // متوسط الإيجار حسب نوع الاستخدام (ريال/م²/سنة)
                    let avgRentPerSqm = 300 // قيمة افتراضية
                    
                    switch (floor.usage) {
                        case 'retail':
                            avgRentPerSqm = 500
                            break
                        case 'office':
                            avgRentPerSqm = 350
                            break
                        case 'hotel':
                            avgRentPerSqm = 400
                            break
                        case 'residential':
                            avgRentPerSqm = 250
                            break
                        case 'parking':
                            avgRentPerSqm = 100
                            break
                        case 'services':
                            avgRentPerSqm = 200
                            break
                        default:
                            avgRentPerSqm = 300
                    }
                    
                    // افتراض معدل إشغال 85%
                    const occupancyRate = 0.85
                    const floorRevenue = netArea * avgRentPerSqm * occupancyRate
                    totalAnnualRevenue += floorRevenue
                    
                    console.log(`💰 إيراد ${floor.number || 'دور غير محدد'} (${floor.usage}): ${netArea.toLocaleString('en-US')} م² × ${avgRentPerSqm} ريال/م²/سنة × ${(occupancyRate * 100)}% = ${floorRevenue.toLocaleString('en-US')} ريال/سنة`)
                }
            })
        }
        
        // Fallback: حساب من مساحة الأرض × معامل متوسط
        if (totalAnnualRevenue === 0) {
            const landArea = getLandAreaFromComponent1()
            const avgRevenuePerLandSqm = 300 // ريال لكل متر مربع أرض سنوياً
            totalAnnualRevenue = landArea * avgRevenuePerLandSqm
        }
        
        console.log(`💰 إجمالي الإيرادات السنوية: ${totalAnnualRevenue.toLocaleString('en-US')} ريال/سنة (من ${totalNetArea.toLocaleString('en-US')} م² مساحة صافية)`)
        return totalAnnualRevenue
        
    } catch (error) {
        console.error('❌ خطأ في حساب الإيرادات السنوية من المكونات:', error)
        return 15000000 // قيمة افتراضية
    }
}

/**
 * حساب إجمالي تكلفة المشروع (أرض + بناء + تمويل)
 */
function getTotalProjectCost() {
    try {
        // 🔧 استخدام الدوال الموحدة المُحدثة للحصول على قيم دقيقة
        const constructionCost = calculateTotalCostUnified() // بدلاً من getConstructionCostFromComponents()
        const landCost = calculateLandCost()
        
        // تكاليف التمويل من معدل الفائدة المُدخل
        const interestRateInput = document.getElementById('interestRate')
        const financingCostPercentage = interestRateInput ? (parseFloat(interestRateInput.value) || 5.0) / 100 : 0.05
        const baseTotalCost = landCost + constructionCost
        const financingCost = baseTotalCost * financingCostPercentage
        
        const totalProjectCost = baseTotalCost + financingCost
        
        console.log(`💰 [getTotalProjectCost] إجمالي تكلفة المشروع المُحدث:`)
        console.log(`   🏞️ تكلفة الأرض: ${landCost.toLocaleString('en-US')} ريال`)
        console.log(`   🏗️ تكلفة البناء: ${constructionCost.toLocaleString('en-US')} ريال`)
        console.log(`   💳 تكاليف التمويل: ${financingCost.toLocaleString('en-US')} ريال`)
        console.log(`   📊 الإجمالي: ${totalProjectCost.toLocaleString('en-US')} ريال`)
        
        console.log('✅ [getTotalProjectCost] تم حساب إجمالي تكلفة المشروع بنجاح باستخدام الدوال الموحدة')
        
        return {
            landCost,
            constructionCost,
            financingCost,
            totalCost: totalProjectCost
        }
        
    } catch (error) {
        console.error('❌ خطأ في حساب إجمالي تكلفة المشروع:', error)
        return {
            landCost: 15000000,
            constructionCost: 50000000,
            financingCost: 3250000,
            totalCost: 68250000
        }
    }
}

