/**
 * تحديث عناصر واجهة المستخدم في قسم التكامل
 */
function updateIntegrationUIElements(landArea, constructionCost, annualRevenue, projectCostBreakdown) {
    try {
        // تحديث مساحة الأرض
        const landAreaElement = document.getElementById('landAreaIntegrationValue')
        if (landAreaElement) {
            landAreaElement.textContent = `${(landArea || 0).toLocaleString('en-US')} م²`
        }
        
        const landCostElement = document.getElementById('landAreaCostValue')
        if (landCostElement) {
            landCostElement.textContent = `تكلفة: ${(projectCostBreakdown?.landCost || 0).toLocaleString('en-US')} ريال`
        }
        
        // تحديث تكلفة التطوير باستخدام الدالة الدقيقة
        const developmentCost = calculateAccurateTotalCosts()
        const constructionCostElement = document.getElementById('constructionCostIntegrationValue')
        if (constructionCostElement) {
            constructionCostElement.textContent = `${(developmentCost || 0).toLocaleString('en-US')} ريال`
            console.log('🏗️ تم تحديث تكلفة التطوير:', developmentCost.toLocaleString('en-US'), 'ريال')
        }
        
        const costPerSqmElement = document.getElementById('costPerSqmValue')
        if (costPerSqmElement) {
            const gfa = landArea * getProjectFAR()
            const costPerSqm = gfa > 0 ? developmentCost / gfa : 0
            costPerSqmElement.textContent = `للمتر المربع: ${(costPerSqm || 0).toLocaleString('en-US', {maximumFractionDigits: 0})} ريال`
        }
        
        // تحديث الإيرادات
        const revenueElement = document.getElementById('revenueIntegrationValue')
        if (revenueElement) {
            revenueElement.textContent = `${(annualRevenue || 0).toLocaleString('en-US')} ريال/سنة`
        }
        
        const revenuePerSqmElement = document.getElementById('revenuePerSqmValue')
        if (revenuePerSqmElement) {
            const revenuePerSqm = landArea > 0 ? annualRevenue / landArea : 0
            revenuePerSqmElement.textContent = `للمتر المربع: ${(revenuePerSqm || 0).toLocaleString('en-US', {maximumFractionDigits: 0})} ريال/سنة`
        }
        
        // تحديث إجمالي تكلفة المشروع
        const totalCostElement = document.getElementById('totalProjectCostValue')
        if (totalCostElement) {
            totalCostElement.textContent = `${(projectCostBreakdown?.totalCost || 0).toLocaleString('en-US')} ريال`
        }
        
        const breakdownElement = document.getElementById('projectCostBreakdownValue')
        if (breakdownElement) {
            const totalCost = projectCostBreakdown?.totalCost || 0
            const landPercentage = totalCost > 0 ? ((projectCostBreakdown?.landCost || 0) / totalCost * 100).toFixed(1) : 0
            const constructionPercentage = totalCost > 0 ? ((projectCostBreakdown?.constructionCost || 0) / totalCost * 100).toFixed(1) : 0
            const financingPercentage = totalCost > 0 ? ((projectCostBreakdown?.financingCost || 0) / totalCost * 100).toFixed(1) : 0
            breakdownElement.textContent = `أرض (${landPercentage}%) + بناء (${constructionPercentage}%) + تمويل (${financingPercentage}%)`
        }
        
        // تحديث إجمالي الاستثمار في المعاملات باستخدام المعادلة الجديدة
        const totalInvestmentElement = document.getElementById('totalInvestment')
        if (totalInvestmentElement) {
            // 🛡️ PROTECTION: منع التحديثات المتداخلة
            if (isUpdatingTotalInvestment) {
                console.log('⏸️ [updateComponent7Integration] تم تجاهل التحديث - تحديث آخر قيد التنفيذ')
                return
            }
            isUpdatingTotalInvestment = true
            
            // 🔄 CRITICAL FIX: إبطال cache قبل الحساب لتجنب القيم القديمة
            invalidateCalculationCache()
            console.log('🔄 تم إبطال cache قبل حساب الاستثمار لتجنب القيم المؤقتة')
            
            // استخدام المعادلة الجديدة: إجمالي الاستثمار = إجمالي التكلفة + تكلفة الأرض
            const integrationData = getIntegrationData()
            const totalInvestmentValue = integrationData.totalProjectCost // هذا يستخدم المعادلة الصحيحة
            
            // ✅ إجمالي الاستثمار محسوب بشكل صحيح
            
            // إصلاح: استخدام القيمة الرقمية فقط (بدون toLocaleString في input)
            totalInvestmentElement.value = Math.round(totalInvestmentValue).toString()
            
            console.log('✅ [updateComponent7Integration] تم تحديث إجمالي الاستثمار: ' + (totalInvestmentValue || 0).toLocaleString('en-US') + ' ريال')
        } else {
            console.error('❌ لم يتم العثور على عنصر totalInvestment في HTML!')
        }
        
    } catch (error) {
        console.error('❌ خطأ في تحديث عناصر واجهة المستخدم:', error)
    } finally {
        // إعادة تعيين العلم في جميع الأحوال
        isUpdatingTotalInvestment = false
    }
}

