// المهمة 1: إنشاء دالة calculateIntegratedAnnualRevenue() لقراءة الإيرادات من النظام المتقدم
function calculateIntegratedAnnualRevenue() {
    console.log('💰 بدء حساب الإيرادات السنوية المتكاملة...')
    
    try {
        let totalAnnualRevenue = 0
        
        // قراءة البيانات من نظام إدارة الإيرادات المتقدم
        if (window.revenuesData && typeof window.revenuesData === 'object') {
            console.log('📊 النظام المتقدم متاح - قراءة البيانات من revenuesData')
            
            // الإيرادات الإيجارية من الوحدات الفرعية
            if (window.revenuesData.rentalRevenues && window.revenuesData.rentalRevenues.subUnits) {
                Object.values(window.revenuesData.rentalRevenues.subUnits).forEach(subUnit => {
                    if (subUnit && typeof subUnit === 'object') {
                        const subUnitRevenue = getSubUnitRentalTotal(subUnit)
                        totalAnnualRevenue += subUnitRevenue
                        console.log(`  📈 ${subUnit.subUnitName}: ${subUnitRevenue.toLocaleString('en-US')} ريال`)
                    }
                })
            }
            
            // الإيرادات الإضافية
            if (window.revenuesData.additionalRevenues && window.revenuesData.additionalRevenues.revenues) {
                window.revenuesData.additionalRevenues.revenues.forEach(revenue => {
                    if (revenue && revenue.amount > 0) {
                        totalAnnualRevenue += revenue.amount
                        console.log(`  💎 ${revenue.name}: ${revenue.amount.toLocaleString('en-US')} ريال`)
                    }
                })
            }
            
            // إيرادات تحسين الإيرادات (Revenue Optimization)
            if (window.revenuesData.revenueOptimization && window.revenuesData.revenueOptimization.strategies) {
                let baseRevenue = totalAnnualRevenue
                let totalOptimizationImpact = 0
                
                window.revenuesData.revenueOptimization.strategies.forEach(strategy => {
                    if (strategy && strategy.impact > 0) {
                        totalOptimizationImpact += strategy.impact
                        console.log(`  📊 ${strategy.name}: +${strategy.impact}%`)
                    }
                })
                
                // Apply cumulative optimization impact
                const optimizationBonus = baseRevenue * (totalOptimizationImpact / 100)
                totalAnnualRevenue += optimizationBonus
                console.log(`  🎯 إجمالي تحسين الإيرادات: +${optimizationBonus.toLocaleString('en-US')} ريال`)
            }
            
        } else {
            console.warn('⚠️ نظام إدارة الإيرادات غير متاح - استخدام الحساب التقليدي')
            
            // Fallback: استخدام حساب تقليدي بناءً على GLA
            const totalGLA = calculateTotalGLA()
            const averageRentPerSqm = 400 // متوسط الإيجار ريال/م²/سنة
            totalAnnualRevenue = totalGLA * averageRentPerSqm
            console.log(`  📐 المساحة المؤجرة: ${totalGLA.toLocaleString('en-US')} م²`)
            console.log(`  💰 متوسط الإيجار: ${averageRentPerSqm} ريال/م²/سنة`)
        }
        
        console.log(`✅ إجمالي الإيرادات السنوية المتكاملة: ${totalAnnualRevenue.toLocaleString('en-US')} ريال`)
        return totalAnnualRevenue
        
    } catch (error) {
        console.error('❌ خطأ في حساب الإيرادات المتكاملة:', error)
        
        // Emergency fallback
        const totalGLA = calculateTotalGLA()
        const fallbackRevenue = totalGLA * 300 // حد أدنى متحفظ
        console.log(`🆘 استخدام القيمة الاحتياطية: ${fallbackRevenue.toLocaleString('en-US')} ريال`)
        return fallbackRevenue
    }
}

/**
 * حساب النفقات التشغيلية المتطورة المرتبطة مباشرة بنظام إدارة OPEX
 * هذه الدالة تقرأ القيم الحقيقية من واجهة المستخدم لنظام OPEX
 */
function calculateAdvancedOpex(yearlyRevenue, totalGLA) {
    console.log('🔧 ================ بدء حساب النفقات التشغيلية من نظام OPEX =================')
console.log('🔧 calculateAdvancedOpex() تم استدعاؤها!')
    
    try {
        let generalOpex = 0
        let variableOpex = 0
        let reservesTotal = 0
        
        console.log('📋 قراءة القيم من نظام إدارة OPEX...')
        
        // 1. النفقات العامة - قراءة من واجهة المستخدم
        generalOpex = readOpexFromUI('generalOpex', yearlyRevenue)
        console.log(`  💰 النفقات العامة: ${generalOpex.toLocaleString('en-US')} ريال`)
        
        // 2. النفقات المتغيرة - قراءة من واجهة المستخدم
        variableOpex = readOpexFromUI('variableOpex', yearlyRevenue, totalGLA)
        console.log(`  📈 النفقات المتغيرة: ${variableOpex.toLocaleString('en-US')} ريال`)
        
        // 3. الاحتياطيات والطوارئ - قراءة من واجهة المستخدم
        const preliminaryTotal = generalOpex + variableOpex
        reservesTotal = readOpexFromUI('emergencyReserve', yearlyRevenue, totalGLA, preliminaryTotal)
        console.log(`  🛡️ الاحتياطيات والطوارئ: ${reservesTotal.toLocaleString('en-US')} ريال`)
        
        // 4. الإجمالي
        const totalOpex = generalOpex + variableOpex + reservesTotal
        
        const breakdown = {
            general: generalOpex,
            variable: variableOpex,
            reserves: reservesTotal,
            total: totalOpex,
            
            // تفاصيل إضافية
            perSqm: totalGLA > 0 ? totalOpex / totalGLA : 0,
            asPercentageOfRevenue: yearlyRevenue > 0 ? (totalOpex / yearlyRevenue) * 100 : 0
        }
        
        console.log(`  💰 النفقات العامة: ${generalOpex.toLocaleString('en-US')} ريال`)
        console.log(`  📈 النفقات المتغيرة: ${variableOpex.toLocaleString('en-US')} ريال`)
        console.log(`  🛡️ الاحتياطيات: ${reservesTotal.toLocaleString('en-US')} ريال`)
        console.log(`  📊 إجمالي OPEX: ${totalOpex.toLocaleString('en-US')} ريال`)
        
        // 🚨 CRITICAL: تصدير الدالة لـ window لتستخدمها من أي مكان
        window.calculateAdvancedOpex = calculateAdvancedOpex
        
        return breakdown
        
    } catch (error) {
        console.error('❌ خطأ في حساب النفقات التشغيلية المتطورة:', error)
        
        // 🚨 CRITICAL FIX: إذا صفر المستخدم القيم، يجب أن تكون النتيجة 0 وليس القيم الافتراضية
        console.error('🚨 CRITICAL: فشل في قراءة OPEX من الواجهة!')
        console.error('🚨 CRITICAL: هذا يعني أن نظام OPEX غير محمل أو معطل!')
        console.error('🚨 CRITICAL: سيتم إعطاء قيمة 0 لجميع النفقات')
        
        return {
            general: 0,
            usageBased: 0,
            variable: 0,
            reserves: 0,
            total: 0,
            perSqm: 0,
            asPercentageOfRevenue: 0
        }
    }
}

/**
 * قراءة قيم النفقات التشغيلية مباشرة من واجهة المستخدم (نظام إدارة OPEX)
 * هذه الدالة تقرأ القيم الحقيقية المدخلة في نظام OPEX وتحسبها
 */
function readOpexFromUI(categoryId, yearlyRevenue = 0, totalGLA = 0, preliminaryTotal = 0) {
    console.log(`🔍 ================ قراءة قيم ${categoryId} من واجهة المستخدم =================`)
console.log(`🔍 readOpexFromUI() تم استدعاؤها للفئة: ${categoryId}`)
    
    try {
        let categoryTotal = 0
        
        // 🔍 DEBUG: فحص توفر العناصر
        const elementsSelector = `[data-category="${categoryId}"]`
        const availableElements = document.querySelectorAll(elementsSelector)
        console.log(`🔍 [DEBUG] البحث عن عناصر ${categoryId}: وجد ${availableElements.length} عنصر`)
        
        if (availableElements.length === 0) {
            console.warn(`⚠️ [DEBUG] لم يتم العثور على أي عناصر لـ ${categoryId} - سيعطي قيمة 0`)
            console.warn(`⚠️ [DEBUG] هذا يعني أن النظام لا يقرأ من نظام OPEX، بل من fallback`)
            return 0
        }
        
        if (categoryId === 'generalOpex') {
            // قراءة النفقات العامة من الواجهة
            const generalExpenses = document.querySelectorAll('[data-category="generalOpex"] input[data-expense-amount]')
            generalExpenses.forEach(input => {
                const value = parseFloat(input.value) || 0
                const expenseId = input.getAttribute('data-expense-id')
                const isPercentage = input.getAttribute('data-is-percentage') === 'true'
                
                if (isPercentage && yearlyRevenue > 0) {
                    // نسبة من الإيرادات
                    const amount = yearlyRevenue * (value / 100)
                    categoryTotal += amount
                    console.log(`    💰 ${expenseId}: ${value}% من الإيرادات = ${amount.toLocaleString('en-US')} ريال`)
                } else {
                    // مبلغ ثابت
                    categoryTotal += value
                    console.log(`    💰 ${expenseId}: ${value.toLocaleString('en-US')} ريال`)
                }
            })
            
        } else if (categoryId === 'variableOpex') {
            // قراءة النفقات المتغيرة من الواجهة
            const variableExpenses = document.querySelectorAll('[data-category="variableOpex"] input[data-variable-rate]')
            variableExpenses.forEach(input => {
                const rate = parseFloat(input.value) || 0
                const variableId = input.getAttribute('data-variable-id')
                
                if (variableId === 'revenue_percentage' && yearlyRevenue > 0) {
                    const amount = yearlyRevenue * (rate / 100)
                    categoryTotal += amount
                    console.log(`    📈 ${variableId}: ${rate}% من الإيرادات = ${amount.toLocaleString('en-US')} ريال`)
                } else if (variableId === 'area_based' && totalGLA > 0) {
                    const amount = totalGLA * rate
                    categoryTotal += amount
                    console.log(`    📈 ${variableId}: ${rate} × ${totalGLA.toLocaleString('en-US')} = ${amount.toLocaleString('en-US')} ريال`)
                }
            })
            
        } else if (categoryId === 'emergencyReserve') {
            // قراءة الاحتياطيات من الواجهة
            const reserveInputs = document.querySelectorAll('[data-category="emergencyReserve"] input[data-reserve-rate]')
            reserveInputs.forEach(input => {
                const rate = parseFloat(input.value) || 0
                const reserveId = input.getAttribute('data-reserve-id')
                
                if (reserveId === 'emergency_fund' && preliminaryTotal > 0) {
                    const amount = preliminaryTotal * (rate / 100)
                    categoryTotal += amount
                    console.log(`    🛡️ ${reserveId}: ${rate}% من المجموع الأولي = ${amount.toLocaleString('en-US')} ريال`)
                } else if (reserveId === 'major_maintenance') {
                    const constructionCost = calculateTotalConstructionCost() || 50000000
                    const amount = constructionCost * (rate / 100)
                    categoryTotal += amount
                    console.log(`    🛡️ ${reserveId}: ${rate}% من قيمة المبنى = ${amount.toLocaleString('en-US')} ريال`)
                } else if (reserveId === 'vacancy_allowance' && yearlyRevenue > 0) {
                    const amount = yearlyRevenue * (rate / 100)
                    categoryTotal += amount
                    console.log(`    🛡️ ${reserveId}: ${rate}% من الإيرادات = ${amount.toLocaleString('en-US')} ريال`)
                }
            })
        }
        
        console.log(`📊 إجمالي ${categoryId}: ${categoryTotal.toLocaleString('en-US')} ريال`)
        return categoryTotal
        
    } catch (error) {
        console.error(`❌ خطأ في قراءة ${categoryId} من الواجهة:`, error)
        
        // 🚨 CRITICAL FIX: لا نريد العودة للقيم الافتراضية - يجب أن نعكس قيم الواجهة الحقيقية
        // إذا كان المستخدم صفّر القيم، يجب أن تكون النتيجة 0
        console.warn(`⚠️ فشل في قراءة ${categoryId} - العودة للقيمة 0 لتعكس حالة الواجهة`)
        return 0
    }
}


// دالة مساعدة لحساب القسط السنوي (Annuity)
function calculateAnnuity(principal, rate, periods) {
    if (rate === 0) return principal / periods
    return principal * (rate * Math.pow(1 + rate, periods)) / (Math.pow(1 + rate, periods) - 1)
}



