// دالة حساب تكلفة الأرض
function calculateLandCost() {
    const landArea = parseFloat(document.getElementById('landArea')?.value || '10000')
    const landAcquisitionMethod = document.querySelector('input[name="landAcquisition"]:checked')?.value || 'purchase'
    
    let landCost = 0
    
    switch (landAcquisitionMethod) {
        case 'purchase':
            const purchasePrice = parseFloat(document.getElementById('purchasePrice')?.value || '0')
            landCost = landArea * purchasePrice
            break
        case 'lease':
            // تكلفة إجمالية للإيجار مع الزيادات التراكمية
            const annualRent = parseFloat(document.getElementById('annualRent')?.value || '200')
            const leaseTerm = parseFloat(document.getElementById('leaseTerm')?.value || '25')
            const rentIncreasePercentage = parseFloat(document.getElementById('rentIncreasePercentage')?.value || '0')
            const rentIncreaseFrequency = parseFloat(document.getElementById('rentIncreaseFrequency')?.value || '0')
            
            // استخدام دالة حساب الإيجار التراكمي
            if (typeof window.calculateCumulativeRent === 'function') {
                const leaseCalculation = window.calculateCumulativeRent(
                    annualRent,
                    landArea,
                    leaseTerm,
                    rentIncreasePercentage,
                    rentIncreaseFrequency
                )
                landCost = leaseCalculation.total
                console.log('🏞️ [calculateLandCost] Lease with increases:', {
                    baseRent: annualRent,
                    term: leaseTerm,
                    increases: leaseCalculation.numberOfIncreases,
                    total: landCost.toLocaleString('en-US')
                })
            } else {
                // الحساب البسيط كاحتياط
                landCost = landArea * annualRent * leaseTerm
            }
            break
        case 'partnership':
            // حساب تكلفة الأرض في حالة الشراكة
            const landValuePerSqm = parseFloat(document.getElementById('landValuePerSqm')?.value || '2000')
            const partnerContribution = document.getElementById('partnerContribution')?.value || 'land'
            const partnerCashContribution = parseFloat(document.getElementById('partnerCashContribution')?.value || '0')
            
            // استخدام دالة حساب تفاصيل الشراكة
            if (typeof window.calculatePartnershipDetails === 'function') {
                const partnershipData = window.calculatePartnershipDetails(
                    partnerContribution,
                    landArea,
                    landValuePerSqm,
                    parseFloat(document.getElementById('partnershipShare')?.value || '50'),
                    partnerCashContribution,
                    0, // developerCashContribution
                    0, // totalProjectCost
                    document.getElementById('profitSharingModel')?.value || 'revenue',
                    parseFloat(document.getElementById('managementFeePercentage')?.value || '5')
                )
                
                // تكلفة الأرض للمشروع حسب نوع المساهمة
                landCost = partnershipData.landCostForProject
                
                console.log('🤝 [calculateLandCost] Partnership:', {
                    contributionType: partnerContribution,
                    landValue: partnershipData.landValue.toLocaleString('en-US'),
                    landCostForProject: landCost.toLocaleString('en-US'),
                    partnerContribution: partnershipData.partner.totalContribution.toLocaleString('en-US'),
                    developerContribution: partnershipData.developer.totalContribution.toLocaleString('en-US')
                })
            } else {
                // الحساب البسيط كاحتياط
                landCost = landArea * landValuePerSqm
            }
            break
        default:
            // استخدام بيانات من مكون الاستثمار إن أمكن
            landCost = (typeof investmentData !== 'undefined' && investmentData.landAcquisition) ? 
                landArea * investmentData.landAcquisition.purchasePrice : 0
    }
    
    // 🔧 FIX: إذا كانت النتيجة 0 أو غير منطقية، استخدم القيمة الافتراضية الآمنة
    if (landCost <= 0 || isNaN(landCost)) {
        console.log('🚨 [calculateLandCost] قيمة غير صحيحة، استخدام القيمة الافتراضية')
        // 🚨 RECURSION FIX: استخدام القيمة الافتراضية بدلاً من recursive call
        landCost = 0 // القيمة الافتراضية الآمنة
    }
    
    console.log('🏞️ [calculateLandCost] النتيجة:', {
        landArea,
        method: landAcquisitionMethod,
        landCost: landCost.toLocaleString('en-US'),
        pricePerSqm: (landCost / landArea).toFixed(0)
    })
    
    return landCost
}


