function getUsageOpexCache() {
  if (typeof window !== 'undefined') {
    window.__OPEX_USAGE_CACHE__ = window.__OPEX_USAGE_CACHE__ || {};
    return window.__OPEX_USAGE_CACHE__;
  }
  if (typeof globalThis !== 'undefined') {
    globalThis.__OPEX_USAGE_CACHE__ = globalThis.__OPEX_USAGE_CACHE__ || {};
    return globalThis.__OPEX_USAGE_CACHE__;
  }
  return {};
}

function mergeUsageExpenses(defaultExpenses = [], cachedUsage = null) {
  const previousExpenses = Array.isArray(cachedUsage?.expenses) ? cachedUsage.expenses : [];
  const previousById = new Map(previousExpenses.map((expense) => [expense.id, expense]));

  const merged = (defaultExpenses || []).map((defaultExpense) => {
    const prior = previousById.get(defaultExpense.id);
    const recommendedRate = toNumeric(defaultExpense.rate, 0);
    const persistedRate = toNumericOrNull(prior?.rate);
    const persistedAmount = toNumericOrNull(prior?.amount);
    const recommendedAmount = toNumeric(defaultExpense.amount, 0);

    return {
      ...defaultExpense,
      recommendedRate,
      rate: persistedRate !== null ? persistedRate : recommendedRate,
      amount: persistedAmount !== null ? persistedAmount : recommendedAmount
    };
  });

  previousExpenses.forEach((expense) => {
    if (!merged.some((entry) => entry.id === expense.id)) {
      merged.push({
        ...expense,
        rate: toNumeric(expense.rate, 0),
        amount: toNumeric(expense.amount, 0)
      });
    }
  });

  return merged;
}

