/**
 * حساب ملخص النفقات التشغيلية
 */
function calculateOpexSummary() {
    let generalOpex = 0
    let areaBasedOpex = 0  // استبدال variableOpex بـ areaBasedOpex
    let reservesTotal = 0
    
    // النفقات العامة
    opexData.generalOpex.expenses.forEach(expense => {
        if (expense.amount > 0) {
            generalOpex += expense.amount
        } else if (expense.percentage > 0) {
            // نسبة من الإيرادات (للتسويق مثلاً)
            const totalRevenue = calculateIntegratedAnnualRevenue() || 0
            generalOpex += totalRevenue * (expense.percentage / 100)
        }
    })
    
    // النفقات وفق المساحة - حساب النفقات المتغيرة
    const totalGLA = calculateTotalGLA()
    
    // إضافة النفقات المتغيرة من نوع area_based
    opexData.variableOpex.variables.forEach(variable => {
        if (variable.id === 'area_based') {
            areaBasedOpex += totalGLA * variable.rate
        }
    })
    
    // حساب النفقات المتغيرة الأخرى (غير المرتبطة بالمساحة) للاستخدام في النظام
    const totalRevenue = calculateIntegratedAnnualRevenue() || 0
    let otherVariableOpex = 0
    opexData.variableOpex.variables.forEach(variable => {
        if (variable.id === 'revenue_percentage') {
            otherVariableOpex += totalRevenue * (variable.rate / 100)
        }
    })
    
    // الاحتياطيات
    const preliminaryTotal = generalOpex + areaBasedOpex + otherVariableOpex
    
    opexData.emergencyReserve.reserves.forEach(reserve => {
        if (reserve.id === 'emergency_fund') {
            reservesTotal += preliminaryTotal * (reserve.rate / 100)
        } else if (reserve.id === 'major_maintenance') {
            // نسبة من قيمة المبنى (سنحسبها من التكاليف)
            const constructionCost = calculateTotalConstructionCost() || 50000000 // قيمة افتراضية
            reservesTotal += constructionCost * (reserve.rate / 100)
        } else if (reserve.id === 'vacancy_allowance') {
            reservesTotal += totalRevenue * (reserve.rate / 100)
        }
    })
    
    const totalOpex = generalOpex + areaBasedOpex + otherVariableOpex + reservesTotal
    const opexToRevenueRatio = totalRevenue > 0 ? (totalOpex / totalRevenue) * 100 : 0
    
    // حساب القيم الجديدة المطلوبة - جمع النسب المدخلة مباشرة من البيانات
    
    // 1. مجموع نسب النفقات من إجمالي OPEX - جمع النسب المدخلة مباشرة
    let totalOpexPercentages = 0
    // جمع النسب من النفقات العامة
    opexData.generalOpex.expenses.forEach(expense => {
        if (expense.percentage > 0) {
            totalOpexPercentages += expense.percentage
        }
    })
    // جمع النسب من احتياطي الطوارئ التي تخص OPEX
    opexData.emergencyReserve.reserves.forEach(reserve => {
        if (reserve.id === 'emergency_fund') { // نسبة من إجمالي OPEX
            totalOpexPercentages += reserve.rate
        }
    })
    
    // 2. مجموع نسب النفقات من قيمة المبنى - جمع النسب المدخلة مباشرة
    let opexToBuildingValueRatio = 0
    opexData.emergencyReserve.reserves.forEach(reserve => {
        if (reserve.id === 'major_maintenance') { // نسبة من قيمة المبنى
            opexToBuildingValueRatio += reserve.rate
        }
    })
    
    // 3. مجموع نسب النفقات من الإيرادات - جمع النسب المدخلة مباشرة
    let opexToRevenueRatioFromData = 0
    // جمع النسب من النفقات المتغيرة
    opexData.variableOpex.variables.forEach(variable => {
        if (variable.id === 'revenue_percentage') { // نسبة من الإيرادات
            opexToRevenueRatioFromData += variable.rate
        }
    })
    // جمع النسب من احتياطي الطوارئ التي تخص الإيرادات
    opexData.emergencyReserve.reserves.forEach(reserve => {
        if (reserve.id === 'vacancy_allowance') { // نسبة من الإيرادات
            opexToRevenueRatioFromData += reserve.rate
        }
    })
    
    // 4. إجمالي المبالغ الثابتة (النفقات العامة + المبالغ الثابتة من النفقات المرتبطة بالاستخدام)
    let totalFixedAmounts = generalOpex // النفقات العامة كلها ثابتة
    
    // المبالغ الثابتة (النفقات العامة فقط)
    
    // إضافة النفقات الثابتة من النفقات المتغيرة (إن وجدت)
    opexData.variableOpex.variables.forEach(variable => {
        if (variable.id === 'fixed_amount' && variable.amount > 0) {
            totalFixedAmounts += variable.amount
        }
    })
    
    return {
        generalOpex,
        areaBasedOpex,  // استبدال variableOpex بـ areaBasedOpex
        reservesTotal,
        totalOpex,
        opexToRevenueRatio,  // النسبة المحسوبة من الإيرادات (للتحليل)
        totalOpexPercentages,  // مجموع النسب المدخلة من إجمالي OPEX
        opexToBuildingValueRatio,  // مجموع النسب المدخلة من قيمة المبنى
        opexToRevenueRatioFromData: opexToRevenueRatioFromData,  // مجموع النسب المدخلة من الإيرادات
        totalFixedAmounts
    }
}

/**
 * حساب GLA لاستخدام معين
 */
function calculateUsageGLA(useId) {
    const useData = usesData[useId]
    if (!useData || useData.share === 0) return 0
    
    const totalGFA = calculateTotalGFA()
    const useGFA = totalGFA * (useData.share / 100)
    const useGLA = useGFA * (useData.efficiency / 100)
    
    return useGLA
}

