// إضافة أحداث Enter للجداول الموجودة
function addEnterKeyListenersToExistingTables() {
    console.log('⚡ بدء إضافة أحداث Enter للجداول الموجودة...')
    
    try {
        // البحث عن جميع حقول input من نوع number في جداول التكاليف
        const costInputs = document.querySelectorAll('#costsGrid input[type="number"]')
        console.log(`🔍 وجدت ${costInputs.length} حقل input في جداول التكاليف`)
        
        if (costInputs.length === 0) {
            console.warn('⚠️ لم يتم العثور على أي حقول input في #costsGrid')
            return 0
        }
        
        let addedCount = 0
        
        costInputs.forEach((input, index) => {
            // التحقق من وجود oninput handler
            const oninputValue = input.getAttribute('oninput')
            console.log(`📋 حقل ${index + 1}: oninput = "${oninputValue}"`)
            
            if (oninputValue && oninputValue.includes('update') && oninputValue.includes('Field')) {
                // التحقق من عدم وجود حدث onkeypress مسبقاً
                if (!input.hasAttribute('onkeypress')) {
                    // إضافة حدث Enter بناءً على oninput الموجود
                    const enterHandler = `if(event.key === 'Enter') { ${oninputValue}; console.log('⚡ Enter pressed - immediate calculation update'); }`
                    input.setAttribute('onkeypress', enterHandler)
                    addedCount++
                    console.log(`✅ أضيف Enter إلى حقل ${index + 1}: ${input.value || 'فارغ'}`)
                } else {
                    console.log(`⏭️ حقل ${index + 1} يحتوي على onkeypress بالفعل`)
                }
            } else {
                console.log(`❌ حقل ${index + 1} لا يحتوي على oninput مناسب`)
            }
        })
        
        console.log(`✅ تم إضافة أحداث Enter إلى ${addedCount} حقل من أصل ${costInputs.length}`)
        return addedCount
        
    } catch (error) {
        console.error('❌ خطأ في إضافة أحداث Enter:', error)
        return 0
    }
}

