/**
 * نظام حماية الحقول المشتقة المعمم - يدعم حقول متعددة
 */
const __PROGRAMMATIC_WRITES__ = new Set();

/**
 * تعيين قيمة حقل مشتق مع الحماية من إطلاق الأحداث
 * @param {string} id - معرف الحقل
 * @param {any} value - القيمة الجديدة
 */
function setDerivedField(id, value) {
  const el = document.getElementById(id);
  if (!el) return;
  
  __PROGRAMMATIC_WRITES__.add(id);
  const next = String(value);
  if (el.value !== next) el.value = next;
  __PROGRAMMATIC_WRITES__.delete(id);
}

/**
 * 🎯 1) تحديث بصيغة منسّقة دون أحداث (للعرض فقط)
 * يحافظ على القيمة الرقمية داخليًا، ويعرض بصيغة عربية للمستخدم
 * @param {string} id - معرف الحقل
 * @param {number} value - القيمة الرقمية
 * @param {string} locale - صيغة العرض (افتراضي: ar-SA)
 */
function setDerivedFieldFormatted(id, value, locale = 'en-US') {
  const el = document.getElementById(id);
  if (!el) return;
  
  const raw = String(Math.round(value || 0));
  const pretty = Number(raw).toLocaleString(locale);
  
  __PROGRAMMATIC_WRITES__.add(id);
  // خزّن الرقمي النقي للقراءة البرمجية (مثلاً في data-*)
  el.dataset.numeric = raw;
  if (el.value !== pretty) el.value = pretty;
  __PROGRAMMATIC_WRITES__.delete(id);
}

