/**
 * 🎯 2) منع تكرار ربط الحارس (listener de-dup)
 * حارس محسن لحقل الاستثمار الإجمالي مع ضمان التنفيذ بعد جهوزية DOM
 * ومنع ربط متعدد للمستمعين (SPA/Hot reload safe)
 */
function guardTotalInvestmentInputOnce() {
  const el = document.getElementById('totalInvestment');
  if (!el || el.dataset.guardAttached === '1') return;
  
  // تعيين الحقل للعرض فقط مع دعم إمكانية الوصول
  try { 
    el.readOnly = true; 
    el.setAttribute('aria-readonly', 'true');
  } catch(e) {}

  // معالج أحداث موحد للحماية
  const handler = (ev) => {
    if (__PROGRAMMATIC_WRITE__ || __PROGRAMMATIC_WRITES__.has(ev.target?.id)) {
      ev.stopImmediatePropagation();
      ev.stopPropagation();
    }
  };
  
  // حماية أحداث input و change
  el.addEventListener('input', handler, true);
  el.addEventListener('change', handler, true);
  
  // علّم أن الحارس مُربط لمنع التكرار
  el.dataset.guardAttached = '1';
  
  _logFin.info('🛡️ Guard attached to totalInvestment field (de-duplicated)');
}

// ضمان التنفيذ بعد جهوزية DOM مع منع التكرار
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', () => guardTotalInvestmentInputOnce(), { once: true });
} else {
  guardTotalInvestmentInputOnce();
}

/**
 * مستمع عام لحماية جميع الحقول المشتقة (اختياري ومفيد للمستقبل)
 */
document.addEventListener('input', (ev) => {
  const id = ev.target?.id;
  if (id && __PROGRAMMATIC_WRITES__.has(id)) {
    ev.stopImmediatePropagation();
    ev.stopPropagation();
  }
}, true);

