/**
 * نسخ نوع الاستخدام
 */
function duplicateUseType(useId) {
    console.log('📋 نسخ الاستخدام:', useId)
    
    const originalUse = usesData[useId]
    if (!originalUse) {
        showNotification('الاستخدام غير موجود!', 'error', 3000, 'خطأ')
        return
    }
    
    // اختيار لون جديد للنسخة
    const colors = ['indigo', 'pink', 'teal', 'yellow', 'red', 'cyan', 'emerald', 'amber', 'violet', 'lime']
    const usedColors = Object.values(usesData).map(use => use.color)
    const availableColors = colors.filter(color => !usedColors.includes(color))
    const newColor = availableColors.length > 0 ? availableColors[0] : colors[Math.floor(Math.random() * colors.length)]
    
    // إنشاء نسخة
    const newId = `${originalUse.id}_copy_${Date.now()}`
    const duplicatedUse = {
        ...originalUse,
        id: newId,
        name: `${originalUse.name} - نسخة`,
        nameEn: `${originalUse.nameEn || originalUse.name} - Copy`,
        color: newColor, // لون جديد للتمييز
        share: 0, // إعادة تعيين النسبة لتجنب التضارب
        totalGLA: 0,
        totalUnits: 0,
        isCustom: true, // النسخ دائماً قابلة للتعديل والحذف
        expanded: true, // توسيع تلقائي لسهولة التعديل
        subUnits: originalUse.subUnits.map(sub => ({
            ...sub,
            id: `${newId}_${sub.id.split('_').pop()}`,
            units: 0 // إعادة تعيين عدد الوحدات
        }))
    }
    
    // إضافة النسخة
    usesData[newId] = duplicatedUse
    
    // إعادة رسم النظام
    renderUsesSystem()
    
    // تحديث القوائم المنسدلة في نظام التكاليف فوراً
    updateAllUseTypeDropdowns()
    
    // تحديث نظام المواقف لإضافة الاستخدام المنسوخ
    if (typeof syncParkingWithUses === 'function') {
        syncParkingWithUses()
    }
    
    // تحديث إضافي لضمان التزامن الكامل
    setTimeout(() => {
        updateAllUseTypeDropdowns()
    }, 50)
    
    // إشعار نجاح
    showNotification(`تم نسخ استخدام "${originalUse.name}" بنجاح!`, 'info', 3000, 'نسخ استخدام')
    
    console.log('✅ تم نسخ الاستخدام بنجاح')
}

/**
 * Toggle GLA counting for a specific usage type
 * CRITICAL: This bridges usesData (app.js) with defaultUsageTypes (index.tsx)
 */
/**
 * Toggle GLA counting for usage type
 * Called from checkbox onchange event
 */
function toggleGLACounting(usageId, isChecked) {
    console.log('✅ toggleGLACounting:', usageId, isChecked)
    
    const use = usesData[usageId]
    if (!use) {
        console.error('❌ Use not found:', usageId)
        return
    }
    
    // 1️⃣ Update in usesData (app.js system)
    use.countInGLA = isChecked
    localStorage.setItem('usesData', JSON.stringify(usesData))
    console.log('✅ Updated usesData')
    
    // 2️⃣ Update in defaultUsageTypesSettings (index.tsx system)
    try {
        const savedSettings = localStorage.getItem('defaultUsageTypesSettings')
        let settings = savedSettings ? JSON.parse(savedSettings) : []
        
        // Find and update
        let found = false
        settings = settings.map(type => {
            if (type.id === usageId) {
                type.countInGLA = isChecked
                found = true
            }
            return type
        })
        
        // Create if not found
        if (!found) {
            settings.push({
                id: usageId,
                nameAr: use.name,
                nameEn: use.nameEn || use.name,
                countInGLA: isChecked
            })
        }
        
        localStorage.setItem('defaultUsageTypesSettings', JSON.stringify(settings))
        console.log('✅ Updated defaultUsageTypesSettings')
    } catch (e) {
        console.error('❌ Failed to update defaultUsageTypesSettings:', e)
    }
    
    // 3️⃣ Recalculate netArea for all floors with this usage
    if (window.floorsData && Array.isArray(window.floorsData)) {
        let updatedCount = 0
        window.floorsData.forEach(floor => {
            if (floor.usage === usageId) {
                // Recalculate netArea based on new countInGLA setting
                const serviceArea = floor.calculatedArea * (floor.servicePercentage / 100)
                floor.netArea = isChecked ? (floor.calculatedArea - serviceArea) : 0
                updatedCount++
            }
        })
        
        if (updatedCount > 0) {
            console.log(`🔄 Updated ${updatedCount} floors with usage ${usageId}`)
            localStorage.setItem('floorsData', JSON.stringify(window.floorsData))
            
            // Update floors display immediately
            if (typeof window.updateFloorsDisplay === 'function') {
                window.updateFloorsDisplay()
            }
        }
    }
    
    // 4️⃣ Update calculations and re-render
    if (typeof window.updateAllSummaries === 'function') {
        window.updateAllSummaries()
    }
    
    // 4️⃣ Re-render uses system to update UI
    renderUsesSystem()
    
    // 5️⃣ Show notification
    const status = isChecked ? '✅ محسوب' : '❌ غير محسوب'
    showNotification(`${use.name}: ${status} في GLA`, 'success', 2000)
    
    console.log('✅ toggleGLACounting complete')
}

