// === Ensure globals for inline handlers ===
(function ensureGlobalBindings() {
  const names = [
    'renderCostsSystem','renderUsesSystem','renderRevenuesSystem',
    'addNewUseType', 'deleteUseType', 'updateUseInfo', 'changeUseIconModal', 'selectIcon', 'selectCustomIcon', 'closeIconModal', 'duplicateUseType', 'resetUsesToDefaultsEnhanced', 'createUseTypeOptions', 'updateAllUseTypeDropdowns', 'debugDropdownSync', 'calculateCostsByUseType', 'calculateTotalUnitsForUse',
    'syncParkingWithUses', 'updateParkingForUse', 'removeParkingForUse', 'calculateParkingRequirements', 'renderParkingRequirementsTable', 'toggleParkingCalculationMode', 'fastParkingUpdate', 'createParkingRadarChart'
  ];
  names.forEach(n => {
    if (typeof window[n] !== 'function' && typeof globalThis[n] === 'function') {
      window[n] = globalThis[n];
    }
  });
})();

