// ✅ ربط الزر بشكل فوري بمجرد تحميل السكريبت
(function initExportButton() {
    console.log('🔌 [initExportButton] بدء تهيئة زر التصدير...');
    
    // دالة لربط الزر
    function attachExportButton() {
        // البحث بـ ID أو data-attribute
        const exportButton = document.getElementById('exportComparisonButton') || 
                           document.querySelector('[data-export-action="comparison-tool"]');
        
        if (exportButton) {
            console.log('✅ [attachExportButton] تم العثور على زر التصدير');
            
            // التحقق من أن الزر ليس مربوطاً بالفعل
            if (exportButton.dataset.listenerAttached === 'true') {
                console.log('ℹ️ الزر مربوط بالفعل، تخطي...');
                return true;
            }
            
            // إضافة event listener
            exportButton.addEventListener('click', function(e) {
                e.preventDefault();
                console.log('🖱️ [Click] تم الضغط على زر التصدير');
                
                try {
                    if (typeof window.exportForComparisonTool === 'function') {
                        console.log('✅ تنفيذ دالة التصدير...');
                        window.exportForComparisonTool();
                    } else {
                        console.error('❌ الدالة exportForComparisonTool غير معرفة');
                        alert('خطأ: وظيفة التصدير غير متاحة. يرجى إعادة تحميل الصفحة.');
                    }
                } catch (error) {
                    console.error('❌ خطأ عند التنفيذ:', error);
                    alert('حدث خطأ أثناء التصدير: ' + error.message);
                }
            });
            
            // وضع علامة أن الزر مربوط
            exportButton.dataset.listenerAttached = 'true';
            
            console.log('✅ [attachExportButton] تم ربط الزر بنجاح');
            return true;
        }
        
        console.warn('⚠️ لم يتم العثور على زر التصدير');
        return false;
    }
    
    // استراتيجية متعددة المراحل للربط
    let attempts = 0;
    const maxAttempts = 5;
    
    function tryAttach() {
        attempts++;
        console.log(`🔄 محاولة ${attempts}/${maxAttempts}...`);
        
        if (attachExportButton()) {
            console.log('✅ تم الربط بنجاح!');
            return;
        }
        
        if (attempts < maxAttempts) {
            setTimeout(tryAttach, 200 * attempts); // تأخير متزايد
        } else {
            console.error('❌ فشل ربط الزر بعد ' + maxAttempts + ' محاولات');
        }
    }
    
    // بدء المحاولات
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', tryAttach);
    } else {
        // DOM محمل بالفعل
        tryAttach();
    }
})();

