window.FEASIBILITY_EXPORT_IMPORT_SYSTEM = FEASIBILITY_EXPORT_IMPORT_SYSTEM;
window.exportFeasibilityData = exportFeasibilityData;
window.importFeasibilityData = importFeasibilityData;
window.exportCostsData = exportCostsData;
window.importCostsData = importCostsData;
window.resetCostsToImported = resetCostsToImported;

// ==================== نظام التصدير والاستيراد للأقسام الفردية ====================

/**
 * تصدير قسم تكاليف واحد فقط
 * Export single cost category
 * @param {string} categoryId - معرف القسم المراد تصديره
 */
function exportSingleCostCategory(categoryId) {
    try {
        console.log('📤 بدء تصدير القسم:', categoryId);
        
        // التحقق من وجود القسم
        if (!window.costsData || !window.costsData[categoryId]) {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'القسم المحدد غير موجود في البيانات', 
                'error'
            );
            return false;
        }
        
        const category = window.costsData[categoryId];
        
        // إنشاء كائن التصدير
        const categoryExport = {
            metadata: {
                exportDate: new Date().toISOString(),
                version: FEASIBILITY_EXPORT_IMPORT_SYSTEM.version,
                systemName: 'Single Cost Category Export',
                dataType: 'singleCostCategory',
                categoryId: categoryId,
                categoryName: category.name || 'غير محدد',
                categoryNameEn: category.nameEn || 'Undefined',
                categoryType: category.categoryType || 'additional',
                isCustom: category.isCustom || false,
                isDuplicated: category.isDuplicated || false,
                originalCategoryId: category.originalCategoryId || null,
                itemsCount: (category.costs && category.costs.length) || 0
            },
            categoryData: JSON.parse(JSON.stringify(category))
        };
        
        // تحويل إلى JSON
        const jsonString = JSON.stringify(categoryExport, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        
        // إنشاء اسم ملف وصفي
        const safeFileName = (category.name || categoryId)
            .replace(/[^a-zA-Z0-9\u0600-\u06FF\s-]/g, '')
            .replace(/\s+/g, '_')
            .substring(0, 50);
        
        const filename = `cost_category_${safeFileName}_${new Date().toISOString().split('T')[0]}.json`;
        
        // تحميل الملف
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        link.style.display = 'none';
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);
        
        console.log('✅ تم تصدير القسم بنجاح:', category.name);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            `✅ تم تصدير قسم "${category.name}" بنجاح!\n📁 ${filename}`, 
            'success',
            4000
        );
        
        return true;
        
    } catch (error) {
        console.error('❌ فشل تصدير القسم:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تصدير القسم: ' + error.message, 
            'error'
        );
        return false;
    }
}

/**
 * استيراد بيانات لقسم تكاليف واحد فقط
 * Import data for single cost category
 * @param {string} categoryId - معرف القسم المراد استيراد البيانات له
 */
function importSingleCostCategory(categoryId) {
    try {
        console.log('📥 بدء استيراد بيانات للقسم:', categoryId);
        
        // التحقق من وجود القسم
        if (!window.costsData || !window.costsData[categoryId]) {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'القسم المحدد غير موجود في البيانات', 
                'error'
            );
            return false;
        }
        
        const targetCategory = window.costsData[categoryId];
        
        // إنشاء عنصر input للملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = async (event) => {
            const file = event.target.files[0];
            if (!file) return;
            
            try {
                // قراءة محتوى الملف
                const text = await FEASIBILITY_EXPORT_IMPORT_SYSTEM.readFileAsText(file);
                const importData = JSON.parse(text);
                
                console.log('📋 بيانات الملف المستورد:', importData);
                
                // التحقق من نوع البيانات
                if (!importData.metadata || importData.metadata.dataType !== 'singleCostCategory') {
                    throw new Error('الملف المحدد لا يحتوي على بيانات قسم تكاليف صحيحة');
                }
                
                if (!importData.categoryData) {
                    throw new Error('الملف لا يحتوي على بيانات القسم');
                }
                
                // عرض رسالة تأكيد للمستخدم
                const importedCategoryName = importData.metadata.categoryName || 'غير محدد';
                const targetCategoryName = targetCategory.name || 'غير محدد';
                const exportDate = importData.metadata.exportDate ? new Date(importData.metadata.exportDate).toLocaleString('en-US') : 'غير محدد';
                
                // معلومات إضافية عن القسم المستورد
                const isDuplicatedInfo = importData.metadata.isDuplicated ? '✅ نعم' : '❌ لا';
                const isCustomInfo = importData.metadata.isCustom ? '✅ نعم' : '❌ لا';
                
                const confirmMessage = `هل تريد استيراد بيانات القسم "${importedCategoryName}" إلى القسم "${targetCategoryName}"؟\n\n` +
                    `⚠️ تحذير: سيتم استبدال جميع البنود الحالية في القسم "${targetCategoryName}"\n\n` +
                    `📊 معلومات الملف المستورد:\n` +
                    `- عدد البنود: ${importData.metadata.itemsCount || 0}\n` +
                    `- نوع القسم: ${importData.metadata.categoryType === 'construction' ? '🏗️ إنشائي' : '➕ إضافي'}\n` +
                    `- قسم مخصص: ${isCustomInfo}\n` +
                    `- قسم مكرر: ${isDuplicatedInfo}\n` +
                    `- تاريخ التصدير: ${exportDate}`;
                
                if (!confirm(confirmMessage)) {
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'تم إلغاء عملية الاستيراد', 
                        'info'
                    );
                    return;
                }
                
                // نسخ البيانات مع الحفاظ على المعرف والهيكل الأساسي للقسم المستهدف
                const importedCategory = JSON.parse(JSON.stringify(importData.categoryData));
                
                // الحفاظ على بعض الخصائص الأساسية من القسم المستهدف
                const preservedProperties = {
                    id: categoryId, // الحفاظ على المعرف الأصلي
                    isCustom: targetCategory.isCustom, // الحفاظ على حالة القسم
                };
                
                // دمج البيانات المستوردة مع الخصائص المحفوظة
                Object.assign(importedCategory, preservedProperties);
                
                // استبدال بيانات القسم في window.costsData
                window.costsData[categoryId] = importedCategory;
                
                // تحديث المتغير المحلي إذا كان موجوداً
                if (typeof costsData !== 'undefined' && costsData[categoryId]) {
                    costsData[categoryId] = importedCategory;
                }
                
                console.log('✅ تم استيراد البيانات للقسم:', categoryId);
                
                // إعادة رسم نظام التكاليف
                if (typeof renderCostsSystem === 'function') {
                    renderCostsSystem();
                }
                
                // عرض رسالة نجاح
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    `✅ تم استيراد بيانات القسم "${importedCategoryName}" بنجاح!\n` +
                    `📊 تم استبدال ${importedCategory.costs ? importedCategory.costs.length : 0} بند في القسم "${targetCategoryName}"`, 
                    'success',
                    5000
                );
                
            } catch (error) {
                console.error('❌ فشل استيراد بيانات القسم:', error);
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'حدث خطأ في استيراد بيانات القسم: ' + error.message, 
                    'error'
                );
            }
        };
        
        // فتح نافذة اختيار الملف
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ خطأ في إعداد عملية الاستيراد:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في إعداد عملية الاستيراد: ' + error.message, 
            'error'
        );
        return false;
    }
}

