/**
 * دالة مساعدة لتحميل ملفات JSON
 * Helper function to download JSON files
 */
function downloadJSONFile(data, filename) {
    try {
        const jsonString = JSON.stringify(data, null, 2);
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        link.style.display = 'none';
        
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        
        URL.revokeObjectURL(url);
        return true;
    } catch (error) {
        console.error('❌ خطأ في تحميل الملف:', error);
        return false;
    }
}

/**
 * تصدير بيانات الإيرادات
 * Export revenues data with comprehensive validation
 */
function exportRevenuesData() {
    try {
        console.log('📤 بدء عملية تصدير بيانات الإيرادات...');
        
        // التحقق من وجود البيانات
        if (!window.revenuesData || typeof window.revenuesData !== 'object') {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'لا توجد بيانات إيرادات للتصدير', 
                'warning'
            );
            return false;
        }

        // إنشاء نسخة عميقة من البيانات
        const revenuesSnapshot = JSON.parse(JSON.stringify(window.revenuesData));
        
        // جمع معلومات إضافية من الواجهة
        const additionalRevenueInfo = {};
        
        // جمع معلومات حالات التفعيل للإيجار والمبيعات
        Object.keys(window.usesData || {}).forEach(useId => {
            // حفظ حالة تفعيل الإيجار
            const rentalCheckbox = document.querySelector(`input[onchange*="toggleRentalRevenue('${useId}'"]`);
            if (rentalCheckbox) {
                additionalRevenueInfo[`rental_${useId}_enabled`] = rentalCheckbox.checked;
            }
            
            // حفظ حالة تفعيل المبيعات  
            const salesCheckbox = document.querySelector(`input[onchange*="toggleSalesRevenue('${useId}'"]`);
            if (salesCheckbox) {
                additionalRevenueInfo[`sales_${useId}_enabled`] = salesCheckbox.checked;
            }
        });

        // معلومات التصدير
        const exportData = {
            exportInfo: {
                timestamp: new Date().toISOString(),
                version: '1.0.0',
                exportType: 'revenues',
                systemName: 'دراسة الجدوى العقارية - نظام الإيرادات',
                description: 'تصدير شامل لبيانات الإيرادات مع حالات التفعيل'
            },
            revenuesData: revenuesSnapshot,
            additionalInfo: additionalRevenueInfo,
            metadata: {
                totalCategories: Object.keys(revenuesSnapshot).length,
                exportedAt: new Date().toLocaleString('en-US'),
                projectName: document.getElementById('projectName')?.value || 'مشروع غير محدد',
                clientName: document.getElementById('clientName')?.value || 'عميل غير محدد'
            }
        };

        // تنزيل الملف
        const filename = `revenues_data_${new Date().toISOString().split('T')[0]}_${Math.floor(Date.now() / 1000)}.json`;
        downloadJSONFile(exportData, filename);
        
        console.log('✅ تم تصدير بيانات الإيرادات بنجاح');
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            '✅ تم تصدير بيانات الإيرادات بنجاح!\n' + 
            `📊 عدد الفئات: ${exportData.metadata.totalCategories}\n` +
            `📁 اسم الملف: ${filename}`,
            'success',
            5000
        );
        
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تصدير بيانات الإيرادات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تصدير بيانات الإيرادات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * استيراد بيانات الإيرادات
 * Import revenues data with comprehensive validation
 */
function importRevenuesData() {
    try {
        console.log('📥 بدء عملية استيراد بيانات الإيرادات...');
        
        // إنشاء عنصر input للملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = function(e) {
            const file = e.target.files[0];
            if (!file) {
                console.log('❌ لم يتم اختيار أي ملف');
                return;
            }

            console.log('📁 تم اختيار الملف:', file.name);
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    console.log('📊 تم قراءة البيانات المستوردة:', importedData);
                    
                    // التحقق من صحة البيانات المستوردة
                    if (validateImportedRevenuesData(importedData)) {
                        // حفظ البيانات في النظام المتكامل
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.importedDefaults = importedData;
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.hasImportedData = true;
                        
                        // حفظ في localStorage
                        localStorage.setItem('feasibility_imported_defaults', JSON.stringify(importedData));
                        localStorage.setItem('feasibility_has_imported_data', 'true');
                        
                        // تطبيق البيانات
                        applyImportedRevenuesData(importedData);
                        
                        console.log('✅ تم استيراد وتطبيق بيانات الإيرادات بنجاح');
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                            '✅ تم استيراد بيانات الإيرادات بنجاح!\n' +
                            `📊 عدد الفئات: ${Object.keys(importedData.revenuesData || {}).length}\n` +
                            `📅 تاريخ التصدير: ${importedData.exportInfo?.timestamp ? new Date(importedData.exportInfo.timestamp).toLocaleString('en-US') : 'غير محدد'}`,
                            'success',
                            6000
                        );
                    }
                } catch (parseError) {
                    console.error('❌ خطأ في قراءة الملف:', parseError);
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'خطأ في قراءة الملف: تأكد من أن الملف بصيغة JSON صحيحة',
                        'error'
                    );
                }
            };
            
            reader.onerror = function() {
                console.error('❌ فشل في قراءة الملف');
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'فشل في قراءة الملف المحدد',
                    'error'
                );
            };
            
            reader.readAsText(file);
        };
        
        // إضافة العنصر إلى الصفحة وتفعيله
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ فشل في استيراد بيانات الإيرادات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في استيراد بيانات الإيرادات: ' + error.message,
            'error'
        );
    }
}

/**
 * التحقق من صحة البيانات المستوردة للإيرادات
 * Validate imported revenues data structure
 */
function validateImportedRevenuesData(data) {
    try {
        console.log('🔍 التحقق من صحة بيانات الإيرادات المستوردة...');
        
        // التحقق من الهيكل الأساسي
        if (!data || typeof data !== 'object') {
            throw new Error('البيانات المستوردة غير صحيحة');
        }
        
        // التحقق من وجود معلومات التصدير
        if (!data.exportInfo || !data.exportInfo.exportType) {
            throw new Error('معلومات التصدير مفقودة');
        }
        
        // التحقق من نوع التصدير
        if (data.exportInfo.exportType !== 'revenues') {
            throw new Error('نوع الملف المستورد غير صحيح. يجب أن يكون ملف إيرادات');
        }
        
        // التحقق من وجود بيانات الإيرادات
        if (!data.revenuesData || typeof data.revenuesData !== 'object') {
            throw new Error('بيانات الإيرادات مفقودة أو غير صحيحة');
        }
        
        // التحقق من الفئات الأساسية
        const requiredCategories = ['rentalRevenues', 'salesRevenues', 'additionalRevenues'];
        const missingCategories = requiredCategories.filter(cat => !data.revenuesData[cat]);
        
        if (missingCategories.length > 0) {
            console.warn('⚠️ فئات مفقودة:', missingCategories);
            // لا نعتبرها خطأ قاتل، فقط تحذير
        }
        
        // التحقق من بنية الإيرادات الإضافية
        if (data.revenuesData.additionalRevenues && 
            data.revenuesData.additionalRevenues.revenues && 
            !Array.isArray(data.revenuesData.additionalRevenues.revenues)) {
            throw new Error('بنية الإيرادات الإضافية غير صحيحة');
        }
        
        console.log('✅ تم التحقق من صحة بيانات الإيرادات بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في التحقق من البيانات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'البيانات المستوردة غير صحيحة: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق البيانات المستوردة للإيرادات
 * Apply imported revenues data to the system
 */
function applyImportedRevenuesData(importedData) {
    try {
        console.log('🔧 تطبيق البيانات المستوردة للإيرادات...');
        
        // نسخ عميق للبيانات المستوردة
        const newRevenuesData = JSON.parse(JSON.stringify(importedData.revenuesData));
        
        // تطبيق البيانات على المتغير العام
        window.revenuesData = newRevenuesData;
        
        // تطبيق البيانات على المتغير المحلي إذا كان موجوداً
        if (typeof revenuesData !== 'undefined') {
            Object.keys(revenuesData).forEach(key => delete revenuesData[key]);
            Object.assign(revenuesData, newRevenuesData);
            console.log('✅ تم تحديث المتغير المحلي revenuesData');
        }
        
        // تطبيق المعلومات الإضافية (حالات التفعيل)
        if (importedData.additionalInfo) {
            console.log('🔧 تطبيق حالات التفعيل...');
            
            // تأخير قصير للتأكد من رسم الواجهة
            setTimeout(() => {
                Object.keys(importedData.additionalInfo).forEach(key => {
                    if (key.startsWith('rental_') && key.endsWith('_enabled')) {
                        const useId = key.replace('rental_', '').replace('_enabled', '');
                        const checkbox = document.querySelector(`input[onchange*="toggleRentalRevenue('${useId}'"]`);
                        if (checkbox) {
                            checkbox.checked = importedData.additionalInfo[key];
                            console.log(`✅ تم تطبيق حالة الإيجار للاستخدام ${useId}: ${checkbox.checked}`);
                        }
                    }
                    
                    if (key.startsWith('sales_') && key.endsWith('_enabled')) {
                        const useId = key.replace('sales_', '').replace('_enabled', '');
                        const checkbox = document.querySelector(`input[onchange*="toggleSalesRevenue('${useId}'"]`);
                        if (checkbox) {
                            checkbox.checked = importedData.additionalInfo[key];
                            console.log(`✅ تم تطبيق حالة المبيعات للاستخدام ${useId}: ${checkbox.checked}`);
                        }
                    }
                });
            }, 500);
        }
        
        // إعادة رسم نظام الإيرادات
        if (typeof renderRevenuesSystem === 'function') {
            setTimeout(() => {
                renderRevenuesSystem();
                console.log('✅ تم إعادة رسم نظام الإيرادات');
                
                // تطبيق القيم على واجهة المستخدم
                setTimeout(() => {
                    if (FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI) {
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI();
                        console.log('✅ تم تطبيق القيم على واجهة المستخدم');
                    }
                }, 300);
            }, 200);
        }
        
        console.log('✅ تم تطبيق بيانات الإيرادات المستوردة بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تطبيق بيانات الإيرادات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تطبيق البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

