/**
 * تصدير بيانات الأرض والبناء (النظام 1)
 * Export Land & Construction data
 * يشمل: طرق الحصول على الأرض + ملخص الاستثمار + توزيع تكاليف البناء + فترات المشروع
 */
function exportLandConstructionData() {
    try {
        console.log('🏗️ بدء عملية تصدير بيانات الأرض والبناء...');
        
        // جمع البيانات من HTML
        const htmlData = collectInvestmentDataFromHTML();
        
        // ✅ UPDATED: إنشاء البيانات المحددة للتصدير مع جميع الحقول الجديدة
        let landConstructionData = {
            landAcquisition: htmlData?.landAcquisition || {},
            capitalExpenditure: htmlData?.capitalExpenditure || {},
            projectPeriods: htmlData?.projectPeriods || {}
        };
        
        // محاولة دمج البيانات من window.investmentData إذا كانت موجودة
        if (typeof window.investmentData !== 'undefined') {
            if (window.investmentData.landAcquisition) {
                // ✅ NEW: تضمين جميع بيانات الشراكة الجديدة
                landConstructionData.landAcquisition = { 
                    ...landConstructionData.landAcquisition, 
                    ...window.investmentData.landAcquisition,
                    // التأكد من تضمين الشركاء الإضافيين
                    partners: window.investmentData.landAcquisition.partners || [],
                    // التأكد من تضمين جميع حقول الشراكة
                    profitSharingModel: window.investmentData.landAcquisition.profitSharingModel || 'revenue',
                    hybridRevenueWeight: window.investmentData.landAcquisition.hybridRevenueWeight || 50,
                    hybridProfitWeight: window.investmentData.landAcquisition.hybridProfitWeight || 50,
                    managementFeePercentage: window.investmentData.landAcquisition.managementFeePercentage || 5,
                    autoCalculateProfitShare: window.investmentData.landAcquisition.autoCalculateProfitShare || false,
                    partnerContribution: window.investmentData.landAcquisition.partnerContribution || 'land',
                    landValuePerSqm: window.investmentData.landAcquisition.landValuePerSqm || 2000,
                    partnerCashContribution: window.investmentData.landAcquisition.partnerCashContribution || 0,
                    developerCashContribution: window.investmentData.landAcquisition.developerCashContribution || 0
                };
            }
            if (window.investmentData.capitalExpenditure) {
                landConstructionData.capitalExpenditure = { 
                    ...landConstructionData.capitalExpenditure, 
                    ...window.investmentData.capitalExpenditure 
                };
            }
            if (window.investmentData.projectPeriods) {
                landConstructionData.projectPeriods = { 
                    ...landConstructionData.projectPeriods, 
                    ...window.investmentData.projectPeriods 
                };
            }
        }
        
        console.log('📊 [exportLandConstructionData] البيانات المُصدرة:', {
            landMode: landConstructionData.landAcquisition.mode,
            hasPartners: landConstructionData.landAcquisition.partners ? true : false,
            partnersCount: landConstructionData.landAcquisition.partners?.length || 0,
            profitSharingModel: landConstructionData.landAcquisition.profitSharingModel,
            autoCalculate: landConstructionData.landAcquisition.autoCalculateProfitShare
        });
        
        // جمع معلومات إضافية من الواجهة
        const additionalInfo = {};
        
        // جمع معلومات طريقة الحصول على الأرض
        const landModeRadios = document.querySelectorAll('input[name="landMode"]');
        let selectedLandMode = 'purchase';
        landModeRadios.forEach(radio => {
            if (radio.checked) {
                selectedLandMode = radio.value;
            }
        });
        additionalInfo.selectedLandMode = selectedLandMode;
        
        // جمع معلومات مساحة الأرض
        const landArea = document.getElementById('landArea')?.value || 0;
        additionalInfo.landArea = parseFloat(landArea);
        
        // ✅ CRITICAL FIX: قراءة القيم الفعلية من حقول HTML مباشرة
        const actualConstructionPeriod = parseInt(document.getElementById('constructionPeriod')?.value) || 
                                        landConstructionData.projectPeriods?.constructionPeriod || 3;
        const actualOperatingPeriod = parseInt(document.getElementById('operatingPeriod')?.value) || 
                                      landConstructionData.projectPeriods?.operatingPeriod || 20;
        
        console.log(`📊 [exportLandConstructionData] القيم الفعلية:`);
        console.log(`   🏗️ فترة البناء: ${actualConstructionPeriod} سنة`);
        console.log(`   ⚙️ فترة التشغيل: ${actualOperatingPeriod} سنة`);
        
        // معلومات التصدير
        const exportData = {
            exportInfo: {
                timestamp: new Date().toISOString(),
                version: '1.0.0',
                exportType: 'land-construction',
                systemName: 'نظام الأرض والبناء - Land & Construction System',
                description: 'تصدير بيانات طرق الحصول على الأرض وملخص الاستثمار وتوزيع تكاليف البناء'
            },
            landConstructionData: {
                ...landConstructionData,
                projectPeriods: {
                    constructionPeriod: actualConstructionPeriod,
                    operatingPeriod: actualOperatingPeriod
                }
            },
            additionalInfo: additionalInfo,
            metadata: {
                exportedAt: new Date().toLocaleString('en-US'),
                projectName: document.getElementById('projectName')?.value || 'مشروع غير محدد',
                clientName: document.getElementById('clientName')?.value || 'عميل غير محدد',
                landArea: additionalInfo.landArea,
                landMode: selectedLandMode,
                constructionPeriod: actualConstructionPeriod,
                operatingPeriod: actualOperatingPeriod,
                componentsSummary: {
                    landAcquisition: landConstructionData.landAcquisition ? 'مُعرف' : 'غير مُعرف',
                    capitalExpenditure: landConstructionData.capitalExpenditure ? 'مُعرف' : 'غير مُعرف',
                    projectPeriods: landConstructionData.projectPeriods ? 'مُعرف' : 'غير مُعرف'
                }
            }
        };
        
        // تنزيل الملف
        const filename = `land_construction_data_${new Date().toISOString().split('T')[0]}_${Math.floor(Date.now() / 1000)}.json`;
        downloadJSONFile(exportData, filename);
        
        console.log('✅ تم تصدير بيانات الأرض والبناء بنجاح');
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            '✅ تم تصدير بيانات الأرض والبناء بنجاح!\n' + 
            `🏞️ طريقة الأرض: ${getLandModeDisplayName(selectedLandMode)}\n` +
            `📐 مساحة الأرض: ${additionalInfo.landArea.toLocaleString('en-US')} م²\n` +
            `🏗️ فترة البناء: ${actualConstructionPeriod} سنة\n` +
            `⚙️ فترة التشغيل: ${actualOperatingPeriod} سنة\n` +
            `📁 اسم الملف: ${filename}`,
            'success',
            6000
        );
        
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تصدير بيانات الأرض والبناء:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تصدير بيانات الأرض والبناء: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * استيراد بيانات الأرض والبناء (النظام 1)
 * Import Land & Construction data
 */
function importLandConstructionData() {
    try {
        console.log('📥 بدء عملية استيراد بيانات الأرض والبناء...');
        
        // إنشاء عنصر input للملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = function(e) {
            const file = e.target.files[0];
            if (!file) {
                console.log('❌ لم يتم اختيار أي ملف');
                return;
            }
            
            console.log('📁 تم اختيار الملف:', file.name);
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    console.log('📊 تم قراءة البيانات المستوردة:', importedData);
                    
                    // التحقق من صحة البيانات المستوردة
                    if (validateImportedLandConstructionData(importedData)) {
                        // حفظ البيانات في localStorage
                        localStorage.setItem('feasibility_imported_land_construction', JSON.stringify(importedData));
                        localStorage.setItem('feasibility_has_land_construction_data', 'true');
                        
                        // تطبيق البيانات
                        applyImportedLandConstructionData(importedData);
                        
                        console.log('✅ تم استيراد وتطبيق بيانات الأرض والبناء بنجاح');
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                            '✅ تم استيراد بيانات الأرض والبناء بنجاح!\n' +
                            `🏞️ طريقة الأرض: ${getLandModeDisplayName(importedData.additionalInfo?.selectedLandMode || 'purchase')}\n` +
                            `📐 مساحة الأرض: ${(importedData.additionalInfo?.landArea || 0).toLocaleString('en-US')} م²\n` +
                            `🏗️ فترة البناء: ${importedData.landConstructionData?.projectPeriods?.constructionPeriod || 3} سنة\n` +
                            `📅 تاريخ التصدير: ${importedData.exportInfo?.timestamp ? new Date(importedData.exportInfo.timestamp).toLocaleString('en-US') : 'غير محدد'}`,
                            'success',
                            6000
                        );
                    }
                } catch (parseError) {
                    console.error('❌ خطأ في قراءة الملف:', parseError);
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'خطأ في قراءة الملف: تأكد من أن الملف بصيغة JSON صحيحة',
                        'error'
                    );
                }
            };
            
            reader.onerror = function() {
                console.error('❌ فشل في قراءة الملف');
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'فشل في قراءة الملف المحدد',
                    'error'
                );
            };
            
            reader.readAsText(file);
        };
        
        // إضافة العنصر إلى الصفحة وتفعيله
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ فشل في استيراد بيانات الأرض والبناء:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في استيراد بيانات الأرض والبناء: ' + error.message,
            'error'
        );
    }
}

/**
 * التحقق من صحة البيانات المستوردة للأرض والبناء
 * Validate imported Land & Construction data
 */
function validateImportedLandConstructionData(data) {
    try {
        console.log('🔍 التحقق من صحة بيانات الأرض والبناء المستوردة...');
        
        // التحقق من الهيكل الأساسي
        if (!data || typeof data !== 'object') {
            throw new Error('البيانات المستوردة غير صحيحة');
        }
        
        // التحقق من وجود معلومات التصدير
        if (!data.exportInfo || !data.exportInfo.exportType) {
            throw new Error('معلومات التصدير مفقودة');
        }
        
        // التحقق من نوع التصدير
        if (data.exportInfo.exportType !== 'land-construction') {
            throw new Error('نوع الملف المستورد غير صحيح. يجب أن يكون ملف بيانات الأرض والبناء');
        }
        
        // التحقق من وجود البيانات الأساسية
        if (!data.landConstructionData || typeof data.landConstructionData !== 'object') {
            throw new Error('بيانات الأرض والبناء مفقودة أو غير صحيحة');
        }
        
        // التحقق من بنية بيانات الأرض
        if (data.landConstructionData.landAcquisition && 
            typeof data.landConstructionData.landAcquisition !== 'object') {
            throw new Error('بنية بيانات الحصول على الأرض غير صحيحة');
        }
        
        // التحقق من بيانات فترات المشروع
        if (data.landConstructionData.projectPeriods && 
            typeof data.landConstructionData.projectPeriods !== 'object') {
            throw new Error('بنية بيانات فترات المشروع غير صحيحة');
        }
        
        console.log('✅ تم التحقق من صحة بيانات الأرض والبناء بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في التحقق من البيانات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'البيانات المستوردة غير صحيحة: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق البيانات المستوردة للأرض والبناء
 * Apply imported Land & Construction data
 */
function applyImportedLandConstructionData(importedData) {
    try {
        console.log('🔧 تطبيق البيانات المستوردة للأرض والبناء...');
        
        const newData = importedData.landConstructionData;
        
        // تطبيق البيانات على window.investmentData إذا كان موجوداً
        if (typeof window.investmentData !== 'undefined') {
            if (newData.landAcquisition) {
                window.investmentData.landAcquisition = { 
                    ...window.investmentData.landAcquisition, 
                    ...newData.landAcquisition 
                };
            }
            if (newData.capitalExpenditure) {
                window.investmentData.capitalExpenditure = { 
                    ...window.investmentData.capitalExpenditure, 
                    ...newData.capitalExpenditure 
                };
            }
            if (newData.projectPeriods) {
                window.investmentData.projectPeriods = { 
                    ...window.investmentData.projectPeriods, 
                    ...newData.projectPeriods 
                };
            }
            console.log('✅ تم تحديث window.investmentData');
        }
        
        // تطبيق البيانات على عناصر HTML
        applyLandConstructionDataToHTML(newData);
        
        // تطبيق المعلومات الإضافية
        if (importedData.additionalInfo) {
            console.log('🔧 تطبيق الإعدادات الإضافية...');
            
            // تطبيق طريقة الحصول على الأرض
            if (importedData.additionalInfo.selectedLandMode) {
                const landModeRadio = document.querySelector(`input[name="landMode"][value="${importedData.additionalInfo.selectedLandMode}"]`);
                if (landModeRadio) {
                    landModeRadio.checked = true;
                    // تفعيل القسم المناسب
                    if (typeof updateLandAcquisitionDisplay === 'function') {
                        updateLandAcquisitionDisplay(importedData.additionalInfo.selectedLandMode);
                    }
                }
            }
        }
        
        // إعادة حساب وتحديث النظام
        setTimeout(() => {
            if (typeof updateInvestmentDisplay === 'function') {
                updateInvestmentDisplay();
                console.log('✅ تم تحديث عرض الاستثمار');
            }
            
            if (typeof calculateInvestmentKPIs === 'function') {
                calculateInvestmentKPIs();
                console.log('✅ تم حساب مؤشرات الاستثمار');
            }
        }, 200);
        
        console.log('✅ تم تطبيق بيانات الأرض والبناء المستوردة بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تطبيق بيانات الأرض والبناء:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تطبيق البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق بيانات الأرض والبناء على عناصر HTML
 * Apply Land & Construction data to HTML elements
 */
function applyLandConstructionDataToHTML(data) {
    try {
        console.log('🎨 تطبيق بيانات الأرض والبناء على عناصر HTML...');
        
        // تطبيق بيانات الأرض
        if (data.landAcquisition) {
            const landData = data.landAcquisition;
            
            if (document.getElementById('purchasePrice') && landData.purchasePrice !== undefined && landData.purchasePrice !== null) {
                document.getElementById('purchasePrice').value = landData.purchasePrice;
            }
            if (document.getElementById('annualRent') && landData.annualRent !== undefined && landData.annualRent !== null) {
                document.getElementById('annualRent').value = landData.annualRent;
            }
            if (document.getElementById('leaseTerm') && landData.leaseTerm !== undefined && landData.leaseTerm !== null) {
                document.getElementById('leaseTerm').value = landData.leaseTerm;
            }
            if (document.getElementById('rentIncrease') && landData.rentIncreasePercentage !== undefined && landData.rentIncreasePercentage !== null) {
                document.getElementById('rentIncrease').value = landData.rentIncreasePercentage;
            }
            if (document.getElementById('rentFrequency') && landData.rentIncreaseFrequency !== undefined && landData.rentIncreaseFrequency !== null) {
                document.getElementById('rentFrequency').value = landData.rentIncreaseFrequency;
            }
            
            // تطبيق بيانات الشراكة الجديدة
            if (landData.mode === 'partnership') {
                // نموذج توزيع الأرباح
                if (document.getElementById('profitSharingModel') && landData.profitSharingModel) {
                    document.getElementById('profitSharingModel').value = landData.profitSharingModel;
                    // تحديث الوصف التفاعلي
                    if (typeof window.updateProfitSharingModel === 'function') {
                        setTimeout(() => window.updateProfitSharingModel(), 100);
                    }
                }
                
                // نسب النموذج المختلط
                if (document.getElementById('hybridRevenueWeight') && landData.hybridRevenueWeight !== undefined) {
                    document.getElementById('hybridRevenueWeight').value = landData.hybridRevenueWeight;
                }
                if (document.getElementById('hybridProfitWeight') && landData.hybridProfitWeight !== undefined) {
                    document.getElementById('hybridProfitWeight').value = landData.hybridProfitWeight;
                }
                if (typeof window.updateHybridWeights === 'function') {
                    setTimeout(() => window.updateHybridWeights(), 100);
                }
                
                // نسبة الشريك ورسوم الإدارة
                if (document.getElementById('partnershipShare') && landData.partnershipShare !== undefined) {
                    document.getElementById('partnershipShare').value = landData.partnershipShare;
                }
                if (document.getElementById('managementFeePercentage') && landData.managementFeePercentage !== undefined) {
                    document.getElementById('managementFeePercentage').value = landData.managementFeePercentage;
                }
                
                // الحساب التلقائي
                if (document.getElementById('autoCalculateProfitShare') && landData.autoCalculateProfitShare !== undefined) {
                    document.getElementById('autoCalculateProfitShare').checked = landData.autoCalculateProfitShare;
                }
                
                // قيمة الأرض للشريك
                if (document.getElementById('landValuePerSqm') && landData.landValuePerSqm !== undefined) {
                    document.getElementById('landValuePerSqm').value = landData.landValuePerSqm;
                }
                
                // الشركاء الإضافيون
                if (landData.partners && Array.isArray(landData.partners) && typeof window.investmentData !== 'undefined') {
                    window.investmentData.landAcquisition.partners = landData.partners;
                    console.log('✅ تم استيراد بيانات الشركاء الإضافيين:', landData.partners.length, 'شركاء');
                }
                
                // تحديث عرض تفاصيل الشراكة
                if (typeof window.updateLandCostDetails === 'function') {
                    setTimeout(() => window.updateLandCostDetails(), 200);
                }
            }
        }
        
        // تطبيق فترات المشروع
        if (data.projectPeriods) {
            const periodsData = data.projectPeriods;
            
            if (document.getElementById('constructionPeriod') && periodsData.constructionPeriod !== undefined && periodsData.constructionPeriod !== null) {
                document.getElementById('constructionPeriod').value = periodsData.constructionPeriod;
                
                // تحديث النظام بعد تطبيق القيمة
                if (typeof handleConstructionPeriodChange === 'function') {
                    setTimeout(() => handleConstructionPeriodChange(), 100);
                }
            }
            if (document.getElementById('operatingPeriod') && periodsData.operatingPeriod !== undefined && periodsData.operatingPeriod !== null) {
                document.getElementById('operatingPeriod').value = periodsData.operatingPeriod;
                
                // تحديث المعاملات العامة
                if (typeof updateInvestmentParameters === 'function') {
                    setTimeout(() => updateInvestmentParameters(), 100);
                }
            }
        }
        
        console.log('✅ تم تطبيق البيانات على عناصر HTML بنجاح');
        
    } catch (error) {
        console.error('❌ خطأ في تطبيق البيانات على HTML:', error);
    }
}

