/**
 * الحصول على اسم طريقة الأرض للعرض
 * Get display name for land acquisition mode
 */
function getLandModeDisplayName(mode) {
    const modeNames = {
        'purchase': 'شراء',
        'lease': 'إيجار',
        'partnership': 'شراكة'
    };
    return modeNames[mode] || mode;
}

/**
 * استيراد بيانات الاستثمار والتمويل وتكاليف الأرض
 * Import Investment, Financing & Land Costs data with comprehensive validation
 */
function importInvestmentData() {
    try {
        console.log('📥 بدء عملية استيراد بيانات الاستثمار والتمويل وتكاليف الأرض...');
        
        // إنشاء عنصر input للملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = function(e) {
            const file = e.target.files[0];
            if (!file) {
                console.log('❌ لم يتم اختيار أي ملف');
                return;
            }

            console.log('📁 تم اختيار الملف:', file.name);
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    console.log('📊 تم قراءة البيانات المستوردة:', importedData);
                    
                    // التحقق من صحة البيانات المستوردة
                    if (validateImportedInvestmentData(importedData)) {
                        // حفظ البيانات في النظام المتكامل
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.importedDefaults = importedData;
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.hasImportedData = true;
                        
                        // حفظ في localStorage
                        localStorage.setItem('feasibility_imported_defaults', JSON.stringify(importedData));
                        localStorage.setItem('feasibility_has_imported_data', 'true');
                        
                        // تطبيق البيانات
                        applyImportedInvestmentData(importedData);
                        
                        console.log('✅ تم استيراد وتطبيق بيانات الاستثمار والتمويل وتكاليف الأرض بنجاح');
                        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                            '✅ تم استيراد بيانات الاستثمار والتمويل وتكاليف الأرض بنجاح!\n' +
                            `🏞️ طريقة الأرض: ${getLandModeDisplayName(importedData.additionalInfo?.selectedLandMode || 'purchase')}\n` +
                            `💰 التمويل بالدين: ${importedData.additionalInfo?.debtFinancingEnabled ? 'مُفعل' : 'غير مُفعل'}\n` +
                            `📈 نمو الإيرادات: ${importedData.additionalInfo?.revenueGrowthEnabled ? 'مُفعل' : 'غير مُفعل'}\n` +
                            `📅 تاريخ التصدير: ${importedData.exportInfo?.timestamp ? new Date(importedData.exportInfo.timestamp).toLocaleString('en-US') : 'غير محدد'}`,
                            'success',
                            7000
                        );
                    }
                } catch (parseError) {
                    console.error('❌ خطأ في قراءة الملف:', parseError);
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'خطأ في قراءة الملف: تأكد من أن الملف بصيغة JSON صحيحة',
                        'error'
                    );
                }
            };
            
            reader.onerror = function() {
                console.error('❌ فشل في قراءة الملف');
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'فشل في قراءة الملف المحدد',
                    'error'
                );
            };
            
            reader.readAsText(file);
        };
        
        // إضافة العنصر إلى الصفحة وتفعيله
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ فشل في استيراد بيانات الاستثمار والتمويل وتكاليف الأرض:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في استيراد بيانات الاستثمار والتمويل: ' + error.message,
            'error'
        );
    }
}

/**
 * التحقق من صحة البيانات المستوردة للاستثمار والتمويل وتكاليف الأرض
 * Validate imported Investment, Financing & Land Costs data structure
 */
function validateImportedInvestmentData(data) {
    try {
        console.log('🔍 التحقق من صحة بيانات الاستثمار والتمويل وتكاليف الأرض المستوردة...');
        
        // التحقق من الهيكل الأساسي
        if (!data || typeof data !== 'object') {
            throw new Error('البيانات المستوردة غير صحيحة');
        }
        
        // التحقق من وجود معلومات التصدير
        if (!data.exportInfo || !data.exportInfo.exportType) {
            throw new Error('معلومات التصدير مفقودة');
        }
        
        // التحقق من نوع التصدير
        if (data.exportInfo.exportType !== 'investment') {
            throw new Error('نوع الملف المستورد غير صحيح. يجب أن يكون ملف استثمار وتمويل');
        }
        
        // التحقق من وجود بيانات الاستثمار
        if (!data.investmentData || typeof data.investmentData !== 'object') {
            throw new Error('بيانات الاستثمار والتمويل مفقودة أو غير صحيحة');
        }
        
        // التحقق من الأقسام الأساسية
        const requiredSections = ['landAcquisition', 'financing'];
        const missingSections = requiredSections.filter(section => !data.investmentData[section]);
        
        if (missingSections.length > 0) {
            console.warn('⚠️ أقسام مفقودة:', missingSections);
            // لا نعتبرها خطأ قاتل، فقط تحذير
        }
        
        // التحقق من بنية بيانات الأرض
        if (data.investmentData.landAcquisition && 
            typeof data.investmentData.landAcquisition !== 'object') {
            throw new Error('بنية بيانات الحصول على الأرض غير صحيحة');
        }
        
        // التحقق من بنية بيانات التمويل
        if (data.investmentData.financing && 
            typeof data.investmentData.financing !== 'object') {
            throw new Error('بنية بيانات التمويل غير صحيحة');
        }
        
        // التحقق من بيانات فترات المشروع
        if (data.investmentData.projectPeriods && 
            typeof data.investmentData.projectPeriods !== 'object') {
            throw new Error('بنية بيانات فترات المشروع غير صحيحة');
        }
        
        // التحقق من قيم فترات المشروع المنطقية
        if (data.investmentData.projectPeriods) {
            const periods = data.investmentData.projectPeriods;
            if (periods.constructionPeriod && (periods.constructionPeriod < 1 || periods.constructionPeriod > 10)) {
                console.warn('⚠️ فترة البناء خارج النطاق المتوقع (1-10 سنوات):', periods.constructionPeriod);
            }
            if (periods.operatingPeriod && (periods.operatingPeriod < 5 || periods.operatingPeriod > 50)) {
                console.warn('⚠️ فترة التشغيل خارج النطاق المتوقع (5-50 سنة):', periods.operatingPeriod);
            }
        }
        
        console.log('✅ تم التحقق من صحة بيانات الاستثمار والتمويل وتكاليف الأرض بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في التحقق من البيانات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'البيانات المستوردة غير صحيحة: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق البيانات المستوردة للاستثمار والتمويل وتكاليف الأرض
 * Apply imported Investment, Financing & Land Costs data to the system
 */
function applyImportedInvestmentData(importedData) {
    try {
        console.log('🔧 تطبيق البيانات المستوردة للاستثمار والتمويل وتكاليف الأرض...');
        
        // نسخ عميق للبيانات المستوردة
        const newInvestmentData = JSON.parse(JSON.stringify(importedData.investmentData));
        
        // تطبيق البيانات على المتغير العام إذا كان موجوداً
        if (typeof window.investmentData !== 'undefined') {
            window.investmentData = newInvestmentData;
            
            // تحديث financing بشكل خاص لضمان التطبيق الصحيح
            if (newInvestmentData.projectPeriods) {
                if (!window.investmentData.financing) {
                    window.investmentData.financing = {};
                }
                window.investmentData.financing.constructionPeriod = newInvestmentData.projectPeriods.constructionPeriod;
                window.investmentData.financing.operatingPeriod = newInvestmentData.projectPeriods.operatingPeriod;
            }
            
            console.log('✅ تم تحديث window.investmentData');
        }
        
        // تطبيق البيانات على متغير محلي إذا كان موجوداً (في src/index.tsx)
        if (typeof investmentData !== 'undefined') {
            Object.keys(investmentData).forEach(key => delete investmentData[key]);
            Object.assign(investmentData, newInvestmentData);
            
            // تحديث financing بشكل خاص لضمان التطبيق الصحيح
            if (newInvestmentData.projectPeriods) {
                if (!investmentData.financing) {
                    investmentData.financing = {};
                }
                investmentData.financing.constructionPeriod = newInvestmentData.projectPeriods.constructionPeriod;
                investmentData.financing.operatingPeriod = newInvestmentData.projectPeriods.operatingPeriod;
            }
            
            console.log('✅ تم تحديث المتغير المحلي investmentData');
        }
        
        // تطبيق البيانات على عناصر HTML
        applyInvestmentDataToHTML(newInvestmentData);
        
        // تطبيق المعلومات الإضافية
        if (importedData.additionalInfo) {
            console.log('🔧 تطبيق الإعدادات الإضافية...');
            
            // تطبيق حالة تفعيل التمويل بالدين
            if (importedData.additionalInfo.debtFinancingEnabled !== undefined) {
                const debtCheckbox = document.querySelector('input[onchange*="toggleDebtFinancing"]');
                if (debtCheckbox) {
                    debtCheckbox.checked = importedData.additionalInfo.debtFinancingEnabled;
                    // تفعيل/إلغاء القسم
                    if (typeof toggleDebtFinancing === 'function') {
                        toggleDebtFinancing(importedData.additionalInfo.debtFinancingEnabled);
                    }
                }
            }
            
            // تطبيق حالة تفعيل نمو الإيرادات
            if (importedData.additionalInfo.revenueGrowthEnabled !== undefined) {
                const revenueGrowthCheckbox = document.getElementById('revenueGrowthEnabled');
                if (revenueGrowthCheckbox) {
                    revenueGrowthCheckbox.checked = importedData.additionalInfo.revenueGrowthEnabled;
                }
            }
            
            // تطبيق طريقة الحصول على الأرض
            if (importedData.additionalInfo.selectedLandMode) {
                const landModeRadio = document.querySelector(`input[name="landMode"][value="${importedData.additionalInfo.selectedLandMode}"]`);
                if (landModeRadio) {
                    landModeRadio.checked = true;
                    // تفعيل القسم المناسب
                    if (typeof updateLandAcquisitionDisplay === 'function') {
                        updateLandAcquisitionDisplay(importedData.additionalInfo.selectedLandMode);
                    }
                }
            }
        }
        
        // إعادة حساب وتحديث النظام
        setTimeout(() => {
            // تحديث العرض والحسابات
            if (typeof updateInvestmentDisplay === 'function') {
                updateInvestmentDisplay();
                console.log('✅ تم تحديث عرض الاستثمار');
            }
            
            if (typeof calculateInvestmentKPIs === 'function') {
                calculateInvestmentKPIs();
                console.log('✅ تم حساب مؤشرات الاستثمار');
            }
            
            // تطبيق القيم على واجهة المستخدم
            setTimeout(() => {
                if (FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI) {
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI();
                    console.log('✅ تم تطبيق القيم على واجهة المستخدم');
                }
            }, 300);
        }, 200);
        
        console.log('✅ تم تطبيق بيانات الاستثمار والتمويل وتكاليف الأرض المستوردة بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تطبيق بيانات الاستثمار والتمويل وتكاليف الأرض:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تطبيق البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق بيانات الاستثمار على عناصر HTML
 * Apply investment data to HTML elements
 */
function applyInvestmentDataToHTML(data) {
    try {
        console.log('🎨 تطبيق بيانات الاستثمار على عناصر HTML...');
        
        // تطبيق بيانات الأرض
        if (data.landAcquisition) {
            const landData = data.landAcquisition;
            
            if (document.getElementById('purchasePrice') && landData.purchasePrice !== undefined && landData.purchasePrice !== null) {
                document.getElementById('purchasePrice').value = landData.purchasePrice || '';
            }
            if (document.getElementById('annualRent') && landData.annualRent !== undefined && landData.annualRent !== null) {
                document.getElementById('annualRent').value = landData.annualRent || '';
            }
            if (document.getElementById('leaseTerm') && landData.leaseTerm !== undefined && landData.leaseTerm !== null) {
                document.getElementById('leaseTerm').value = landData.leaseTerm || '';
            }
        }
        
        // تطبيق بيانات التمويل
        if (data.financing) {
            const finData = data.financing;
            
            if (document.getElementById('equityRatio') && finData.equityRatio !== undefined && finData.equityRatio !== null) {
                document.getElementById('equityRatio').value = finData.equityRatio || '';
            }
            if (document.getElementById('debtRatio') && finData.debtRatio !== undefined && finData.debtRatio !== null) {
                document.getElementById('debtRatio').value = finData.debtRatio || '';
            }
            if (document.getElementById('interestRate') && finData.interestRate !== undefined && finData.interestRate !== null) {
                document.getElementById('interestRate').value = finData.interestRate || '';
            }
        }
        
        // تطبيق بيانات التمويل بالدين
        if (data.debtFinancing) {
            const debtData = data.debtFinancing;
            
            if (document.getElementById('loanAmount') && debtData.loanAmount !== undefined) {
                document.getElementById('loanAmount').value = debtData.loanAmount;
            }
            if (document.getElementById('loanInterestRate') && debtData.interestRate !== undefined) {
                document.getElementById('loanInterestRate').value = debtData.interestRate;
            }
            if (document.getElementById('loanPeriod') && debtData.loanPeriod !== undefined) {
                document.getElementById('loanPeriod').value = debtData.loanPeriod;
            }
        }
        
        // تطبيق بيانات الخصم
        if (data.discounting) {
            const discData = data.discounting;
            
            if (document.getElementById('costOfEquity') && discData.costOfEquity !== undefined) {
                document.getElementById('costOfEquity').value = discData.costOfEquity;
            }
            if (document.getElementById('costOfDebt') && discData.costOfDebt !== undefined) {
                document.getElementById('costOfDebt').value = discData.costOfDebt;
            }
        }
        
        // تطبيق بيانات الخروج
        if (data.exit) {
            const exitData = data.exit;
            
            if (document.getElementById('exitYear') && exitData.year !== undefined) {
                document.getElementById('exitYear').value = exitData.year;
            }
            if (document.getElementById('expectedNOI') && exitData.expectedNOI !== undefined) {
                document.getElementById('expectedNOI').value = exitData.expectedNOI;
            }
            if (document.getElementById('exitCapRate') && exitData.capRate !== undefined) {
                document.getElementById('exitCapRate').value = exitData.capRate;
            }
        }
        
        // تطبيق فترات المشروع
        if (data.projectPeriods) {
            const periodsData = data.projectPeriods;
            
            if (document.getElementById('constructionPeriod') && periodsData.constructionPeriod !== undefined && periodsData.constructionPeriod !== null) {
                document.getElementById('constructionPeriod').value = periodsData.constructionPeriod || '';
                
                // تحديث النظام بعد تطبيق القيمة
                if (typeof handleConstructionPeriodChange === 'function') {
                    setTimeout(() => handleConstructionPeriodChange(), 100);
                }
            }
            if (document.getElementById('operatingPeriod') && periodsData.operatingPeriod !== undefined && periodsData.operatingPeriod !== null) {
                document.getElementById('operatingPeriod').value = periodsData.operatingPeriod || '';
                
                // تحديث المعاملات العامة
                if (typeof updateInvestmentParameters === 'function') {
                    setTimeout(() => updateInvestmentParameters(), 100);
                }
            }
        }
        
        // تطبيق الافتراضات
        if (data.assumptions) {
            const assumptionsData = data.assumptions;
            
            if (document.getElementById('inflationRate') && assumptionsData.inflationRate !== undefined) {
                document.getElementById('inflationRate').value = assumptionsData.inflationRate;
            }
            if (document.getElementById('revenueGrowthRate') && assumptionsData.revenueGrowthRate !== undefined) {
                document.getElementById('revenueGrowthRate').value = assumptionsData.revenueGrowthRate;
            }
            if (document.getElementById('stabilizedOccupancy') && assumptionsData.stabilizedOccupancy !== undefined) {
                document.getElementById('stabilizedOccupancy').value = assumptionsData.stabilizedOccupancy;
            }
            if (document.getElementById('occupancyYear1') && assumptionsData.occupancyYear1 !== undefined) {
                document.getElementById('occupancyYear1').value = assumptionsData.occupancyYear1;
            }
            if (document.getElementById('occupancyYear2') && assumptionsData.occupancyYear2 !== undefined) {
                document.getElementById('occupancyYear2').value = assumptionsData.occupancyYear2;
            }
            if (document.getElementById('occupancyYear3') && assumptionsData.occupancyYear3 !== undefined) {
                document.getElementById('occupancyYear3').value = assumptionsData.occupancyYear3;
            }
            if (document.getElementById('vacancyAllowance') && assumptionsData.vacancyAllowance !== undefined) {
                document.getElementById('vacancyAllowance').value = assumptionsData.vacancyAllowance;
            }
        }
        
        console.log('✅ تم تطبيق البيانات على عناصر HTML بنجاح');
        
    } catch (error) {
        console.error('❌ خطأ في تطبيق البيانات على HTML:', error);
    }
}

