/**
 * تصدير بيانات نظام إدارة الاستخدامات المحسن
 * Export Enhanced Uses Management System data with comprehensive validation
 */
function exportUsesData() {
    try {
        console.log('🏗️ بدء عملية تصدير بيانات نظام إدارة الاستخدامات المحسن...');
        
        // التحقق من وجود البيانات من النافذة أو HTML
        let usesDataToExport = null;
        
        // محاولة الحصول على البيانات من النافذة أو المتغير العام
        if (typeof window.usesData !== 'undefined') {
            usesDataToExport = window.usesData;
        } else if (typeof usesData !== 'undefined') {
            usesDataToExport = usesData;
        } else {
            // جمع البيانات من العناصر الموجودة في HTML
            usesDataToExport = collectUsesDataFromHTML();
        }
        
        // التحقق من وجود البيانات
        if (!usesDataToExport || typeof usesDataToExport !== 'object') {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'لا توجد بيانات استخدامات للتصدير', 
                'warning'
            );
            return false;
        }

        // إنشاء نسخة عميقة من البيانات
        const usesSnapshot = JSON.parse(JSON.stringify(usesDataToExport));
        
        // جمع معلومات إضافية من الواجهة
        const additionalUsesInfo = {};
        
        // جمع إعدادات المشروع العامة
        const projectSettings = collectProjectSettings();
        additionalUsesInfo.projectSettings = projectSettings;
        
        // جمع بيانات الإجماليات المحسوبة
        const calculatedTotals = calculateUsesTotals(usesSnapshot);
        additionalUsesInfo.calculatedTotals = calculatedTotals;

        // معلومات التصدير
        const exportData = {
            exportInfo: {
                timestamp: new Date().toISOString(),
                version: '1.0.0',
                exportType: 'uses',
                systemName: 'دراسة الجدوى العقارية - نظام إدارة الاستخدامات المحسن',
                description: 'تصدير شامل لبيانات نظام الاستخدامات مع جميع الإعدادات والحسابات'
            },
            usesData: usesSnapshot,
            additionalInfo: additionalUsesInfo,
            metadata: {
                exportedAt: new Date().toLocaleString('en-US'),
                projectName: document.getElementById('projectName')?.value || 'مشروع غير محدد',
                clientName: document.getElementById('clientName')?.value || 'عميل غير محدد',
                landArea: document.getElementById('landArea')?.value || 0,
                totalGFA: calculatedTotals.totalGFA,
                totalGLA: calculatedTotals.totalGLA,
                totalUnits: calculatedTotals.totalUnits,
                usesCount: Object.keys(usesSnapshot).length,
                componentsSummary: {
                    usesTypes: Object.keys(usesSnapshot).join(', '),
                    hasRevenueSettings: Object.values(usesSnapshot).some(use => use.revenueSettings),
                    hasSubUnits: Object.values(usesSnapshot).some(use => use.subUnits && use.subUnits.length > 0)
                }
            }
        };

        // تنزيل الملف
        const filename = `uses_management_data_${new Date().toISOString().split('T')[0]}_${Math.floor(Date.now() / 1000)}.json`;
        downloadJSONFile(exportData, filename);
        
        console.log('✅ تم تصدير بيانات نظام إدارة الاستخدامات المحسن بنجاح');
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            '✅ تم تصدير بيانات نظام إدارة الاستخدامات المحسن بنجاح!\n' + 
            `🏗️ إجمالي المساحة المبنية: ${exportData.metadata.totalGFA.toLocaleString('en-US')} م²\n` +
            `🏢 إجمالي المساحة القابلة للتأجير: ${exportData.metadata.totalGLA.toLocaleString('en-US')} م²\n` +
            `🔢 إجمالي الوحدات: ${exportData.metadata.totalUnits.toLocaleString('en-US')} وحدة\n` +
            `📂 أنواع الاستخدامات: ${exportData.metadata.usesCount}\n` +
            `📁 اسم الملف: ${filename}`,
            'success',
            7000
        );
        
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تصدير بيانات نظام إدارة الاستخدامات المحسن:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تصدير بيانات الاستخدامات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * جمع بيانات الاستخدامات من عناصر HTML
 * Collect uses data from HTML elements
 */
function collectUsesDataFromHTML() {
    try {
        console.log('🔍 جمع بيانات الاستخدامات من عناصر HTML...');
        
        const data = {};
        
        // البحث عن جميع أقسام الاستخدامات في الجدول
        const usesRows = document.querySelectorAll('#usesGrid tbody tr');
        
        usesRows.forEach(row => {
            const useId = row.getAttribute('data-use-id');
            if (!useId) return;
            
            const cells = row.querySelectorAll('td');
            if (cells.length >= 6) {
                const useData = {
                    id: useId,
                    name: cells[0].textContent.trim(),
                    nameEn: cells[0].getAttribute('data-name-en') || useId,
                    icon: cells[0].querySelector('span')?.textContent || '🏢',
                    color: row.getAttribute('data-color') || 'gray',
                    share: parseFloat(cells[1].textContent) || 0,
                    efficiency: parseFloat(cells[2].textContent) || 0,
                    totalGLA: parseFloat(cells[3].textContent?.replace(/,/g, '')) || 0,
                    totalUnits: parseFloat(cells[4].textContent?.replace(/,/g, '')) || 0,
                    countInGLA: collectGLACounting(useId), // ✅ جمع حالة احتساب GLA
                    revenueSettings: collectRevenueSettings(useId),
                    subUnits: collectSubUnits(useId)
                };
                
                data[useId] = useData;
            }
        });
        
        console.log('✅ تم جمع بيانات الاستخدامات من HTML بنجاح');
        return data;
        
    } catch (error) {
        console.error('❌ خطأ في جمع بيانات الاستخدامات من HTML:', error);
        return null;
    }
}

/**
 * جمع حالة احتساب GLA لاستخدام معين
 */
function collectGLACounting(useId) {
    try {
        // محاولة الحصول على القيمة من window.usesData أولاً (أدق)
        if (window.usesData && window.usesData[useId]) {
            return window.usesData[useId].countInGLA !== false;
        }
        
        // محاولة قراءة من checkbox إذا كان موجوداً
        const checkbox = document.querySelector(`[data-use="${useId}"] input[onchange*="toggleGLACounting"]`);
        if (checkbox) {
            return checkbox.checked;
        }
        
        // الافتراضي: محسوب في GLA
        return true;
    } catch (error) {
        console.error('خطأ في جمع حالة GLA:', error);
        return true;  // الافتراضي: محسوب في GLA
    }
}

/**
 * جمع إعدادات الإيرادات لاستخدام معين
 */
function collectRevenueSettings(useId) {
    try {
        const revenuePanel = document.querySelector(`[data-use="${useId}"] .revenue-settings`);
        if (!revenuePanel) {
            return {
                rentalEnabled: true,
                salesEnabled: true,
                rentalLabel: "إيجار سنوي",
                salesLabel: "بيع مباشر"
            };
        }
        
        return {
            rentalEnabled: revenuePanel.querySelector('[data-type="rental"]')?.checked || false,
            salesEnabled: revenuePanel.querySelector('[data-type="sales"]')?.checked || false,
            rentalLabel: revenuePanel.querySelector('[data-type="rental"]')?.getAttribute('data-label') || "إيجار سنوي",
            salesLabel: revenuePanel.querySelector('[data-type="sales"]')?.getAttribute('data-label') || "بيع مباشر"
        };
    } catch (error) {
        console.error('خطأ في جمع إعدادات الإيرادات:', error);
        return {
            rentalEnabled: true,
            salesEnabled: true,
            rentalLabel: "إيجار",
            salesLabel: "بيع"
        };
    }
}

/**
 * جمع بيانات الوحدات الفرعية لاستخدام معين
 */
function collectSubUnits(useId) {
    try {
        const subUnits = [];
        const subUnitRows = document.querySelectorAll(`[data-use="${useId}"] .sub-unit-row`);
        
        subUnitRows.forEach((row, index) => {
            const inputs = row.querySelectorAll('input');
            if (inputs.length >= 4) {
                subUnits.push({
                    id: `${useId}_${index + 1}`,
                    name: inputs[0].value || `وحدة ${index + 1}`,
                    percentage: parseFloat(inputs[1].value) || 0,
                    efficiency: parseFloat(inputs[2].value) || 0,
                    areaPerUnit: parseFloat(inputs[3].value) || 0,
                    units: parseFloat(inputs[4]?.value) || 0
                });
            }
        });
        
        return subUnits;
    } catch (error) {
        console.error('خطأ في جمع بيانات الوحدات الفرعية:', error);
        return [];
    }
}

/**
 * جمع إعدادات المشروع العامة
 */
function collectProjectSettings() {
    try {
        return {
            totalGFA: document.getElementById('totalGFADisplay')?.textContent?.replace(/,/g, '') || 0,
            landArea: document.getElementById('landArea')?.value || 0,
            FAR: document.getElementById('FAR')?.value || 0,
            defaultEfficiency: document.getElementById('defaultEfficiency')?.value || 80
        };
    } catch (error) {
        console.error('خطأ في جمع إعدادات المشروع:', error);
        return {};
    }
}

/**
 * حساب الإجماليات من بيانات الاستخدامات
 */
function calculateUsesTotals(usesData) {
    try {
        let totalGFA = 0;
        let totalGLA = 0; 
        let totalUnits = 0;
        
        Object.values(usesData).forEach(use => {
            totalGLA += use.totalGLA || 0;
            totalUnits += use.totalUnits || 0;
        });
        
        // حساب إجمالي GFA من GLA والكفاءة
        if (totalGLA > 0) {
            const avgEfficiency = Object.values(usesData).reduce((sum, use) => sum + (use.efficiency || 80), 0) / Object.keys(usesData).length;
            totalGFA = totalGLA / (avgEfficiency / 100);
        }
        
        return {
            totalGFA: Math.round(totalGFA),
            totalGLA: Math.round(totalGLA),
            totalUnits: totalUnits
        };
    } catch (error) {
        console.error('خطأ في حساب الإجماليات:', error);
        return {
            totalGFA: 0,
            totalGLA: 0,
            totalUnits: 0
        };
    }
}

/**
 * استيراد بيانات نظام إدارة الاستخدامات المحسن
 * Import Enhanced Uses Management System data with comprehensive validation
 */
function importUsesData() {
    try {
        console.log('🏗️ بدء عملية استيراد بيانات نظام إدارة الاستخدامات المحسن...');
        
        // إنشاء عنصر input للملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = function(event) {
            const file = event.target.files[0];
            if (!file) {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'لم يتم اختيار ملف',
                    'warning'
                );
                return;
            }
            
            if (!file.name.toLowerCase().endsWith('.json')) {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'يرجى اختيار ملف JSON صالح',
                    'error'
                );
                return;
            }
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    
                    // التحقق من صحة البيانات
                    if (validateImportedUsesData(importedData)) {
                        // تطبيق البيانات
                        if (applyImportedUsesData(importedData)) {
                            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                                '✅ تم استيراد بيانات نظام الاستخدامات بنجاح!\n' +
                                'تم تطبيق جميع الإعدادات والبيانات المحفوظة.',
                                'success',
                                5000
                            );
                            
                            // تحديث النظام
                            setTimeout(() => {
                                if (typeof updateUsesCalculations === 'function') {
                                    updateUsesCalculations();
                                }
                                if (typeof refreshUsesDisplay === 'function') {
                                    refreshUsesDisplay();
                                }
                            }, 500);
                        }
                    }
                } catch (parseError) {
                    console.error('خطأ في تحليل ملف JSON:', parseError);
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'خطأ في تحليل الملف: تأكد من أن الملف بتنسيق JSON صالح',
                        'error'
                    );
                }
            };
            
            reader.readAsText(file);
        };
        
        // إضافة العنصر إلى DOM وتفعيله
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ فشل في بدء عملية الاستيراد:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في بدء عملية الاستيراد: ' + error.message,
            'error'
        );
    }
}

/**
 * التحقق من صحة البيانات المستوردة لنظام الاستخدامات
 * Validate imported uses data structure and content
 */
function validateImportedUsesData(data) {
    try {
        console.log('🔍 التحقق من صحة بيانات الاستخدامات المستوردة...');
        
        // التحقق من البنية الأساسية
        if (!data || typeof data !== 'object') {
            throw new Error('البيانات المستوردة غير صحيحة');
        }
        
        // التحقق من نوع التصدير
        if (data.exportInfo.exportType !== 'uses') {
            throw new Error('نوع الملف المستورد غير صحيح. يجب أن يكون ملف بيانات الاستخدامات');
        }
        
        // التحقق من وجود بيانات الاستخدامات
        if (!data.usesData || typeof data.usesData !== 'object') {
            throw new Error('بيانات الاستخدامات مفقودة أو غير صحيحة');
        }
        
        // التحقق من وجود استخدامات
        const usesCount = Object.keys(data.usesData).length;
        if (usesCount === 0) {
            throw new Error('لا توجد استخدامات في الملف المستورد');
        }
        
        // التحقق من بنية كل استخدام
        Object.entries(data.usesData).forEach(([key, use]) => {
            if (!use.id || !use.name) {
                throw new Error(`بيانات الاستخدام "${key}" غير مكتملة`);
            }
            
            if (typeof use.share !== 'number' || use.share < 0 || use.share > 100) {
                console.warn(`⚠️ نسبة الاستخدام "${use.name}" خارج النطاق المتوقع (0-100%):`, use.share);
            }
            
            if (typeof use.efficiency !== 'number' || use.efficiency < 0 || use.efficiency > 100) {
                console.warn(`⚠️ كفاءة الاستخدام "${use.name}" خارج النطاق المتوقع (0-100%):`, use.efficiency);
            }
        });
        
        console.log('✅ تم التحقق من صحة بيانات الاستخدامات بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في التحقق من البيانات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'البيانات المستوردة غير صحيحة: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق البيانات المستوردة لنظام الاستخدامات
 * Apply imported uses data to the system
 */
function applyImportedUsesData(importedData) {
    try {
        console.log('🎨 تطبيق بيانات الاستخدامات المستوردة...');
        
        const usesData = importedData.usesData;
        const additionalInfo = importedData.additionalInfo || {};
        
        // تحديث البيانات العامة
        if (window.usesData) {
            // تحديث البيانات العامة في النافذة
            Object.assign(window.usesData, usesData);
        } else {
            // إنشاء البيانات إذا لم تكن موجودة
            window.usesData = JSON.parse(JSON.stringify(usesData));
        }
        
        // تطبيق البيانات على عناصر HTML
        applyUsesDataToHTML(usesData);
        
        // تطبيق الإعدادات الإضافية
        if (additionalInfo.projectSettings) {
            applyProjectSettings(additionalInfo.projectSettings);
        }
        
        // إعادة حساب وتحديث النظام
        setTimeout(() => {
            // تحديث العرض والحسابات
            if (typeof calculateUsesDistribution === 'function') {
                calculateUsesDistribution();
                console.log('✅ تم تحديث حساب توزيع الاستخدامات');
            }
            
            if (typeof updateUsesTable === 'function') {
                updateUsesTable();
                console.log('✅ تم تحديث جدول الاستخدامات');
            }
            
            if (typeof refreshUsesSummary === 'function') {
                refreshUsesSummary();
                console.log('✅ تم تحديث ملخص الاستخدامات');
            }
            
            // تطبيق القيم على واجهة المستخدم
            setTimeout(() => {
                if (FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI) {
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI();
                    console.log('✅ تم تطبيق القيم على واجهة المستخدم');
                }
            }, 300);
        }, 200);
        
        console.log('✅ تم تطبيق بيانات الاستخدامات المستوردة بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تطبيق بيانات الاستخدامات:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تطبيق البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق بيانات الاستخدامات على عناصر HTML
 * Apply uses data to HTML elements
 */
function applyUsesDataToHTML(usesData) {
    try {
        console.log('🎨 تطبيق بيانات الاستخدامات على عناصر HTML...');
        
        Object.entries(usesData).forEach(([useId, useData]) => {
            // تحديث صف الاستخدام في الجدول
            const useRow = document.querySelector(`#usesGrid tr[data-use-id="${useId}"]`);
            if (useRow) {
                const cells = useRow.querySelectorAll('td');
                if (cells.length >= 6) {
                    // تحديث النسبة
                    const shareInput = cells[1].querySelector('input');
                    if (shareInput) shareInput.value = useData.share || 0;
                    
                    // تحديث الكفاءة
                    const efficiencyInput = cells[2].querySelector('input');
                    if (efficiencyInput) efficiencyInput.value = useData.efficiency || 0;
                    
                    // تحديث المساحة القابلة للتأجير
                    if (cells[3]) cells[3].textContent = (useData.totalGLA || 0).toLocaleString('en-US');
                    
                    // تحديث عدد الوحدات
                    if (cells[4]) cells[4].textContent = (useData.totalUnits || 0).toLocaleString('en-US');
                }
            }
            
            // تطبيق إعدادات الإيرادات
            if (useData.revenueSettings) {
                applyRevenueSettings(useId, useData.revenueSettings);
            }
            
            // ✅ تطبيق حالة احتساب GLA
            if (useData.countInGLA !== undefined) {
                applyGLACounting(useId, useData.countInGLA);
            }
            
            // تطبيق بيانات الوحدات الفرعية
            if (useData.subUnits && useData.subUnits.length > 0) {
                applySubUnitsData(useId, useData.subUnits);
            }
        });
        
        console.log('✅ تم تطبيق البيانات على عناصر HTML بنجاح');
        
    } catch (error) {
        console.error('❌ خطأ في تطبيق البيانات على HTML:', error);
    }
}

/**
 * تطبيق حالة احتساب GLA
 */
