/**
 * تصدير بيانات نظام إدارة الأدوار
 * Export Floors Management System data with comprehensive validation
 */
function exportFloorsData() {
    try {
        console.log('🏢 بدء عملية تصدير بيانات نظام إدارة الأدوار...');
        
        // التحقق من وجود البيانات من النافذة أو HTML
        let floorsDataToExport = null;
        
        // محاولة الحصول على البيانات من النافذة أو المتغير العام
        if (typeof window.floorsData !== 'undefined') {
            floorsDataToExport = window.floorsData;
        } else if (typeof floorsData !== 'undefined') {
            floorsDataToExport = floorsData;
        } else {
            // جمع البيانات من العناصر الموجودة في HTML
            floorsDataToExport = collectFloorsDataFromHTML();
        }
        
        // التحقق من وجود البيانات
        if (!floorsDataToExport || (!Array.isArray(floorsDataToExport) && typeof floorsDataToExport !== 'object')) {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'لا توجد بيانات أدوار للتصدير', 
                'warning'
            );
            return false;
        }

        // إنشاء نسخة عميقة من البيانات
        const floorsSnapshot = JSON.parse(JSON.stringify(floorsDataToExport));
        
        // جمع معلومات إضافية من الواجهة
        const additionalFloorsInfo = {};
        
        // جمع إعدادات المشروع العامة
        const projectSettings = collectProjectSettings();
        additionalFloorsInfo.projectSettings = projectSettings;
        
        // جمع بيانات الإجماليات المحسوبة
        const calculatedTotals = calculateFloorsTotals(floorsSnapshot);
        additionalFloorsInfo.calculatedTotals = calculatedTotals;

        // معلومات التصدير
        const exportData = {
            exportInfo: {
                timestamp: new Date().toISOString(),
                version: '1.0.0',
                exportType: 'floors',
                systemName: 'دراسة الجدوى العقارية - نظام إدارة الأدوار',
                description: 'تصدير شامل لبيانات نظام إدارة الأدوار مع جميع الإعدادات والحسابات'
            },
            floorsData: floorsSnapshot,
            additionalInfo: additionalFloorsInfo,
            metadata: {
                exportedAt: new Date().toLocaleString('en-US'),
                projectName: document.getElementById('projectName')?.value || 'مشروع غير محدد',
                clientName: document.getElementById('clientName')?.value || 'عميل غير محدد',
                landArea: document.getElementById('landArea')?.value || 0,
                totalGFA: calculatedTotals.totalGFA,
                totalNetArea: calculatedTotals.totalNetArea,
                totalServiceArea: calculatedTotals.totalServiceArea,
                floorsCount: Array.isArray(floorsSnapshot) ? floorsSnapshot.length : Object.keys(floorsSnapshot).length,
                componentsSummary: {
                    floorTypes: Array.isArray(floorsSnapshot) 
                        ? floorsSnapshot.map(floor => floor.usage || 'mixed').join(', ')
                        : Object.keys(floorsSnapshot).join(', '),
                    hasCalculations: Array.isArray(floorsSnapshot) 
                        ? floorsSnapshot.some(floor => floor.calculatedArea)
                        : Object.values(floorsSnapshot).some(floor => floor.calculatedArea),
                    hasOrderSettings: Array.isArray(floorsSnapshot) 
                        ? floorsSnapshot.some(floor => floor.order !== undefined)
                        : Object.values(floorsSnapshot).some(floor => floor.order !== undefined)
                }
            }
        };

        // تنزيل الملف
        const filename = `floors_management_data_${new Date().toISOString().split('T')[0]}_${Math.floor(Date.now() / 1000)}.json`;
        downloadJSONFile(exportData, filename);
        
        console.log('✅ تم تصدير بيانات نظام إدارة الأدوار بنجاح');
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            '✅ تم تصدير بيانات نظام إدارة الأدوار بنجاح!\n' + 
            `🏢 إجمالي المساحة المبنية: ${exportData.metadata.totalGFA.toLocaleString('en-US')} م²\n` +
            `📐 إجمالي المساحة الصافية: ${exportData.metadata.totalNetArea.toLocaleString('en-US')} م²\n` +
            `🔧 إجمالي مساحة الخدمات: ${exportData.metadata.totalServiceArea.toLocaleString('en-US')} م²\n` +
            `🔢 عدد الأدوار: ${exportData.metadata.floorsCount}\n` +
            `📁 اسم الملف: ${filename}`,
            'success',
            7000
        );
        
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تصدير بيانات نظام إدارة الأدوار:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ أثناء تصدير البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * جمع بيانات الأدوار من عناصر HTML
 * Collect floors data from HTML elements
 */
function collectFloorsDataFromHTML() {
    try {
        console.log('📋 جمع بيانات الأدوار من عناصر HTML...');
        
        const floorsData = [];
        const floorsTableBody = document.getElementById('floorsTableBody');
        
        if (!floorsTableBody) {
            console.warn('⚠️ لم يتم العثور على جدول الأدوار');
            return [];
        }
        
        // قراءة صفوف الجدول
        const rows = floorsTableBody.querySelectorAll('tr');
        
        rows.forEach((row, index) => {
            const cells = row.querySelectorAll('td');
            
            if (cells.length >= 8) { // تأكد من وجود جميع الأعمدة
                const floorData = {
                    id: row.dataset.floorId || `floor_${index}`,
                    number: cells[0]?.textContent?.trim() || '',
                    usage: cells[1]?.textContent?.trim() || 'mixed',
                    reference: cells[2]?.textContent?.trim() || 'landArea',
                    percentage: parseFloat(cells[3]?.textContent?.trim()) || 0,
                    servicePercentage: parseFloat(cells[4]?.textContent?.trim()) || 15,
                    calculatedArea: parseFloat(cells[5]?.textContent?.replace(/[^\d.]/g, '')) || 0,
                    netArea: parseFloat(cells[6]?.textContent?.replace(/[^\d.]/g, '')) || 0,
                    serviceArea: parseFloat(cells[7]?.textContent?.replace(/[^\d.]/g, '')) || 0,
                    order: parseInt(cells[8]?.textContent?.trim()) || index + 1,
                    enabled: !row.classList.contains('disabled')
                };
                
                floorsData.push(floorData);
            }
        });
        
        console.log(`📋 تم جمع ${floorsData.length} دور من HTML`);
        return floorsData;
        
    } catch (error) {
        console.error('❌ خطأ في جمع بيانات الأدوار من HTML:', error);
        return [];
    }
}

/**
 * حساب إجماليات الأدوار
 * Calculate floors totals for export metadata
 */
function calculateFloorsTotals(floorsData) {
    try {
        const floorsArray = Array.isArray(floorsData) ? floorsData : Object.values(floorsData);
        
        let totalGFA = 0;
        let totalNetArea = 0;
        let totalServiceArea = 0;
        let enabledFloorsCount = 0;
        
        floorsArray.forEach(floor => {
            if (floor.enabled !== false) { // تضمين الأدوار المفعلة فقط
                totalGFA += parseFloat(floor.calculatedArea) || 0;
                totalNetArea += parseFloat(floor.netArea) || 0;
                totalServiceArea += parseFloat(floor.serviceArea) || 0;
                enabledFloorsCount++;
            }
        });
        
        return {
            totalGFA,
            totalNetArea,
            totalServiceArea,
            enabledFloorsCount,
            totalFloorsCount: floorsArray.length
        };
        
    } catch (error) {
        console.error('❌ خطأ في حساب إجماليات الأدوار:', error);
        return {
            totalGFA: 0,
            totalNetArea: 0,
            totalServiceArea: 0,
            enabledFloorsCount: 0,
            totalFloorsCount: 0
        };
    }
}

/**
 * استيراد بيانات نظام إدارة الأدوار
 * Import Floors Management System data with validation
 */
function importFloorsData() {
    try {
        console.log('📥 بدء عملية استيراد بيانات نظام إدارة الأدوار...');
        
        // إنشاء عنصر input لاختيار الملف
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.json';
        input.style.display = 'none';
        
        input.onchange = function(e) {
            const file = e.target.files[0];
            if (!file) {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'لم يتم اختيار ملف',
                    'warning'
                );
                return;
            }
            
            if (!file.name.toLowerCase().endsWith('.json')) {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'يرجى اختيار ملف JSON صحيح',
                    'error'
                );
                return;
            }
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const importedData = JSON.parse(e.target.result);
                    
                    // التحقق من صحة البيانات المستوردة
                    if (validateImportedFloorsData(importedData)) {
                        // تطبيق البيانات المستوردة
                        if (applyImportedFloorsData(importedData)) {
                            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                                '✅ تم استيراد بيانات نظام إدارة الأدوار بنجاح!\n' +
                                `📊 تم استيراد ${importedData.metadata?.floorsCount || 0} دور\n` +
                                `🏢 إجمالي المساحة المبنية: ${(importedData.metadata?.totalGFA || 0).toLocaleString('en-US')} م²\n` +
                                `📐 إجمالي المساحة الصافية: ${(importedData.metadata?.totalNetArea || 0).toLocaleString('en-US')} م²\n` +
                                `⏰ تاريخ التصدير: ${importedData.metadata?.exportedAt || 'غير محدد'}`,
                                'success',
                                8000
                            );
                        }
                    }
                    
                } catch (parseError) {
                    console.error('❌ خطأ في تحليل ملف JSON:', parseError);
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                        'الملف المحدد لا يحتوي على بيانات JSON صحيحة',
                        'error'
                    );
                }
            };
            
            reader.onerror = function() {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    'حدث خطأ أثناء قراءة الملف',
                    'error'
                );
            };
            
            reader.readAsText(file);
        };
        
        document.body.appendChild(input);
        input.click();
        document.body.removeChild(input);
        
    } catch (error) {
        console.error('❌ فشل في استيراد بيانات نظام إدارة الأدوار:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ أثناء استيراد البيانات: ' + error.message,
            'error'
        );
    }
}

/**
 * التحقق من صحة البيانات المستوردة للأدوار
 * Validate imported floors data structure and content
 */
function validateImportedFloorsData(importedData) {
    try {
        console.log('🔍 التحقق من صحة بيانات الأدوار المستوردة...');
        
        // التحقق من البنية الأساسية
        if (!importedData || typeof importedData !== 'object') {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'بنية البيانات المستوردة غير صحيحة',
                'error'
            );
            return false;
        }
        
        // التحقق من معلومات التصدير
        if (!importedData.exportInfo || importedData.exportInfo.exportType !== 'floors') {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'هذا الملف لا يحتوي على بيانات نظام إدارة الأدوار',
                'error'
            );
            return false;
        }
        
        // التحقق من وجود بيانات الأدوار
        if (!importedData.floorsData) {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'لا توجد بيانات أدوار في الملف المستورد',
                'error'
            );
            return false;
        }
        
        // التحقق من صحة بيانات الأدوار
        const floorsData = importedData.floorsData;
        const floorsArray = Array.isArray(floorsData) ? floorsData : Object.values(floorsData);
        
        // التحقق من وجود أدوار
        if (floorsArray.length === 0) {
            FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                'الملف المستورد لا يحتوي على أي أدوار',
                'warning'
            );
            return false;
        }
        
        // التحقق من صحة بيانات كل دور
        for (let i = 0; i < floorsArray.length; i++) {
            const floor = floorsArray[i];
            
            if (!floor || typeof floor !== 'object') {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    `بيانات الدور رقم ${i + 1} غير صحيحة`,
                    'error'
                );
                return false;
            }
            
            // التحقق من الحقول المطلوبة
            const requiredFields = ['number', 'usage', 'reference', 'percentage'];
            for (const field of requiredFields) {
                if (floor[field] === undefined || floor[field] === null) {
                    console.warn(`⚠️ حقل مفقود في الدور ${i + 1}: ${field}`);
                }
            }
            
            // التحقق من صحة القيم الرقمية
            if (floor.percentage !== undefined && (isNaN(floor.percentage) || floor.percentage < 0 || floor.percentage > 200)) {
                FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
                    `نسبة غير صحيحة في الدور "${floor.number}": ${floor.percentage}%`,
                    'warning'
                );
            }
            
            if (floor.servicePercentage !== undefined && (isNaN(floor.servicePercentage) || floor.servicePercentage < 0 || floor.servicePercentage > 100)) {
                console.warn(`⚠️ نسبة خدمات غير صحيحة في الدور "${floor.number}": ${floor.servicePercentage}%`);
            }
        }
        
        console.log('✅ تم التحقق من صحة بيانات الأدوار بنجاح');
        console.log(`📊 عدد الأدوار: ${floorsArray.length}`);
        
        return true;
        
    } catch (error) {
        console.error('❌ خطأ في التحقق من صحة بيانات الأدوار:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ أثناء التحقق من صحة البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق البيانات المستوردة للأدوار
 * Apply imported floors data to the system
 */
function applyImportedFloorsData(importedData) {
    try {
        console.log('🔄 تطبيق بيانات الأدوار المستوردة...');
        
        // إنشاء نسخة عميقة من البيانات المستوردة
        const newFloorsData = JSON.parse(JSON.stringify(importedData.floorsData));
        
        // تطبيق البيانات على النظام العام
        if (typeof window !== 'undefined') {
            window.floorsData = newFloorsData;
        }
        
        // تطبيق البيانات على المتغير العام إذا كان موجوداً
        if (typeof floorsData !== 'undefined') {
            if (Array.isArray(newFloorsData)) {
                // إذا كانت البيانات المستوردة مصفوفة، استبدل المصفوفة
                floorsData.length = 0; // مسح المحتويات
                floorsData.push(...newFloorsData);
            } else {
                // إذا كانت البيانات المستوردة كائن، استبدل الخصائص
                Object.keys(floorsData).forEach(key => delete floorsData[key]);
                Object.assign(floorsData, newFloorsData);
            }
        }
        
        // تطبيق البيانات على عناصر HTML
        applyFloorsDataToHTML(newFloorsData);
        
        // تطبيق المعلومات الإضافية
        if (importedData.additionalInfo) {
            console.log('🔧 تطبيق الإعدادات الإضافية...');
            
            // تطبيق إعدادات المشروع
            if (importedData.additionalInfo.projectSettings) {
                applyProjectSettings(importedData.additionalInfo.projectSettings);
            }
        }
        
        // إعادة حساب وتحديث النظام
        setTimeout(() => {
            // تحديث عرض الأدوار
            if (typeof updateFloorsDisplay === 'function') {
                updateFloorsDisplay();
                console.log('✅ تم تحديث عرض الأدوار');
            }
            
            // تحديث ملخص الأدوار
            if (typeof updateFloorsSummary === 'function') {
                updateFloorsSummary();
                console.log('✅ تم تحديث ملخص الأدوار');
            }
            
            // Efficiency summary system removed
            
            // تطبيق القيم على واجهة المستخدم
            setTimeout(() => {
                if (FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI) {
                    FEASIBILITY_EXPORT_IMPORT_SYSTEM.applyValuesToUI();
                    console.log('✅ تم تطبيق القيم على واجهة المستخدم');
                }
            }, 300);
        }, 200);
        
        console.log('✅ تم تطبيق بيانات الأدوار المستوردة بنجاح');
        return true;
        
    } catch (error) {
        console.error('❌ فشل في تطبيق بيانات الأدوار المستوردة:', error);
        FEASIBILITY_EXPORT_IMPORT_SYSTEM.showNotification(
            'حدث خطأ في تطبيق البيانات: ' + error.message,
            'error'
        );
        return false;
    }
}

/**
 * تطبيق بيانات الأدوار على عناصر HTML
 * Apply floors data to HTML elements
 */
function applyFloorsDataToHTML(floorsData) {
    try {
        console.log('🎨 تطبيق بيانات الأدوار على عناصر HTML...');
        
        const floorsArray = Array.isArray(floorsData) ? floorsData : Object.values(floorsData);
        const floorsTableBody = document.getElementById('floorsTableBody');
        
        if (!floorsTableBody) {
            console.warn('⚠️ لم يتم العثور على جدول الأدوار');
            return;
        }
        
        // مسح الجدول الحالي
        floorsTableBody.innerHTML = '';
        
        // إضافة الأدوار إلى الجدول
        floorsArray.forEach((floor, index) => {
            const row = document.createElement('tr');
            row.dataset.floorId = floor.id || `floor_${index}`;
            
            if (floor.enabled === false) {
                row.classList.add('disabled');
            }
            
            // تحديد استخدام الدور باللغة العربية
            const usageNames = {
                'parking': 'مواقف',
                'services': 'خدمات', 
                'reception': 'استقبال',
                'hotel': 'فندق',
                'retail': 'تجاري',
                'office': 'مكتبي',
                'residential': 'سكني',
                'mixed': 'مختلط'
            };
            
            const usageDisplayName = usageNames[floor.usage] || floor.usage || 'مختلط';
            
            row.innerHTML = `
                <td class="border border-white/20 px-2 py-1 text-center">${floor.number || ''}</td>
                <td class="border border-white/20 px-2 py-1 text-center">${usageDisplayName}</td>
                <td class="border border-white/20 px-2 py-1 text-center">${floor.reference === 'landArea' ? 'مساحة الأرض' : floor.reference || ''}</td>
                <td class="border border-white/20 px-2 py-1 text-center">${(floor.percentage || 0).toFixed(1)}%</td>
                <td class="border border-white/20 px-2 py-1 text-center">${(floor.servicePercentage || 15).toFixed(1)}%</td>
                <td class="border border-white/20 px-2 py-1 text-center">${(floor.calculatedArea || 0).toLocaleString('en-US')} م²</td>
                <td class="border border-white/20 px-2 py-1 text-center">${(floor.netArea || 0).toLocaleString('en-US')} م²</td>
                <td class="border border-white/20 px-2 py-1 text-center">${(floor.serviceArea || 0).toLocaleString('en-US')} م²</td>
                <td class="border border-white/20 px-2 py-1 text-center">${floor.order || index + 1}</td>
                <td class="border border-white/20 px-2 py-1 text-center">
                    <button onclick="editFloor('${row.dataset.floorId}')" class="text-blue-200 hover:text-blue-100 mx-1" title="تعديل">
                        <i class="fas fa-edit"></i>
                    </button>
                    <button onclick="deleteFloor('${row.dataset.floorId}')" class="text-red-200 hover:text-red-100 mx-1" title="حذف">
                        <i class="fas fa-trash"></i>
                    </button>
                </td>
            `;
            
            floorsTableBody.appendChild(row);
        });
        
        console.log(`✅ تم تطبيق ${floorsArray.length} دور على جدول HTML`);
        
    } catch (error) {
        console.error('❌ خطأ في تطبيق بيانات الأدوار على HTML:', error);
    }
}

