// ==================== نظام التصدير والاستيراد لمعلومات المشروع ====================

// تصدير بيانات معلومات المشروع
function exportProjectData() {
    try {
        console.log('📤 بدء تصدير بيانات معلومات المشروع...');
        
        // جمع البيانات من جميع حقول معلومات المشروع
        const projectName = document.getElementById('projectName')?.value || '';
        const clientName = document.getElementById('clientName')?.value || '';
        const city = document.getElementById('city')?.value || '';
        const landArea = parseFloat(document.getElementById('landArea')?.value) || 0;
        const far = parseFloat(document.getElementById('far')?.value) || 0;
        const projectCode = document.getElementById('projectCode')?.value || '';
        
        // جمع الإحداثيات
        const latitude = parseFloat(document.getElementById('currentLatitude')?.value) || 0;
        const longitude = parseFloat(document.getElementById('currentLongitude')?.value) || 0;
        const locationName = document.getElementById('currentLocationName')?.textContent || '';
        
        // تجميع البيانات في كائن واحد
        const projectData = {
            // معلومات المشروع الأساسية
            projectName: projectName,
            clientName: clientName,
            city: city,
            landArea: landArea,
            far: far,
            projectCode: projectCode,
            
            // معلومات الموقع والإحداثيات
            coordinates: {
                latitude: latitude,
                longitude: longitude,
                locationName: locationName
            },
            
            // معلومات التصدير
            exportInfo: {
                timestamp: new Date().toISOString(),
                version: '1.0.0',
                exportType: 'project-information',
                description: 'معلومات المشروع الأساسية والموقع'
            }
        };
        
        // تحويل البيانات إلى JSON
        const jsonData = JSON.stringify(projectData, null, 2);
        
        // إنشاء اسم الملف
        const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
        const filename = `project-info_${projectName || 'unnamed'}_${timestamp}.json`;
        
        // إنشاء رابط التحميل
        const blob = new Blob([jsonData], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.download = filename;
        
        // تحميل الملف
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        
        // تنظيف الذاكرة
        URL.revokeObjectURL(url);
        
        console.log('✅ تم تصدير بيانات معلومات المشروع بنجاح:', filename);
        showNotification('تم تصدير بيانات معلومات المشروع بنجاح', 'success');
        
    } catch (error) {
        console.error('❌ خطأ في تصدير بيانات معلومات المشروع:', error);
        showNotification('فشل في تصدير بيانات معلومات المشروع: ' + error.message, 'error');
    }
}

// استيراد بيانات معلومات المشروع
function importProjectData() {
    try {
        console.log('📥 بدء استيراد بيانات معلومات المشروع...');
        
        // إنشاء عنصر input لاختيار الملف
        const fileInput = document.createElement('input');
        fileInput.type = 'file';
        fileInput.accept = '.json';
        fileInput.style.display = 'none';
        
        fileInput.onchange = function(event) {
            const file = event.target.files[0];
            if (!file) {
                console.log('لم يتم اختيار ملف');
                return;
            }
            
            const reader = new FileReader();
            reader.onload = function(e) {
                try {
                    const jsonData = JSON.parse(e.target.result);
                    console.log('📥 تم قراءة البيانات:', jsonData);
                    
                    // التحقق من صحة البيانات
                    if (!jsonData.exportInfo || jsonData.exportInfo.exportType !== 'project-information') {
                        throw new Error('الملف المحدد ليس ملف معلومات مشروع صحيح');
                    }
                    
                    // تطبيق البيانات على النموذج
                    applyProjectDataToForm(jsonData);
                    
                    console.log('✅ تم استيراد بيانات معلومات المشروع بنجاح');
                    showNotification('تم استيراد بيانات معلومات المشروع بنجاح', 'success');
                    
                } catch (parseError) {
                    console.error('❌ خطأ في تحليل الملف:', parseError);
                    showNotification('خطأ في قراءة الملف: ' + parseError.message, 'error');
                }
            };
            
            reader.onerror = function() {
                console.error('❌ خطأ في قراءة الملف');
                showNotification('فشل في قراءة الملف المحدد', 'error');
            };
            
            reader.readAsText(file);
        };
        
        // إضافة العنصر والنقر عليه
        document.body.appendChild(fileInput);
        fileInput.click();
        document.body.removeChild(fileInput);
        
    } catch (error) {
        console.error('❌ خطأ في استيراد بيانات معلومات المشروع:', error);
        showNotification('فشل في استيراد بيانات معلومات المشروع: ' + error.message, 'error');
    }
}

// تطبيق البيانات المستوردة على النموذج
function applyProjectDataToForm(projectData) {
    try {
        console.log('🔄 تطبيق بيانات معلومات المشروع على النموذج...');
        
        // ✅ CRITICAL FIX: حفظ البيانات في window.projectData أولاً
        if (!window.projectData) {
            window.projectData = {};
        }
        
        // تطبيق المعلومات الأساسية
        if (projectData.projectName !== undefined) {
            window.projectData.projectName = projectData.projectName;
            const projectNameField = document.getElementById('projectName');
            if (projectNameField) {
                projectNameField.value = projectData.projectName;
            }
        }
        
        if (projectData.clientName !== undefined) {
            window.projectData.clientName = projectData.clientName;
            const clientNameField = document.getElementById('clientName');
            if (clientNameField) {
                clientNameField.value = projectData.clientName;
            }
        }
        
        if (projectData.city !== undefined) {
            window.projectData.city = projectData.city;
            const cityField = document.getElementById('city');
            if (cityField) {
                cityField.value = projectData.city;
            }
        }
        
        if (projectData.landArea !== undefined && projectData.landArea > 0) {
            window.projectData.landArea = projectData.landArea;
            const landAreaField = document.getElementById('landArea');
            if (landAreaField) {
                landAreaField.value = projectData.landArea;
                console.log(`   ✅ تم تطبيق مساحة الأرض: ${projectData.landArea}`);
            }
        }
        
        if (projectData.far !== undefined && projectData.far >= 0) {
            window.projectData.far = projectData.far;
            const farField = document.getElementById('far');
            if (farField) {
                farField.value = projectData.far;
                console.log(`   ✅ تم تطبيق معامل البناء: ${projectData.far}`);
            }
        }
        
        if (projectData.projectCode !== undefined) {
            window.projectData.projectCode = projectData.projectCode;
            const projectCodeField = document.getElementById('projectCode');
            if (projectCodeField) {
                projectCodeField.value = projectData.projectCode;
            }
        }
        
        // تطبيق الإحداثيات
        if (projectData.coordinates) {
            if (projectData.coordinates.latitude !== undefined) {
                const latitudeField = document.getElementById('currentLatitude');
                if (latitudeField) {
                    latitudeField.value = projectData.coordinates.latitude;
                }
            }
            
            if (projectData.coordinates.longitude !== undefined) {
                const longitudeField = document.getElementById('currentLongitude');
                if (longitudeField) {
                    longitudeField.value = projectData.coordinates.longitude;
                }
            }
            
            if (projectData.coordinates.locationName !== undefined) {
                const locationNameField = document.getElementById('currentLocationName');
                if (locationNameField) {
                    locationNameField.textContent = projectData.coordinates.locationName;
                }
            }
            
            // تحديث الخريطة إذا توفرت الإحداثيات
            if (projectData.coordinates.latitude && projectData.coordinates.longitude) {
                if (typeof updateMapFromCoordinates === 'function') {
                    updateMapFromCoordinates();
                } else if (typeof updateMapLocation === 'function') {
                    updateMapLocation(
                        projectData.coordinates.latitude, 
                        projectData.coordinates.longitude, 
                        projectData.coordinates.locationName || 'موقع مستورد'
                    );
                }
            }
        }
        
        // ✅ FIX: لا نستدعي التحديثات هنا - سيتم استدعاؤها من FEASIBILITY_EXPORT_IMPORT_SYSTEM
        console.log('✅ تم تطبيق جميع قيم معلومات المشروع على الحقول');
        console.log(`   📊 landArea: ${window.projectData.landArea}`);
        console.log(`   📊 far: ${window.projectData.far}`);
        
        console.log('✅ تم تطبيق بيانات معلومات المشروع بنجاح');
        
    } catch (error) {
        console.error('❌ خطأ في تطبيق البيانات على النموذج:', error);
        throw error;
    }
}

