                `;
                document.body.appendChild(successNotification);
                
                setTimeout(() => {
                    successNotification.style.animation = 'slideUp 0.3s ease-out';
                    setTimeout(() => successNotification.remove(), 300);
                }, 3000);
                
                console.log('✅ [Manual Refresh] اكتمل التحديث اليدوي بنجاح!');
            } else {
                throw new Error('نظام التحديث الشامل غير متوفر');
            }
        } catch (error) {
            console.error('❌ [Manual Refresh] خطأ في التحديث:', error);
            
            // Error notification
            notification.style.animation = 'slideUp 0.3s ease-out';
            setTimeout(() => notification.remove(), 300);
            
            const errorNotification = document.createElement('div');
            errorNotification.style.cssText = notification.style.cssText.replace('667eea 0%, #764ba2', 'ef4444 0%, #dc2626');
            errorNotification.innerHTML = `
