// ✅ Initialize export button immediately when script loads
console.log('🔌 [Export Button Init] Starting initialization...');

(function initExportButtonNow() {
    console.log('🚀 [initExportButtonNow] Executing IIFE...');
    
    function attachButton() {
        console.log('🔍 [attachButton] Searching for button...');
        const btn = document.getElementById('exportComparisonButton');
        
        if (btn) {
            console.log('✅ [attachButton] Button found!', btn);
            
            if (btn.dataset.listenerAttached === 'true') {
                console.log('ℹ️ Button already has listener attached');
                return true;
            }
            
            btn.addEventListener('click', function(e) {
                e.preventDefault();
                console.log('🖱️ BUTTON CLICKED!');
                
                if (typeof window.exportForComparisonTool === 'function') {
                    console.log('✅ Function exists, calling it...');
                    window.exportForComparisonTool();
                } else {
                    console.error('❌ exportForComparisonTool not defined!');
                    alert('خطأ: وظيفة التصدير غير متاحة');
                }
            });
            
            btn.dataset.listenerAttached = 'true';
            console.log('✅ Listener attached successfully!');
            return true;
        }
        
        console.warn('⚠️ Button not found yet');
        return false;
    }
    
    // Try multiple times with increasing delays
    let attempt = 0;
    function tryAttach() {
        attempt++;
        console.log(`🔄 Attempt ${attempt}/10...`);
        
        if (attachButton()) {
            console.log('✅ SUCCESS! Button attached');
            return;
        }
        
        if (attempt < 10) {
            setTimeout(tryAttach, 300 * attempt);
        } else {
            console.error('❌ Failed to attach button after 10 attempts');
        }
    }
    
    // Start trying
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', tryAttach);
    } else {
        tryAttach();
    }
})();

