// ============================================================================
// Export Cash Flow Table to JSON for Comparison Tool
// ============================================================================
window.exportCashFlowTableToJSON = function() {
    try {
        console.log('📥 بدء تصدير جدول التدفقات النقدية...');
        
        // Get table element
        const table = document.getElementById('cashFlowTable');
        if (!table) {
            alert('⚠️ لم يتم العثور على جدول التدفقات النقدية. قم بتحديث الجدول أولاً.');
            return;
        }
        
        const tbody = table.querySelector('tbody');
        if (!tbody || tbody.children.length === 0) {
            alert('⚠️ الجدول فارغ. قم بتحديث الجدول أولاً بالضغط على "تحديث الجدول".');
            return;
        }
        
        // ✅ NEW: Check if land rent column is visible
        const landRentColumnHeader = document.getElementById('landRentColumn');
        const isLandRentVisible = landRentColumnHeader && landRentColumnHeader.offsetParent !== null;
        
        // ✅ NEW: Check if partnership columns are visible
        const partnershipHeader = document.getElementById('partnershipColumnsHeader');
        const isPartnershipVisible = partnershipHeader && partnershipHeader.offsetParent !== null;
        
        // ✅ NEW: Get actual cashFlow data if available
        const cashFlowData = window.investmentData?.cashFlow || [];
        
        // Extract table data
        const rows = [];
        const tableRows = tbody.querySelectorAll('tr');
        
        tableRows.forEach((row, rowIndex) => {
            const cells = row.querySelectorAll('td');
            if (cells.length === 0) return;
            
            // ✅ NEW: Get corresponding data from cashFlow array if available
            const dataRow = cashFlowData[rowIndex];
            
            const rowData = {
                year: cells[0]?.textContent?.trim() || '',
                capex: {
                    landCost: parseFloat(cells[1]?.textContent?.replace(/[^0-9.-]/g, '') || '0'),
                    construction: parseFloat(cells[2]?.textContent?.replace(/[^0-9.-]/g, '') || '0'),
                    loanDisbursement: parseFloat(cells[3]?.textContent?.replace(/[^0-9.-]/g, '') || '0'),
                    equity: parseFloat(cells[4]?.textContent?.replace(/[^0-9.-]/g, '') || '0')
                },
                operations: {
                    revenue: parseFloat(cells[5]?.textContent?.replace(/[^0-9.-]/g, '') || '0'),
                    opex: parseFloat(cells[6]?.textContent?.replace(/[^0-9.-]/g, '') || '0'),
                    landRent: 0,
                    noiBeforePartnership: 0,
                    noi: 0
                },
                partnership: {
                    partnerShare: 0,
                    mainPartnerShare: 0,
                    additionalPartnersShare: 0,
                    managementFee: 0
                },
                debt: {
                    debtService: 0,
                    debtPrincipal: 0,
                    debtInterest: 0,
                    debtBalance: 0
                },
                exit: {
                    strategy: '',
                    grossValue: 0,
                    sellingCosts: 0,
                    netValue: 0,
                    loanPayoff: 0,
                    partnerShare: 0,
                    totalPartnersShare: 0,
                    investorShare: 0
                },
                cashFlow: {
                    freeCashFlow: 0,
                    cumulativeCashFlow: 0,
                    noiMargin: '',
                    dscr: ''
                }
            };
            
            // Adjust indices based on column visibility
            let idx = 7;
            
            // Land rent column (if visible)
            if (isLandRentVisible) {
                rowData.operations.landRent = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
                idx++;
            }
            
            // NOI Before Partnership
            rowData.operations.noiBeforePartnership = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
            idx++;
            
            // Partnership columns (if visible)
            if (isPartnershipVisible) {
                rowData.partnership.partnerShare = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
                idx++;
                rowData.partnership.managementFee = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
                idx++;
                rowData.operations.noi = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
                idx++;
            } else {
                rowData.operations.noi = rowData.operations.noiBeforePartnership;
            }
            
            // ✅ NEW: Add detailed partnership and exit data from dataRow if available
            if (dataRow) {
                rowData.partnership.mainPartnerShare = dataRow.mainPartnerShare || 0;
                rowData.partnership.additionalPartnersShare = dataRow.additionalPartnersShare || 0;
                rowData.debt.debtPrincipal = dataRow.debtPrincipal || 0;
                rowData.debt.debtInterest = dataRow.debtInterest || 0;
                rowData.debt.debtBalance = dataRow.debtBalance || 0;
                
                if (dataRow.exitStrategy) {
                    rowData.exit.strategy = dataRow.exitStrategy;
                    rowData.exit.grossValue = dataRow.exitGrossValue || 0;
                    rowData.exit.sellingCosts = dataRow.exitSellingCosts || 0;
                    rowData.exit.netValue = dataRow.exitNetValue || 0;
                    rowData.exit.loanPayoff = dataRow.exitLoanPayoff || 0;
                    rowData.exit.partnerShare = dataRow.exitPartnerShare || 0;
                    rowData.exit.totalPartnersShare = dataRow.exitTotalPartnersShare || 0;
                    rowData.exit.investorShare = dataRow.exitInvestorShare || 0;
                }
            }
            
            // Debt service
            rowData.debt.debtService = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
            idx++;
            
            // Free cash flow
            rowData.cashFlow.freeCashFlow = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
            idx++;
            
            // Cumulative cash flow
            rowData.cashFlow.cumulativeCashFlow = parseFloat(cells[idx]?.textContent?.replace(/[^0-9.-]/g, '') || '0');
            idx++;
            
            // NOI Margin
            rowData.cashFlow.noiMargin = cells[idx]?.textContent?.trim() || '';
            idx++;
            
            // DSCR
            rowData.cashFlow.dscr = cells[idx]?.textContent?.trim() || '';
            
            rows.push(rowData);
        });
        
        // Get summary data
        const totalRevenue = document.getElementById('totalRevenueSummary')?.textContent?.replace(/[^0-9.-]/g, '') || '0';
        const totalOpex = document.getElementById('totalOpexSummary')?.textContent?.replace(/[^0-9.-]/g, '') || '0';
        const totalNOI = document.getElementById('totalNOISummary')?.textContent?.replace(/[^0-9.-]/g, '') || '0';
        const totalCashFlow = document.getElementById('totalCashFlowSummary')?.textContent?.replace(/[^0-9.-]/g, '') || '0';
        
        // Get project name
        const projectName = document.getElementById('projectName')?.value || 'مشروع';
        
        // ✅ NEW: Create comprehensive export object with all new columns
        const exportData = {
            metadata: {
                projectName: projectName,
                exportDate: new Date().toISOString(),
                exportVersion: '2.0.0',
                isLandRentEnabled: isLandRentVisible,
                isPartnershipEnabled: isPartnershipVisible,
                tableType: 'cashFlowTable',
                landMode: window.investmentData?.landAcquisition?.mode || 'unknown',
                exitStrategy: window.investmentData?.exit?.strategy || 'unknown',
                exitYear: window.investmentData?.exit?.year || 10
            },
            summary: {
                totalRevenue: parseFloat(totalRevenue),
                totalOpex: parseFloat(totalOpex),
                totalNOI: parseFloat(totalNOI),
                totalCashFlow: parseFloat(totalCashFlow)
            },
            columns: (() => {
                let cols = [
                    'السنة', 'تكلفة الأرض', 'البناء', 'صرف القرض', 'رأس المال',
                    'الإيرادات', 'OPEX'
                ];
                if (isLandRentVisible) cols.push('إيجار الأرض');
                cols.push('NOI قبل الشراكة');
                if (isPartnershipVisible) {
                    cols.push('حصة الشركاء', 'رسوم الإدارة', 'NOI بعد الشراكة');
                }
                cols.push('خدمة الدين', 'التدفق الحر', 'التدفق التراكمي', 'هامش NOI', 'DSCR');
                return cols;
            })(),
            partnership: isPartnershipVisible ? {
                enabled: true,
                profitSharingModel: window.investmentData?.landAcquisition?.profitSharingModel || 'revenue',
                mainPartnerShare: window.investmentData?.landAcquisition?.partnershipShare || 0,
                managementFee: window.investmentData?.landAcquisition?.managementFeePercentage || 5,
                additionalPartnersCount: window.investmentData?.landAcquisition?.partners?.length || 0,
                autoCalculate: window.investmentData?.landAcquisition?.autoCalculateProfitShare || false
            } : {
                enabled: false
            },
            rows: rows
        };
        
        // Convert to JSON
        const jsonString = JSON.stringify(exportData, null, 2);
        
        // Download file
        const blob = new Blob([jsonString], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `cashflow-${projectName.replace(/\s+/g, '-')}-${Date.now()}.json`;
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
        
        console.log('✅ تم تصدير جدول التدفقات النقدية بنجاح!');
        alert('✅ تم تصدير جدول التدفقات النقدية بنجاح!\n\nالملف يحتوي على:\n• جميع الصفوف والأعمدة\n• حالة عمود إيجار الأرض\n• البيانات الملخصة\n• معلومات المشروع');
        
    } catch (error) {
        console.error('❌ خطأ في تصدير الجدول:', error);
        alert('❌ حدث خطأ أثناء التصدير: ' + error.message);
    }
};

