function editCategoryName(categoryId) {
    const category = costsData.generalCosts?.categories?.[categoryId];
    if (!category) {
        console.error('❌ Category not found:', categoryId);
        return;
    }
    
    const newName = prompt('أدخل الاسم الجديد (عربي):', category.name);
    if (newName && newName.trim()) {
        category.name = newName.trim();
        localStorage.setItem('costsData', JSON.stringify(costsData));
        renderCostsSystem();
        console.log(`✅ Updated category name: ${categoryId} → ${newName}`);
    }
}

function editCategoryNameEn(categoryId) {
    const category = costsData.generalCosts?.categories?.[categoryId];
    if (!category) {
        console.error('❌ Category not found:', categoryId);
        return;
    }
    
    const newNameEn = prompt('Enter new name (English):', category.nameEn || category.name);
    if (newNameEn && newNameEn.trim()) {
        category.nameEn = newNameEn.trim();
        localStorage.setItem('costsData', JSON.stringify(costsData));
        renderCostsSystem();
        console.log(`✅ Updated category English name: ${categoryId} → ${newNameEn}`);
    }
}

function editCategoryType(categoryId) {
    const category = costsData[categoryId];
    if (!category) {
        console.error('❌ Category not found:', categoryId);
        return;
    }
    
    // استخدام categoryType بدلاً من type للتوافق مع rendering
    const currentType = category.categoryType || 'additional';
    const newType = currentType === 'construction' ? 'additional' : 'construction';
    
    const typeNames = {
        construction: 'إنشائي (Construction)',
        additional: 'إضافي (Additional Costs)'
    };
    
    if (confirm(`تغيير نوع الفئة من "${typeNames[currentType]}" إلى "${typeNames[newType]}"؟`)) {
        category.categoryType = newType; // حفظ في categoryType
        localStorage.setItem('costsData', JSON.stringify(costsData));
        renderCostsSystem(); // إعادة رسم البطاقات
        updateCostsSummary(); // تحديث الملخصات
        console.log(`✅ Changed category type: ${categoryId} → ${newType}`);
    }
}

window.editCategoryName = editCategoryName;
window.editCategoryNameEn = editCategoryNameEn;
window.editCategoryType = editCategoryType;

