// ============================================================================
// 🎨 CUSTOM DARK DROPDOWN SYSTEM - Replace Native Selects
// ============================================================================
/**
 * Replaces ALL native <select> elements with custom dark-themed dropdowns
 * that have full control over appearance (no white backgrounds)
 */

class DarkDropdownSystem {
    constructor() {
        this.dropdowns = new Map();
        this.activeDropdown = null;
    }
    
    // Create custom dropdown HTML
    createCustomDropdown(select) {
        const wrapper = document.createElement('div');
        wrapper.className = 'custom-dark-dropdown';
        wrapper.style.cssText = `
            position: relative;
            width: 100%;
            min-width: 150px;
            z-index: 1;
        `;
        
        // Get selected option
        const selectedOption = select.options[select.selectedIndex];
        const selectedText = selectedOption ? selectedOption.textContent : 'اختر...';
        
        // Create trigger button
        const trigger = document.createElement('div');
        trigger.className = 'dropdown-trigger';
        trigger.style.cssText = `
            background: #1f2937;
            border: 2px solid rgba(255, 255, 255, 0.2);
            border-radius: 8px;
            color: #ffffff;
            padding: 0.5rem 2rem 0.5rem 1rem;
            cursor: pointer;
            user-select: none;
            transition: all 0.2s;
            position: relative;
            font-size: 0.875rem;
            font-weight: 500;
        `;
        trigger.textContent = selectedText;
        
        // Add arrow icon
        const arrow = document.createElement('span');
        arrow.style.cssText = `
            position: absolute;
            left: 0.5rem;
            top: 50%;
            transform: translateY(-50%);
            color: #fbbf24;
            transition: transform 0.2s;
            pointer-events: none;
        `;
        arrow.innerHTML = '▼';
        trigger.appendChild(arrow);
        
        // Create dropdown menu
        const menu = document.createElement('div');
        menu.className = 'dropdown-menu';
        menu.style.cssText = `
            position: absolute;
            top: calc(100% + 4px);
            right: 0;
            left: 0;
            background: #1f2937;
            border: 2px solid rgba(255, 255, 255, 0.2);
            border-radius: 8px;
            max-height: 250px;
            overflow-y: auto;
            z-index: 9999 !important;
            display: none;
            box-shadow: 0 10px 25px rgba(0, 0, 0, 0.5);
        `;
        
        // Add options to menu
        Array.from(select.options).forEach((option, index) => {
            const item = document.createElement('div');
            item.className = 'dropdown-item';
            item.style.cssText = `
                padding: 0.75rem 1rem;
                color: #ffffff;
                cursor: pointer;
                transition: all 0.15s;
                font-size: 0.875rem;
                font-weight: 500;
                border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            `;
            item.textContent = option.textContent;
            item.dataset.value = option.value;
            item.dataset.index = index;
            
            // Highlight selected item
            if (index === select.selectedIndex) {
                item.style.background = 'linear-gradient(90deg, #3b82f6 0%, #2563eb 100%)';
            }
            
            // Hover effect
            item.addEventListener('mouseenter', () => {
                if (parseInt(item.dataset.index) !== select.selectedIndex) {
                    item.style.background = '#374151';
                    item.style.color = '#fbbf24';
                }
            });
            
            item.addEventListener('mouseleave', () => {
                if (parseInt(item.dataset.index) !== select.selectedIndex) {
                    item.style.background = 'transparent';
                    item.style.color = '#ffffff';
                }
            });
            
            // Click handler
            item.addEventListener('click', () => {
                // Update original select
                select.selectedIndex = parseInt(item.dataset.index);
                
                // Trigger change event
                const event = new Event('change', { bubbles: true });
                select.dispatchEvent(event);
                
                // Update trigger text
                trigger.childNodes[0].textContent = option.textContent;
                
                // Update item styles
                menu.querySelectorAll('.dropdown-item').forEach((menuItem, i) => {
                    if (i === parseInt(item.dataset.index)) {
                        menuItem.style.background = 'linear-gradient(90deg, #3b82f6 0%, #2563eb 100%)';
                        menuItem.style.color = '#ffffff';
                    } else {
                        menuItem.style.background = 'transparent';
                        menuItem.style.color = '#ffffff';
                    }
                });
                
                // Close menu
                this.closeDropdown(wrapper);
            });
            
            menu.appendChild(item);
        });
        
        // Toggle dropdown
        trigger.addEventListener('click', (e) => {
            e.stopPropagation();
            
            if (menu.style.display === 'block') {
                this.closeDropdown(wrapper);
            } else {
                // Close other dropdowns
                if (this.activeDropdown && this.activeDropdown !== wrapper) {
                    this.closeDropdown(this.activeDropdown);
                }
                
                // Open dropdown
                menu.style.display = 'block';
                arrow.style.transform = 'translateY(-50%) rotate(180deg)';
                trigger.style.borderColor = '#fbbf24';
                trigger.style.background = '#374151';
                wrapper.style.zIndex = '9998'; // Raise wrapper z-index when open
                
                // CRITICAL FIX: Also raise parent row z-index to ensure it's above other rows
                const parentRow = wrapper.closest('tr');
                if (parentRow) {
                    parentRow.style.zIndex = '9997';
                    parentRow.style.position = 'relative';
                }
                
                this.activeDropdown = wrapper;
            }
        });
        
        // Assemble dropdown
        wrapper.appendChild(trigger);
        wrapper.appendChild(menu);
        
        // Hide original select
        select.style.display = 'none';
        
        // Insert after original select
        select.parentNode.insertBefore(wrapper, select.nextSibling);
        
        // Store reference
        this.dropdowns.set(select, wrapper);
        
        return wrapper;
    }
    
    closeDropdown(wrapper) {
        if (!wrapper) return;
        
        const menu = wrapper.querySelector('.dropdown-menu');
        const trigger = wrapper.querySelector('.dropdown-trigger');
        const arrow = trigger.querySelector('span');
        
        menu.style.display = 'none';
        arrow.style.transform = 'translateY(-50%) rotate(0deg)';
        trigger.style.borderColor = 'rgba(255, 255, 255, 0.2)';
        trigger.style.background = '#1f2937';
        wrapper.style.zIndex = '1'; // Reset wrapper z-index when closed
        
        // CRITICAL FIX: Reset parent row z-index
        const parentRow = wrapper.closest('tr');
        if (parentRow) {
            parentRow.style.zIndex = '';
            parentRow.style.position = '';
        }
        
        if (this.activeDropdown === wrapper) {
            this.activeDropdown = null;
        }
    }
    
    // Replace all select elements
    replaceAllSelects() {
        const selects = document.querySelectorAll('select:not([data-custom-dropdown])');
        let count = 0;
        
        selects.forEach(select => {
            // Skip if already processed or hidden
            if (select.dataset.customDropdown === 'true' || select.offsetParent === null) {
                return;
            }
            
            // Mark as processed
            select.dataset.customDropdown = 'true';
            
            // Create custom dropdown
            this.createCustomDropdown(select);
            count++;
        });
        
        if (count > 0) {
            console.log(`✅ Replaced ${count} native selects with custom dark dropdowns`);
        }
        
        return count;
    }
    
    // Initialize system
    init() {
        // Replace existing selects
        this.replaceAllSelects();
        
        // Close dropdowns when clicking outside
        document.addEventListener('click', () => {
            if (this.activeDropdown) {
                this.closeDropdown(this.activeDropdown);
            }
        });
        
        // Watch for new selects
        if (typeof MutationObserver !== 'undefined') {
            const observer = new MutationObserver(() => {
                this.replaceAllSelects();
            });
            
            observer.observe(document.body, {
                childList: true,
                subtree: true
            });
        }
        
        // Periodic check
        setInterval(() => {
            this.replaceAllSelects();
        }, 3000);
        
        console.log('🎨 Custom Dark Dropdown System initialized');
    }
}

// Initialize the system
const darkDropdownSystem = new DarkDropdownSystem();
darkDropdownSystem.init();


