// Global variable for templates library
let templatesLibrary = null;
let floorsTemplatesLibrary = null;
let currentTemplateCategory = 'cost'; // cost, revenue, operating_expenses, roles, floors

// Load templates library from JSON file
async function loadTemplatesLibrary() {
    try {
        const response = await fetch('/static/data/cost_templates_library.json');
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        templatesLibrary = await response.json();
        console.log('✅ Cost templates library loaded:', templatesLibrary.totalTemplates, 'templates');
        return templatesLibrary;
    } catch (error) {
        console.error('❌ Failed to load cost templates library:', error);
        return null;
    }
}

// Load floors templates library from JSON file
async function loadFloorsTemplatesLibrary() {
    try {
        const response = await fetch('/static/data/floor_templates_library.json');
        if (!response.ok) {
            throw new Error(`HTTP error! status: ${response.status}`);
        }
        floorsTemplatesLibrary = await response.json();
        console.log('✅ Floors templates library loaded:', floorsTemplatesLibrary.totalTemplates, 'templates');
        return floorsTemplatesLibrary;
    } catch (error) {
        console.error('❌ Failed to load floors templates library:', error);
        return null;
    }
}

