                            style="background: rgba(34, 197, 94, 0.2); border: 1px solid rgba(34, 197, 94, 0.4); width: 32px; height: 32px; border-radius: 8px; color: #22C55E; cursor: pointer; transition: all 0.3s; display: flex; align-items: center; justify-content: center;"
