// Add "Templates Library" button to main navigation
function addTemplatesLibraryButton() {
    // Find the navigation container (assuming it's the cost actions area)
    const costsActions = document.querySelector('.modern-card-header .flex.items-center.gap-4');
    
    if (costsActions && !document.getElementById('templates-library-btn')) {
        const libraryBtn = document.createElement('button');
        libraryBtn.id = 'templates-library-btn';
        libraryBtn.className = 'modern-button';
        libraryBtn.innerHTML = '<i class="fas fa-layer-group"></i> مكتبة القوالب';
        libraryBtn.onclick = showTemplatesLibrary;
        libraryBtn.style.cssText = 'background: linear-gradient(135deg, #667eea 0%, #764ba2 100%); border: none; padding: 10px 20px; border-radius: 10px; color: white; font-size: 14px; font-weight: 600; cursor: pointer; transition: all 0.3s; display: flex; align-items: center; gap: 8px;';
        
        // Insert after "Add Category" button
        const addCategoryBtn = costsActions.querySelector('button[onclick*="addCostCategory"]');
        if (addCategoryBtn && addCategoryBtn.nextSibling) {
            costsActions.insertBefore(libraryBtn, addCategoryBtn.nextSibling);
        } else {
            costsActions.appendChild(libraryBtn);
        }
        
        console.log('✅ Templates Library button added to navigation');
    }
}

// Initialize templates library button when costs system is rendered
const originalRenderCostsSystem = renderCostsSystem;
renderCostsSystem = function() {
    originalRenderCostsSystem();
    setTimeout(() => {
        addTemplatesLibraryButton();
    }, 100);
};

