// Storage for user templates (localStorage)
let userTemplates = [];

// Load user templates from localStorage
function loadUserTemplates() {
    try {
        const stored = localStorage.getItem('userTemplates');
        if (stored) {
            userTemplates = JSON.parse(stored);
            console.log(`✅ Loaded ${userTemplates.length} user templates from localStorage`);
        }
    } catch (error) {
        console.error('❌ Failed to load user templates:', error);
        userTemplates = [];
    }
}

// Save user templates to localStorage
function saveUserTemplates() {
    try {
        localStorage.setItem('userTemplates', JSON.stringify(userTemplates));
        console.log(`✅ Saved ${userTemplates.length} user templates to localStorage`);
    } catch (error) {
        console.error('❌ Failed to save user templates:', error);
    }
}

// Initialize user templates
loadUserTemplates();

