// Confirm save template
function confirmSaveTemplate(categoryId) {
    const category = costsData[categoryId];
    const nameInput = document.getElementById('template-name-input');
    const descInput = document.getElementById('template-desc-input');
    const tagsInput = document.getElementById('template-tags-input');
    
    if (!nameInput || !nameInput.value.trim()) {
        alert('⚠️ يرجى إدخال اسم القالب');
        return;
    }
    
    // Parse tags
    const tags = tagsInput.value
        .split(',')
        .map(tag => tag.trim())
        .filter(tag => tag.length > 0);
    
    // Create template object
    const template = {
        id: `user_template_${Date.now()}_${Math.random().toString(36).substring(2, 11)}`,
        name: nameInput.value.trim(),
        nameEn: category.nameEn || '',
        description: descInput.value.trim() || `${nameInput.value.trim()} - ${category.costs ? category.costs.length : 0} بند`,
        categoryType: category.categoryType || 'construction',
        isCustom: true,
        isUserTemplate: true,
        isFavorite: false,
        itemsCount: category.costs ? category.costs.length : 0,
        icon: category.icon || '🏗️',
        color: category.color || 'blue',
        categoryData: JSON.parse(JSON.stringify(category)), // Deep clone
        metadata: {
            exportDate: new Date().toISOString(),
            version: '1.0.0',
            systemName: 'User Template',
            dataType: 'singleCostCategory',
            categoryId: category.id,
            categoryName: nameInput.value.trim(),
            categoryType: category.categoryType || 'construction',
            isCustom: true,
            itemsCount: category.costs ? category.costs.length : 0
        },
        tags: tags,
        createdAt: new Date().toISOString()
    };
    
    // Add to user templates
    userTemplates.push(template);
    saveUserTemplates();
    
    console.log(`✅ Saved template: ${template.name}`);
    
    // Close modal
    document.querySelector('.modal-overlay')?.remove();
    
    alert(`✅ تم حفظ القالب "${template.name}" بنجاح!\n\nيمكنك الآن العثور عليه في مكتبة القوالب.`);
    
    // Refresh library if open
    if (templatesLibrary) {
        mergeUserTemplatesWithLibrary();
    }
}

// Merge user templates with library
function mergeUserTemplatesWithLibrary() {
    if (!templatesLibrary) return;
    
    // Add user templates to cost category
    templatesLibrary.categories.cost.templates = [
        ...userTemplates,
        ...templatesLibrary.categories.cost.templates.filter(t => !t.isUserTemplate)
    ];
    
    templatesLibrary.totalTemplates = templatesLibrary.categories.cost.templates.length;
}

// Delete template
function deleteTemplate(templateId) {
    const template = findTemplateById(templateId);
    
    if (!template) {
        alert('❌ لم يتم العثور على القالب');
        return;
    }
    
    // No protection - allow deletion of all templates
    const confirmMsg = `هل أنت متأكد من حذف القالب "${template.name}"؟\n\nلا يمكن التراجع عن هذا الإجراء.`;
    if (!confirm(confirmMsg)) {
        return;
    }
    
    // Remove from user templates
    const index = userTemplates.findIndex(t => t.id === templateId);
    if (index > -1) {
        userTemplates.splice(index, 1);
        saveUserTemplates();
        console.log(`✅ Deleted template: ${template.name}`);
        
        // Refresh library
        mergeUserTemplatesWithLibrary();
        renderTemplates();
        
        alert(`✅ تم حذف القالب "${template.name}" بنجاح!`);
    }
}

// Find template by ID
function findTemplateById(templateId) {
    for (const category of Object.values(templatesLibrary.categories)) {
        const template = category.templates.find(t => t.id === templateId);
        if (template) return template;
    }
    return null;
}

