                                    <div class="dropdown-selected" style="background: rgba(255,255,255,0.05); border: 1px solid rgba(255,255,255,0.1); border-radius: 8px; padding: 10px; color: white; font-size: 12px; cursor: pointer; display: flex; justify-content: space-between; align-items: center;">
                                        <span>${currentUseType.label}</span>
                                        <i class="fas fa-chevron-down" style="font-size: 10px; transition: transform 0.3s;"></i>
                                    </div>
