                                    onclick="deleteEditingCostItem(${index})"
                                    style="background: rgba(239, 68, 68, 0.2); border: 1px solid rgba(239, 68, 68, 0.4); width: 36px; height: 36px; border-radius: 8px; color: #EF4444; cursor: pointer; transition: all 0.3s;"
                                    title="حذف البند"
                                    onmouseover="this.style.transform='scale(1.1)'"
                                    onmouseout="this.style.transform='scale(1)'"
